// Quiz content for Cours27 — Analyse fonctionnelle profonde : hiérarchies, Ursatz, réduction schenkérienne

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours27Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // ── 1. Régions tonales (T/SD/D) ──────────────────────────────────────────
  { q: "Quels degrés appartiennent à la région tonique (T) en Do majeur ?", opts: ["I, II, IV", "I, III, VI", "V, VII, II", "IV, VI, III"], a: 1, fb: "La région tonique regroupe les accords dont la sonorité évoque la stabilité de la tonique : I, III et VI. Ces accords partagent deux notes avec I (Do–Mi–Sol) et renforcent la couleur de repos." },
  { q: "Quels degrés appartiennent à la région sous-dominante (SD) en Do majeur ?", opts: ["I, III, VI", "V, VII", "II, IV", "I, IV, V"], a: 2, fb: "La région sous-dominante comprend II et IV. Ces accords exercent une préparation harmonique vers la dominante — ils créent un mouvement de tension intermédiaire entre le repos (T) et la tension maximale (D)." },
  { q: "Quels degrés appartiennent à la région dominante (D) en Do majeur ?", opts: ["I, III, VI", "II, IV", "V, VII", "III, V"], a: 2, fb: "La région dominante regroupe V et VII. Ces accords portent la tension maximale et exigent la résolution vers la tonique. V7 est l'accord de dominante par excellence, VII en est la version incomplète." },
  { q: "Dans la progression I–VI–II–V–I, à quelle région appartient VI ?", opts: ["Région dominante", "Région sous-dominante", "Région tonique", "Aucune région"], a: 2, fb: "VI (La mineur en Do majeur) appartient à la région tonique car il partage deux notes avec I (Do et Mi). Dans cette progression, VI joue un rôle de prolongation tonique avant le mouvement vers SD (II) et D (V)." },
  { q: "La progression T–SD–D–T décrit :", opts: ["La règle des quintes parallèles", "L'enchaînement fonctionnel de base de l'harmonie tonale", "La structure de l'Urlinie", "Le principe de la Bassbrechung"], a: 1, fb: "T–SD–D–T est le schéma fonctionnel fondamental de la musique tonale : départ stable (T), préparation (SD), tension maximale (D), retour au repos (T). Toute progression tonale peut se lire comme une variante de ce modèle." },
  { q: "L'accord de II6 (2e degré en 1er renversement) appartient à quelle région fonctionnelle ?", opts: ["Région tonique", "Région dominante", "Région sous-dominante", "Aucune — les renversements changent la région"], a: 2, fb: "Le renversement ne change pas la région fonctionnelle. II (Ré–Fa–La) appartient à la région sous-dominante qu'il soit à l'état fondamental ou en 1er renversement. II6 est même la forme préférée de II dans le style classique avant V." },
  { q: "Pourquoi IV–V–IV est-il une progression déconseillée ?", opts: ["Car IV et V ne peuvent pas se suivre", "Car ce retour en arrière T→D→T→D brise la logique directionnelle SD→D→T", "Car IV n'appartient pas à la gamme", "Car V suivi de IV crée des quintes parallèles systématiques"], a: 1, fb: "IV–V–IV représente un 'retour en arrière' fonctionnel : on quitte la sous-dominante pour la dominante, puis on revient à la sous-dominante. Cette hésitation brise la logique directionnelle T→SD→D→T et affaiblit la progression." },
  { q: "En Sol majeur, l'accord de Mi mineur (VIm) appartient à :", opts: ["Région dominante", "Région sous-dominante", "Région tonique", "Aucune de ces régions"], a: 2, fb: "En Sol majeur, VI est Mi mineur. Il appartient à la région tonique car il partage deux notes avec I (Sol et Si de Sol–Si–Ré). Mi–Sol–Si partage Sol et Si avec Sol majeur — c'est bien la couleur de repos tonique." },
  { q: "Qu'est-ce qu'une prolongation de la région tonique ?", opts: ["Un accord étranger à la tonalité", "Une séquence d'accords qui maintient la couleur fonctionnelle de T sans changer de région", "Le passage obligatoire par V avant I", "La répétition littérale de I à l'octave"], a: 1, fb: "Une prolongation tonique est un ensemble d'accords (ex. I–VI–I6–I) qui restent dans la région T. Ils ornent et font durer la couleur de repos de la tonique sans véritable mouvement fonctionnel vers SD ou D." },
  { q: "Dans une phrase de 8 mesures en forme sentence, les mesures 1–4 sont souvent :", opts: ["D–T–D–T", "T prolongée, puis mouvement vers D", "SD uniquement", "Alternance rapide T/D/T/D"], a: 1, fb: "La phrase sentence classique commence par une présentation (mm.1–4) qui prolonge la tonique, puis une continuation (mm.5–8) qui développe le mouvement SD–D–T jusqu'à la cadence finale. C'est la structure archétypale de Haydn et Mozart." },

  // ── 2. Prolongation harmonique ────────────────────────────────────────────
  { q: "Qu'est-ce qu'une prolongation harmonique ?", opts: ["Un accord joué très fort pour être entendu", "Le maintien d'une fonction harmonique sur plusieurs mesures à travers des harmonies de surface changeantes", "L'augmentation de la durée de toutes les notes", "Un accord tenu sans changement pendant plusieurs mesures"], a: 1, fb: "La prolongation harmonique est le principe par lequel une fonction (T, SD ou D) est maintenue pendant plusieurs mesures, même si les accords de surface changent. Ex. : I–I6–I6/4 prolonge tous la fonction tonique." },
  { q: "La progression I–VI–I6–I est un exemple de :", opts: ["Mouvement T→SD→D→T", "Prolongation de la région tonique", "Cadence authentique", "Bassbrechung"], a: 1, fb: "I–VI–I6–I prolonge la région tonique : VI appartient à T (partage deux notes avec I), I6 est I en renversement. Tous ces accords maintiennent la couleur fonctionnelle de repos de la tonique." },
  { q: "Dans une prolongation de dominante, quel accord peut 'orner' V sans le quitter fonctionnellement ?", opts: ["IV", "I6/4 (avant V, 6/4 de cadence)", "II", "VI"], a: 1, fb: "Le 6/4 de cadence (I6/4) sur un temps fort prolonge la région dominante : sa basse est Sol (quinte de I mais aussi fondamentale de V), et il résout immédiatement sur V. On dit que I6/4–V forme une unité de prolongation dominante." },
  { q: "Comment reconnaître une prolongation dans une analyse ?", opts: ["Les accords ont tous la même durée", "Plusieurs accords successifs partagent la même fonction régionale et servent à orner ou développer un accord structural", "Les accords sont tous dans la même octave", "La basse ne bouge pas du tout"], a: 1, fb: "Une prolongation se reconnaît à la cohérence fonctionnelle : plusieurs accords différents en surface qui maintiennent la même région (T, SD ou D). L'accord structural est le pilier ; les autres sont ses ornements." },
  { q: "Une note de pédale à la basse sur Sol prolonge :", opts: ["La région tonique uniquement", "La région dominante, en maintenant la fondamentale de V sous des harmonies changeantes", "La région sous-dominante", "Aucune région précise"], a: 1, fb: "Une pédale sur Sol (dominante) maintient la tension de V sous des harmonies changeantes. Les accords qui passent au-dessus sont des ornements de surface — la fonction structurelle reste D pendant toute la pédale." },
  { q: "Quelle est la différence entre un accord de passage et un accord structural ?", opts: ["L'accord de passage est plus long", "L'accord structural est un pilier fonctionnel ; l'accord de passage est un ornement entre deux piliers", "L'accord structural est toujours à l'état fondamental", "Il n'y a pas de différence — tous les accords sont égaux"], a: 1, fb: "L'accord structural (pilier) est un point d'ancrage fonctionnel dans l'analyse en couches. L'accord de passage est un ornement de surface qui relie deux piliers — il n'a pas de poids structural indépendant." },
  { q: "Dans la séquence I–IV–I6–V–I, quels accords prolongent la tonique au début ?", opts: ["I et IV", "I, IV et I6", "I seul", "I et I6"], a: 3, fb: "I et I6 prolongent la tonique (même accord, renversement différent). IV appartient à SD — c'est un mouvement vers la sous-dominante, pas une prolongation tonique. Donc seuls I et I6 prolongent T ici." },
  { q: "Une gamme ascendante à la basse (Do–Ré–Mi–Fa) sous un accord de I prolonge :", opts: ["La dominante", "La tonique par mouvement de basse ornemental", "La sous-dominante", "Aucune région — la gamme casse la prolongation"], a: 1, fb: "Une ligne de basse conjointe ascendante (Do–Ré–Mi–Fa) peut prolonger la tonique : la basse orne l'accord de I en passant par des positions intermédiaires (I–I6–I6/4 ou avec des harmonies de passage). C'est une prolongation par basse arpeggée ou conjointe." },
  { q: "Le concept de prolongation est central dans l'analyse de :", opts: ["Schönberg", "Schenker", "Rameau", "Riemann"], a: 1, fb: "Heinrich Schenker (1868–1935) est le théoricien qui a développé le concept de prolongation comme outil d'analyse fondamental. Selon lui, toute musique tonale est une prolongation de la Ursatz (structure fondamentale)." },
  { q: "Une prolongation de dominante typique avant une cadence finale est :", opts: ["V–IV–V", "I6/4–V–V7", "V–VI–V", "I–V–I"], a: 1, fb: "I6/4–V–V7 est une prolongation classique de la dominante avant la cadence : le 6/4 de cadence prépare V qui est amplifié par V7. Toute cette séquence prolonge la région D avant la résolution sur I." },

  // ── 3. Harmonie de surface vs structurelle ────────────────────────────────
  { q: "Qu'est-ce que l'harmonie de surface ?", opts: ["Les accords joués sur le dessus du piano", "L'ensemble de tous les accords tels qu'ils apparaissent dans la partition", "Les accords principaux de la structure profonde", "Les accords sans renversement"], a: 1, fb: "L'harmonie de surface désigne tous les accords comme ils apparaissent dans la partition — chaque accord de passage, broderie, voisinage. C'est la 'surface' visible de l'harmonie, avant toute réduction analytique." },
  { q: "Qu'est-ce qu'un accord structurel (pilier harmonique) ?", opts: ["Un accord joué fortissimo", "Un accord qui occupe une position fonctionnelle clé dans la structure profonde de la pièce", "Un accord dépourvu de renversements", "L'accord le plus souvent répété dans la pièce"], a: 1, fb: "Un accord structurel (ou pilier) est un accord porteur d'une fonction clé dans la logique tonale : il ancre une région (T, SD, D) et fait partie de la structure profonde que l'on cherche à dégager par la réduction." },
  { q: "Comment distinguer un accord de surface d'un accord structurel ?", opts: ["Par sa durée uniquement", "Par sa position fonctionnelle et son importance pour la logique cadentielle de la phrase", "Par sa position dans la mesure (temps fort = structurel)", "Par le nombre de notes qu'il contient"], a: 1, fb: "La durée et la position métrique sont des indices mais pas des critères absolus. L'accord structurel est celui dont la suppression changerait la logique tonale fondamentale — il est indispensable à la progression cadentielle." },
  { q: "Dans la progression I–IV–V–I, l'accord IV est-il structurel ou de surface ?", opts: ["Toujours de surface", "Structurel — il articule le mouvement SD avant D", "De surface — il peut être remplacé par II6 sans changer la structure", "Ni l'un ni l'autre — IV n'a aucun rôle harmonique"], a: 1, fb: "IV est ici un accord structurel de la région SD : il articule le mouvement fonctionnel T→SD→D→T. Dans ce contexte, sa présence est porteuse de sens structural. En revanche, un IV passager entre deux I serait de surface." },
  { q: "Dans I–I6–I6/4–V–I, quel est le véritable accord structurel de dominante ?", opts: ["I6/4 car il est sur le temps fort", "V — I6/4 est une prolongation ornementale de V (6/4 de cadence)", "I6/4 et V ensemble", "Aucun — tous sont de surface"], a: 1, fb: "V est l'accord structurel de dominante. I6/4 (6/4 de cadence) est une prolongation ornementale qui 'prépare' V — il appartient fonctionnellement à la région dominante mais n'en est pas le pilier structurel." },
  { q: "Un accord de broderie (note broderie harmonisée) est :", opts: ["Un accord structurel par définition", "Un accord de surface qui orne un accord structural sans en changer la fonction", "Un accord pivot entre deux tonalités", "Un accord de passage modulant"], a: 1, fb: "Un accord de broderie est un accord de surface : il orne un accord structural en s'écartant puis en y revenant. Il ne crée pas de mouvement fonctionnel indépendant — il prolonge l'accord structural qu'il entoure." },
  { q: "Comment identifier les piliers structuraux d'une phrase de 4 mesures ?", opts: ["Prendre tous les accords sur les temps forts", "Identifier l'accord d'ouverture, la cadence médiane et la cadence finale — les autres sont des prolongations", "Garder uniquement les accords de I et V", "Identifier les accords les plus longs"], a: 1, fb: "La stratégie schenkérienne consiste à repérer les points d'ancrage cadentiels : début (ouverture tonique), cadence médiane (souvent demi-cadence V), cadence finale (V–I). Ces trois pôles forment le squelette structural." },
  { q: "Dans une réduction, que fait-on des accords de passage ?", opts: ["On les transpose à l'octave", "On les supprime — ils ne font pas partie de la structure profonde", "On les déplace sur le temps fort", "On les remplace par des accords de septième"], a: 1, fb: "Dans la réduction, les accords de passage sont éliminés car ils n'appartiennent pas à la structure profonde. On ne conserve que les piliers structuraux (début, cadences) et leurs prolongations directes." },
  { q: "Quelle est la limite de l'analyse purement de surface (accord par accord) ?", opts: ["Elle est trop simple pour les musiciens avancés", "Elle ne révèle pas la logique tonale profonde et peut masquer la structure directionnelle de la pièce", "Elle n'existe pas — l'analyse de surface est la seule méthode valable", "Elle produit toujours des erreurs d'harmonie"], a: 1, fb: "L'analyse accord par accord reste à la surface : elle peut manquer les prolongations et les grandes arches fonctionnelles. La structure profonde (T→D→T sur toute une œuvre) est invisible si l'on s'arrête à la surface." },
  { q: "Pourquoi la distinction surface/structure est-elle pédagogiquement importante ?", opts: ["Pour simplifier l'apprentissage", "Pour comprendre que tous les accords n'ont pas la même importance et développer une lecture hiérarchique", "Pour éviter d'analyser certains accords difficiles", "Pour mémoriser plus facilement les progressions"], a: 1, fb: "La distinction surface/structure développe la pensée hiérarchique : l'élève comprend que la richesse harmonique de surface sert une structure plus simple et plus profonde. C'est un outil de compréhension, pas de simplification." },

  // ── 4. L'Urlinie ─────────────────────────────────────────────────────────
  { q: "Qu'est-ce que l'Urlinie selon Schenker ?", opts: ["La ligne de basse fondamentale", "La ligne mélodique fondamentale descendante du soprano, de 3̂/5̂/8̂ vers 1̂", "La ligne de ténor dans un choral", "La mélodie principale de l'œuvre"], a: 1, fb: "L'Urlinie ('ligne fondamentale') est la descente mélodique fondamentale du soprano, partant de 3̂, 5̂ ou 8̂ et descendant diatoniquement jusqu'à 1̂ (tonique). C'est la structure mélodique profonde que toute mélodie tonale réalise, selon Schenker." },
  { q: "Quelles sont les trois formes possibles de l'Urlinie ?", opts: ["1̂–2̂–3̂, 3̂–4̂–5̂, 5̂–6̂–7̂", "3̂–2̂–1̂, 5̂–4̂–3̂–2̂–1̂, 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "Do–Ré–Mi, Sol–La–Si, Mi–Fa–Sol", "I–V–I, I–IV–I, I–II–I"], a: 1, fb: "Schenker reconnaît trois Urlinien : 3̂–2̂–1̂ (descente de tierce), 5̂–4̂–3̂–2̂–1̂ (descente de quinte) et 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (descente d'octave). Chaque grande mélodie tonale réalise l'une de ces trois formes." },
  { q: "Dans l'Urlinie 3̂–2̂–1̂ en Do majeur, quelle note correspond à 3̂ ?", opts: ["Do", "Ré", "Mi", "Sol"], a: 2, fb: "En Do majeur, 3̂ est Mi (3e degré de la gamme). L'Urlinie 3̂–2̂–1̂ descend donc Mi–Ré–Do. Mi est la note de tête (Kopfton) qui initie la ligne fondamentale." },
  { q: "Dans l'Urlinie 5̂–4̂–3̂–2̂–1̂ en Sol majeur, quelle est la note de départ ?", opts: ["Sol", "Ré", "Si", "La"], a: 1, fb: "En Sol majeur, 5̂ est Ré (quinte de Sol). L'Urlinie 5̂–4̂–3̂–2̂–1̂ descend Ré–Do–Si–La–Sol. Ré est le Kopfton (note de tête) qui initie la descente fondamentale." },
  { q: "Pourquoi l'Urlinie descend-elle toujours vers 1̂ ?", opts: ["Par convention arbitraire de Schenker", "Parce que 1̂ (tonique) est le point de résolution et de repos de toute tension mélodique tonale", "Parce que les voix de soprano descendent toujours", "Pour éviter les quintes parallèles"], a: 1, fb: "1̂ est la tonique — le point de résolution finale de toute tension. Dans la logique tonale, toute tension mélodique doit résoudre sur la tonique. L'Urlinie matérialise cette résolution obligatoire à l'échelle de toute l'œuvre." },
  { q: "Comment repérer le Kopfton (note de tête, début de l'Urlinie) dans une mélodie ?", opts: ["C'est la note la plus aiguë de la mélodie", "C'est la note structurellement prépondérante au début, harmonisée par I, depuis laquelle la descente fondamentale s'engage", "C'est la première note de la mélodie", "C'est la note la plus longue"], a: 1, fb: "Le Kopfton est la note structurelle d'ouverture (3̂, 5̂ ou 8̂) qui appartient à l'accord de tonique initial et depuis laquelle la descente Urlinie commence. Ce n'est pas forcément la première note ni la plus haute." },
  { q: "Dans la mélodie Mi–Fa–Mi–Ré–Do (Do majeur), quelle est l'Urlinie probable ?", opts: ["5̂–4̂–3̂–2̂–1̂", "3̂–2̂–1̂ avec Mi comme Kopfton", "8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "Pas d'Urlinie — la mélodie est trop ornementée"], a: 1, fb: "Mi est 3̂ en Do majeur. La mélodie Mi–Fa–Mi–Ré–Do réalise l'Urlinie 3̂–2̂–1̂ (Mi–Ré–Do) avec Fa comme broderie ornementale. Le Kopfton est Mi, et la descente structurelle est 3̂(Mi)–2̂(Ré)–1̂(Do)." },
  { q: "L'Urlinie est-elle toujours audible directement dans la mélodie de surface ?", opts: ["Oui — elle correspond toujours à la mélodie exacte", "Non — elle est souvent ornementée, déplacée à l'octave ou interrompue par des notes étrangères de surface", "Non — elle appartient toujours à la basse", "Oui — mais uniquement dans la musique de Bach"], a: 1, fb: "L'Urlinie est une abstraction de la mélodie de surface — elle est ornementée, prolongée, interrompue. La mélodie réelle est une réalisation de surface de cette structure profonde. Il faut 'entendre à travers' la surface pour la dégager." },
  { q: "Que signifie '2̂ harmonisé par V' dans l'Urlinie ?", opts: ["Le 2e degré est joué par la voix de ténor", "La note 2̂ (sensible ou supratenante selon la forme) coïncide avec l'accord de dominante dans la structure profonde", "Le 2e degré est joué deux fois", "L'accord V est au 2e renversement"], a: 1, fb: "Dans l'Urlinie, chaque note fondamentale est harmonisée par un accord structurel : 2̂ coïncide avec V (dominante) et 1̂ avec I (tonique). C'est la conjonction de l'Urlinie et de la Bassbrechung qui forme la Ursatz." },
  { q: "Pourquoi Schenker dit-il que toute grande mélodie tonale réalise l'Urlinie ?", opts: ["Parce que toutes les mélodies sont identiques", "Parce que la logique tonale exige la résolution de toute tension vers la tonique — l'Urlinie est l'expression mélodique universelle de cette loi", "Parce qu'il a analysé toutes les mélodies existantes", "Parce que les compositeurs copient tous le même modèle"], a: 1, fb: "Pour Schenker, la logique tonale est universelle : toute tension doit résoudre vers 1̂. L'Urlinie n'est pas un schéma imposé de l'extérieur mais la conséquence inévitable de la tonalité elle-même." },

  // ── 5. La Bassbrechung ────────────────────────────────────────────────────
  { q: "Qu'est-ce que la Bassbrechung ?", opts: ["La ligne mélodique descendante du soprano", "L'arche de basse I–V–I qui structure la tonalité à l'échelle de l'œuvre", "Une technique de basse continue baroque", "Le chiffrage de basse dans un choral"], a: 1, fb: "La Bassbrechung ('brisure de basse') est l'arche fondamentale I–V–I à la basse, qui décrit le mouvement de quinte fondamental de l'harmonie tonale : de la tonique à la dominante, puis retour à la tonique." },
  { q: "Quelle est la basse fondamentale de la Bassbrechung en Do majeur ?", opts: ["Do–Fa–Do", "Do–Sol–Do", "Do–Ré–Do", "Do–La–Do"], a: 1, fb: "La Bassbrechung en Do majeur est Do–Sol–Do (I–V–I). Sol est la dominante — la quinte de la gamme. L'arche Do→Sol→Do représente le mouvement de quinte fondamental de la tonalité." },
  { q: "La Bassbrechung couvre-t-elle une phrase, une section ou une œuvre entière ?", opts: ["Uniquement une phrase de 4 mesures", "Elle peut s'étendre à n'importe quelle échelle — de la phrase à l'œuvre entière", "Uniquement des formes courtes (chanson)", "Elle ne s'applique qu'aux chorals de Bach"], a: 1, fb: "La Bassbrechung est scalable : elle peut structurer une phrase (mm.1–4), une section (mm.1–16), un mouvement entier ou une symphonie complète. C'est son caractère fractal qui rend l'analyse schenkérienne universelle." },
  { q: "Comment la Bassbrechung est-elle liée à l'Urlinie dans la Ursatz ?", opts: ["Elles sont indépendantes", "La Bassbrechung (basse I–V–I) soutient l'Urlinie (soprano 3̂–2̂–1̂) — ensemble elles forment la Ursatz", "L'Urlinie est la version mélodique de la Bassbrechung", "La Bassbrechung remplace l'Urlinie en mode mineur"], a: 1, fb: "Dans la Ursatz, l'Urlinie (soprano) et la Bassbrechung (basse) sont superposées : 3̂ sur I, 2̂ sur V, 1̂ sur I. Ce contrepoint à deux voix est la structure fondamentale universelle de la musique tonale selon Schenker." },
  { q: "Que représente le V intermédiaire dans la Bassbrechung I–V–I ?", opts: ["Une tonicisation momentanée", "Le point de tension maximale — la dominante qui structure la progression vers la résolution finale sur I", "Un accord de passage sans importance", "La sous-dominante en renversement"], a: 1, fb: "Le V dans I–V–I est le sommet de tension de la Bassbrechung — il représente le mouvement de quinte descendante fondamental de la tonalité (quinte I→V ou montée de quarte). Sa résolution sur I conclut l'arche tonale." },
  { q: "Dans une fugue de Bach de 100 mesures, où se situe généralement le V de la Bassbrechung ?", opts: ["Mesure 2 uniquement", "Au milieu structurel de l'œuvre, souvent à la plus grande cadence intermédiaire", "À chaque fin de phrase", "Il n'y a pas de Bassbrechung dans les fugues"], a: 1, fb: "Dans une grande forme, le V structurel de la Bassbrechung coïncide avec le point de tension maximal de l'œuvre — souvent la grande cadence sur V à mi-parcours. Tout ce qui précède prolonge I (aller), tout ce qui suit prolonge le retour vers I." },
  { q: "La Bassbrechung est analogue à quel principe formel dans la forme sonate ?", opts: ["L'exposition et la récapitulation", "La présentation → tension (développement) → résolution (récapitulation), soit I→V→I à grande échelle", "Le thème principal uniquement", "La coda finale"], a: 1, fb: "La forme sonate réalise la Bassbrechung à grande échelle : exposition en I (souvent avec 2e thème en V), développement (tension harmonique), récapitulation en I. Cette structure tonale I–V–I est la Bassbrechung de l'œuvre entière." },
  { q: "En mineur, la Bassbrechung est-elle Im–Vm–Im ou Im–V–Im ?", opts: ["Im–Vm–Im (mineur à la dominante)", "Im–V–Im (dominante majeure, avec sensible élevée)", "Im–bVII–Im", "Im–IV–Im"], a: 1, fb: "En mineur, la dominante est toujours V majeur (avec sensible élevée). La Bassbrechung est donc Im–V–Im : on utilise le mineur harmonique à la dominante pour conserver la tension maximale de la sensible vers la tonique." },
  { q: "Quel intervalle de basse caractérise le mouvement I→V dans la Bassbrechung ?", opts: ["Tierce ascendante", "Quinte descendante (ou quarte ascendante) — le mouvement fondamental de l'harmonie tonale", "Seconde ascendante", "Sixte descendante"], a: 1, fb: "I→V correspond à une quinte descendante (Do→Sol en Do majeur) ou quarte ascendante. C'est le mouvement le plus puissant de l'harmonie tonale — il crée la tension maximale qui appelle la résolution V→I." },
  { q: "La Bassbrechung est considérée par Schenker comme :", opts: ["Un schéma optionnel pour analyser la basse", "Le mouvement de basse universel de toute musique tonale — l'arche fondamentale du contrepoint à deux voix", "Une règle applicable uniquement à Bach", "Une simplification pédagogique sans valeur analytique"], a: 1, fb: "Pour Schenker, la Bassbrechung est une loi universelle : toute musique tonale réalise le mouvement I–V–I à la basse, à quelque échelle que ce soit. C'est la fondation harmonique de la Ursatz." },

  // ── 6. La Ursatz ─────────────────────────────────────────────────────────
  { q: "Qu'est-ce que la Ursatz selon Schenker ?", opts: ["La structure rythmique fondamentale", "La structure contrapuntique fondamentale = Urlinie (soprano) + Bassbrechung (basse)", "La gamme fondamentale de toute tonalité", "Le motif thématique principal d'une œuvre"], a: 1, fb: "La Ursatz ('structure fondamentale') est la superposition de l'Urlinie (descente du soprano 3̂–2̂–1̂) et de la Bassbrechung (arche de basse I–V–I). C'est un contrepoint à deux voix qui sous-tend toute musique tonale." },
  { q: "La Ursatz est composée de combien de couches ?", opts: ["Une seule — la mélodie principale", "Deux — soprano (Urlinie) et basse (Bassbrechung)", "Trois — soprano, alto, basse", "Quatre — les quatre voix SATB"], a: 1, fb: "La Ursatz est un contrepoint à deux voix : l'Urlinie au soprano et la Bassbrechung à la basse. Ces deux voix fondamentales suffisent à définir la structure tonale profonde de n'importe quelle œuvre." },
  { q: "Dans la Ursatz, comment sont alignées l'Urlinie et la Bassbrechung ?", opts: ["Elles sont indépendantes et ne se croisent jamais", "3̂ coïncide avec I (basse), 2̂ avec V (basse), 1̂ avec I (basse)", "5̂ coïncide avec V (basse), 3̂ avec IV, 1̂ avec I", "Elles s'alternent sans jamais se synchroniser"], a: 1, fb: "L'alignement canonique de la Ursatz : Kopfton (3̂/5̂/8̂) sur I, puis le mouvement intermédiaire (2̂ sur V), puis la résolution (1̂ sur I). Cette superposition crée le contrepoint fondamental de la musique tonale." },
  { q: "Pourquoi Schenker dit-il que toute musique tonale est une 'prolongation de la Ursatz' ?", opts: ["Parce que tous les compositeurs copient le même schéma", "Parce que toute composition tonale est une élaboration de cette structure fondamentale simple — les ornements de surface développent la Ursatz", "Parce que la Ursatz est imposée par le conservatoire", "Parce que la Ursatz est la seule structure audible"], a: 1, fb: "La Ursatz est la structure la plus profonde et la plus simple — toute composition tonale l'élabore à travers des couches successives de prolongation. Les ornements de surface (mélodies, progressions) sont des réalisations de plus en plus complexes de cette arche fondamentale." },
  { q: "La Ursatz s'applique-t-elle à la musique du XXe siècle atonale ?", opts: ["Oui — Schenker l'applique à toute musique", "Non — la Ursatz présuppose la tonalité ; la musique atonale ne suit pas ses principes", "Oui mais avec des modifications", "Non — elle s'applique uniquement à Bach"], a: 1, fb: "La Ursatz présuppose la tonalité : Urlinie descendant vers 1̂ et Bassbrechung I–V–I. La musique atonale, qui rejette la hiérarchie des degrés, ne peut pas être analysée dans ce cadre. C'est une limite explicite du système schenkérien." },
  { q: "Quelle est la version complète de la Ursatz avec l'Urlinie 5̂–4̂–3̂–2̂–1̂ ?", opts: ["5̂ sur I, 4̂ sur IV, 3̂ sur I, 2̂ sur V, 1̂ sur I", "5̂ sur I, descente 4̂–3̂ prolongée, 2̂ sur V, 1̂ sur I", "5̂ sur V, 4̂ sur IV, 3̂ sur III, 2̂ sur II, 1̂ sur I", "5̂ sur I, 4̂–3̂–2̂ ornementaux, 1̂ sur V"], a: 1, fb: "Dans l'Urlinie 5̂ (descente de quinte), les degrés 4̂ et 3̂ sont souvent prolongés par des mouvements harmoniques intermédiaires, mais les points d'ancrage structuraux sont 5̂ sur I, 2̂ sur V, et 1̂ sur I — formant la Ursatz complète." },
  { q: "La Ursatz a-t-elle un seul modèle ou plusieurs variantes ?", opts: ["Un seul modèle unique pour toute la musique", "Trois variantes selon le Kopfton (3̂, 5̂ ou 8̂)", "Une infinité de variantes selon le compositeur", "Deux variantes (majeur et mineur)"], a: 1, fb: "Schenker reconnaît trois formes de Ursatz selon le Kopfton : 3̂–2̂–1̂ (plus simple), 5̂–4̂–3̂–2̂–1̂ (très fréquente), 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (plus rare). La Bassbrechung reste I–V–I dans les trois cas." },
  { q: "Comment la Ursatz se manifeste-t-elle à grande échelle dans une symphonie ?", opts: ["Uniquement dans le 1er mouvement", "La tonalité principale de I se prolonge jusqu'au V structurel (souvent au développement) puis revient à I à la fin", "Elle n'est visible qu'au niveau des phrases", "Elle se manifeste uniquement dans la basse continue"], a: 1, fb: "Dans une symphonie, la Ursatz s'étend sur toute l'œuvre : le début s'ancre sur I, le point de tension maximal (souvent développement ou cadence centrale) réalise V, et la conclusion revient à I. La Bassbrechung I–V–I structure l'œuvre entière." },
  { q: "Qu'est-ce que le 'Vordergrund', 'Mittelgrund' et 'Hintergrund' dans l'analyse schenkérienne ?", opts: ["Trois instruments différents", "Les trois couches d'analyse : surface (Vordergrund), couche intermédiaire (Mittelgrund), structure profonde (Hintergrund = Ursatz)", "Trois parties d'une fugue", "Trois types de cadences"], a: 1, fb: "Schenker utilise ces trois niveaux : Vordergrund (avant-plan = musique de surface telle qu'elle est écrite), Mittelgrund (plan intermédiaire = prolongations groupées), Hintergrund (arrière-plan = Ursatz seule). La réduction progresse du Vordergrund vers le Hintergrund." },
  { q: "Quel est l'apport principal de la théorie de la Ursatz pour l'analyse musicale ?", opts: ["Elle permet de mémoriser plus facilement les partitions", "Elle révèle la structure tonale profonde commune à toutes les grandes œuvres et explique leur cohérence à grande échelle", "Elle simplifie la notation musicale", "Elle remplace l'analyse harmonique traditionnelle par accord"], a: 1, fb: "La Ursatz permet de comprendre la cohérence tonale à grande échelle : pourquoi une œuvre de 300 mesures 'tient ensemble'. Elle révèle que la complexité de surface masque une structure fondamentale simple et universelle." },

  // ── 7. Réduction en couches ───────────────────────────────────────────────
  { q: "Combien d'étapes comporte une réduction schenkérienne complète ?", opts: ["1 étape — passer directement à la Ursatz", "3 couches minimum : surface (Vordergrund) → intermédiaire (Mittelgrund) → profond (Hintergrund)", "5 étapes fixes identiques pour chaque analyse", "2 étapes — accords pairs et accords impairs"], a: 1, fb: "La réduction schenkérienne procède en couches successives : Vordergrund (surface) → Mittelgrund(s) (couches intermédiaires, parfois plusieurs) → Hintergrund (Ursatz). Le nombre de couches intermédiaires dépend de la complexité de l'œuvre." },
  { q: "Que fait-on en premier dans une réduction en couches ?", opts: ["Identifier l'Urlinie immédiatement", "Écrire tous les accords de la partition (harmonie de surface)", "Réduire à la Ursatz", "Analyser les modulations"], a: 1, fb: "La première étape est d'écrire l'harmonie de surface complète — tous les accords tels qu'ils apparaissent. C'est le Vordergrund : le point de départ avant toute réduction. On ne saute pas les étapes." },
  { q: "Qu'est-ce qu'une réduction de couche intermédiaire (Mittelgrund) ?", opts: ["Une analyse qui garde tous les accords de surface", "Une analyse qui regroupe les accords de surface par fonctions et élimine les ornements, révélant les prolongations principales", "Une analyse uniquement mélodique", "Une réduction qui garde uniquement I et V"], a: 1, fb: "Le Mittelgrund est une couche intermédiaire où l'on élimine les accords de passage et de broderie, en regroupant les accords de surface par fonction. On obtient une vue des prolongations principales sans aller jusqu'à la Ursatz complète." },
  { q: "Comment décide-t-on qu'un accord est 'éliminable' dans la réduction ?", opts: ["En éliminant les accords mineurs", "En éliminant les accords qui n'ont pas de rôle fonctionnel propre — accords de passage, broderies, ornements", "En éliminant tous les accords sur temps faibles", "En éliminant les renversements"], a: 1, fb: "Un accord est éliminable s'il n'a pas de rôle fonctionnel indépendant : accord de passage entre deux piliers, accord de broderie, accord de voisinage. Sa suppression ne change pas la logique tonale fondamentale." },
  { q: "Dans la réduction de I–IV–I6–V7–I, quelle serait la version réduite à la couche intermédiaire ?", opts: ["I–I6–V7–I", "I–IV–V–I", "I–V–I", "I–V7–I"], a: 3, fb: "I–IV–V7–I est une réduction intermédiaire raisonnable : on garde I, IV (SD), V7 (D) et I. I6 est éliminé car c'est une prolongation de I (même accord en renversement). La réduction profonde serait I–V–I (Bassbrechung)." },
  { q: "La réduction en couches révèle quel type de structure ?", opts: ["La structure rythmique uniquement", "La structure hiérarchique : de la complexité de surface à la simplicité fondamentale", "La structure contrapuntique de chaque voix", "La structure modale de l'œuvre"], a: 1, fb: "La réduction en couches révèle la hiérarchie harmonique : à chaque couche, la structure devient plus simple et plus fondamentale. La complexité de surface (Vordergrund) se résout en prolongations (Mittelgrund) puis en Ursatz (Hintergrund)." },
  { q: "Que révèle la différence entre le Vordergrund et le Hintergrund ?", opts: ["Les erreurs d'harmonie du compositeur", "La richesse des ornements et prolongations qui développent la structure fondamentale — c'est le 'contenu' de l'œuvre", "Les parties copiées sur d'autres compositeurs", "Les difficultés techniques de la pièce"], a: 1, fb: "La différence entre surface et structure profonde montre comment le compositeur 'habille' la Ursatz : les prolongations, ornements et développements qui donnent à chaque œuvre sa personnalité unique tout en reposant sur la même structure fondamentale." },
  { q: "Peut-on réduire une pièce en couches sans connaître la tonalité ?", opts: ["Oui — la réduction est indépendante de la tonalité", "Non — la tonalité est le cadre indispensable pour identifier les fonctions et les piliers", "Oui, si on ne garde que la basse", "Oui, mais uniquement pour le Vordergrund"], a: 1, fb: "La réduction schenkérienne présuppose la tonalité : identifier T, SD, D et leurs prolongations exige de connaître la tonalité. Sans ce cadre, on ne peut pas distinguer accord structural et accord ornemental." },
  { q: "Comment la notion de couches s'applique-t-elle à une phrase de 8 mesures ?", opts: ["Chaque mesure est une couche distincte", "Surface : tous les accords des 8 mesures. Intermédiaire : I–IV–V–I (piliers). Profond : I–V–I (Ursatz)", "La phrase de 8 mesures n'a pas de structure en couches", "Les couches ne s'appliquent qu'aux mouvements entiers"], a: 1, fb: "Même une courte phrase de 8 mesures peut être analysée en couches : surface (tous les accords), intermédiaire (piliers fonctionnels T–SD–D–T), profond (Ursatz I–V–I). C'est le principe fractal de l'analyse schenkérienne." },
  { q: "Quelle est l'utilité pratique de la réduction en couches pour un compositeur ?", opts: ["Aucune — c'est uniquement pour l'analyse théorique", "Comprendre la structure profonde pour écrire des œuvres longues cohérentes et planifier la trajectoire harmonique à grande échelle", "Simplifier l'écriture en n'utilisant que I et V", "Éviter les accords complexes"], a: 1, fb: "La réduction en couches aide le compositeur à planifier la grande forme : quelle est la Bassbrechung de l'œuvre ? Quand arrive le V structurel ? Comment les prolongations intermédiaires développent-elles la Ursatz ? C'est un outil de composition autant qu'd'analyse." },

  // ── 8. Analyse d'exemples Bach/Mozart ────────────────────────────────────
  { q: "Dans le Prélude en Do majeur BWV 846 de Bach (arpeggios), la structure harmonique de surface est :", opts: ["Uniquement I pendant toute la pièce", "Une succession d'accords arpégés changeants sur un plan harmonique fonctionnel T→SD→D→T", "Une improvisation sans structure", "Une série de modulations dans les tons voisins"], a: 1, fb: "Le Prélude BWV 846 réalise une progression harmonique fonctionnelle complète à travers des arpeggios : la structure de surface est riche mais la structure profonde est une simple progression T→SD→D→T réalisant la Ursatz." },
  { q: "Dans un choral de Bach, les cadences internes servent principalement à :", opts: ["Changer de tonalité définitivement", "Articuler la structure en phrases et sections, créant des piliers harmoniques intermédiaires dans la réduction", "Éviter les quintes parallèles", "Introduire de nouvelles voix"], a: 1, fb: "Les cadences internes (demi-cadences, cadences imparfaites) d'un choral Bach articulent la structure : elles créent des points d'ancrage intermédiaires dans la réduction, révélant la hiérarchie des cadences (intermédiaires vs finale)." },
  { q: "Dans la Sonate K.331 de Mozart (thème avec variations), la structure harmonique du thème est :", opts: ["Complexe et modulante dès la 1ère phrase", "Simple — I prolongé (mm.1–4), puis V (mm.5–8), résolution sur I (mm.9–16) : Bassbrechung claire", "Uniquement sur IV et V alternés", "Sans structure fonctionnelle claire"], a: 1, fb: "Le thème de K.331 réalise la Bassbrechung sur 16 mesures : présentation sur I (mm.1–8), tension sur V (mm.9–14), résolution I (mm.15–16). La structure est un modèle d'économie tonale." },
  { q: "Dans une fugue de Bach en Do majeur, quand le sujet entre en Sol majeur (V), cela représente :", opts: ["Une modulation définitive en Sol majeur", "La réponse tonale — une tonicisation de V qui s'inscrit dans la Bassbrechung I→V", "Une erreur d'écriture du contrepoint", "L'exposition du contre-sujet"], a: 1, fb: "La réponse en V dans une fugue réalise le premier mouvement de la Bassbrechung : I→V. La fugue 'module' vers V mais c'est une tonicisation qui s'inscrit dans l'arche fondamentale I–V–I de toute la fugue." },
  { q: "Dans le 1er mouvement de la Symphonie n°40 KV550 de Mozart, le 2e thème en Sib majeur représente :", opts: ["Une modulation définitive et indépendante", "La tonicisation du III (relatif majeur du mineur) — mouvement harmonique de l'exposition vers la 'dominante' structurelle", "Une erreur de tonalité de Mozart", "Le début de la récapitulation"], a: 1, fb: "En Sol mineur, le 2e thème en Sib (bIII = relatif majeur) représente le mouvement structural de l'exposition vers la zone de dominante. Dans la Bassbrechung en mineur, bIII joue souvent le rôle de la dominante structurelle de l'exposition." },
  { q: "Dans un menuet de Haydn de 16 mesures, la cadence sur V à la mesure 8 représente :", opts: ["La fin de l'œuvre", "Le V structurel de la Bassbrechung — point de tension médian avant le retour sur I à la fin", "Une modulation définitive en Sol", "Un accident harmonique non planifié"], a: 1, fb: "La cadence sur V à mi-parcours est typique de la forme période : le V de la mesure 8 est le V structural de la Bassbrechung. Tout ce qui suit (mm.9–16) prolonge le retour vers I final — c'est la deuxième moitié de l'arche I–V–I." },
  { q: "Dans la Chaconne BWV 1004 de Bach (basse obstinée), la Bassbrechung s'étend sur :", opts: ["Chaque répétition de la basse uniquement", "L'œuvre entière — les 64 variations prolongent une Ursatz unique de la première à la dernière mesure", "Les 4 premières variations uniquement", "La basse obstinée n'a pas de Bassbrechung"], a: 1, fb: "La Chaconne de Bach réalise une Ursatz à l'échelle de l'œuvre entière : les 64 variations sont une prolongation monumentale de I–V–I. La basse obstinée est elle-même une prolongation de la Bassbrechung fondamentale." },
  { q: "Comment analyser un choral Bach en 4 mesures avec la méthode de réduction ?", opts: ["Garder tous les accords et les numéroter", "1) noter tous les accords, 2) repérer ouverture (T), cadence médiane (V ou II6–V), cadence finale (V–I), 3) réduire à la Bassbrechung I–V–I", "Simplifier à I–IV–V–I uniquement", "Identifier uniquement les renversements"], a: 1, fb: "La méthode en 3 étapes : 1) surface complète, 2) piliers fonctionnels (ouverture T, cadences intermédiaires et finale), 3) Bassbrechung I–V–I. Cette approche évite l'analyse purement accord par accord et révèle la structure profonde." },
  { q: "Dans Mozart K.545 (Sonate en Do majeur, début), les 4 premières mesures prolongent :", opts: ["V uniquement", "I (tonique) à travers des harmonies de surface variées (I–V6–I–IV6–I6/4–V–I)", "IV uniquement", "La sous-dominante"], a: 1, fb: "Les mm.1–4 de K.545 prolongent I (tonique) : les harmonies de surface (V6, IV6, I6/4–V–I) ornent la tonique et la cadencent. La structure profonde de ces 4 mesures est I prolongé — un Kopfton suspendu avant le mouvement réel vers V." },
  { q: "Pourquoi Bach et Mozart sont-ils les auteurs de référence pour l'analyse schenkérienne ?", opts: ["Parce qu'ils utilisaient exactement les mêmes formules", "Parce que leur écriture tonale est exemplaire : structure profonde simple, prolongations élaborées, logique harmonique irréprochable", "Parce que Schenker les connaissait personnellement", "Parce que leur musique est la plus difficile à analyser"], a: 1, fb: "Bach et Mozart sont des modèles parce que leur écriture tonale réalise parfaitement la Ursatz : derrière une surface d'une grande richesse, la structure profonde est d'une clarté et d'une logique exemplaires. Ils illustrent idéalement les principes schenkériens." },

  // ── 9. Application pratique ────────────────────────────────────────────────
  { q: "Dans la progression Do–Sol–La–Fa–Sol–Do (basse, Do majeur), quel est l'accord structurel de dominante ?", opts: ["La (VI)", "Fa (IV)", "Sol (V) — les deux occurrences", "Do (I)"], a: 2, fb: "Sol (V) est l'accord structurel de dominante. Les deux occurrences de Sol peuvent prolonger V avant la résolution finale sur I. Do = T, La = T prolongé (VI), Fa = SD, Sol = D, Do = T : progression T–T–SD–D–T." },
  { q: "Vous analysez 8 mesures. La structure est I–IV–I6–V6–I–II6–V7–I. Quels sont les piliers structuraux ?", opts: ["Tous les 8 accords sont des piliers", "I (début), V (cadence médiane ou dominante), I (conclusion) — les autres sont prolongations", "I, IV, V7, I uniquement", "I6, V6, II6, I"], a: 1, fb: "Les piliers structuraux sont I (ouverture), V/V7 (dominante) et I (conclusion). IV, I6, V6 et II6 sont des prolongations ou des ornements fonctionnels. La Bassbrechung sous-jacente est I–V–I." },
  { q: "On vous donne la mélodie Mi–Ré–Do sur 3 mesures (Do majeur, harmonisée par I–V–I). C'est un exemple de :", opts: ["Bassbrechung uniquement", "Urlinie 3̂–2̂–1̂ harmonisée par la Ursatz I–V–I — un exemple parfait de structure fondamentale", "Prolongation de V", "Cadence imparfaite"], a: 1, fb: "Mi–Ré–Do (3̂–2̂–1̂) sur I–V–I est l'exemple le plus pur de la Ursatz : l'Urlinie de tierce descend de 3̂ à 1̂ supportée par la Bassbrechung I–V–I. C'est le modèle de base que Schenker illustre dans Der freie Satz." },
  { q: "Comment déterminer si une modulation est structurelle ou ornementale dans une pièce ?", opts: ["Toutes les modulations sont structurelles", "Si la nouvelle tonalité est confirmée par une cadence V–I et maintenue pendant une section significative, elle est structurelle ; sinon c'est une tonicisation ornementale", "Une modulation est toujours ornementale", "Si la modulation dure plus de 2 mesures, elle est structurelle"], a: 1, fb: "La distinction clé : tonicisation (momentanée, quelques accords) vs modulation structurelle (confirmée par V–I, maintenue sur une section). Dans l'analyse en couches, les tonicisations disparaissent au Mittelgrund ; seules les modulations structurelles persistent." },
  { q: "Dans une analyse pratique, par où commencer ?", opts: ["Par la dernière mesure", "Par identifier la tonalité, puis repérer la cadence finale (V–I), puis remonter vers le début", "Par les notes les plus aiguës", "Par analyser chaque accord de gauche à droite sans ordre particulier"], a: 1, fb: "Commencer par la tonalité et la cadence finale est la stratégie schenkérienne : la cadence finale (V–I) est le V et le I de la Bassbrechung. On remonte ensuite pour trouver comment la structure profonde se déploie depuis l'ouverture." },
  { q: "Laquelle de ces analyses de I–VI–II–V–I est correcte ?", opts: ["I=D, VI=T, II=SD, V=D, I=T", "I=T, VI=T (prolongation), II=SD, V=D, I=T", "I=T, VI=SD, II=D, V=T, I=D", "I=SD, VI=D, II=T, V=SD, I=T"], a: 1, fb: "I=T, VI=T (VI appartient à la région tonique), II=SD, V=D, I=T. La progression réalise T(prolongé par VI)–SD–D–T. L'analyse correcte identifie VI comme appartenant à la région tonique, pas à une autre fonction." },
  { q: "Vous devez réduire I–I6–IV–II6–I6/4–V7–I à la couche intermédiaire. Quel est le résultat ?", opts: ["I–IV–II6–V7–I", "I–IV–V7–I (ou I–II6–V7–I)", "I–I6/4–V7–I", "I–V–I uniquement"], a: 1, fb: "À la couche intermédiaire, I6 (prolongation de I) et II6 ou IV (SD) sont gardés, I6/4 (prolongation de V) est parfois éliminé. Le résultat typique est I–IV–V7–I ou I–II6–V7–I — la structure fonctionnelle T–SD–D–T sans les ornements." },
  { q: "Quelle est la meilleure analyse de surface pour Do–Sol–Mi–Do (basse ascendante, Do majeur) ?", opts: ["I–V–I6–I (arpège de I)", "I–V–III–I (4 accords différents)", "I prolongé par arpège (I–I6–I6/4–I) — une seule fonction tonique", "II–V–I–I"], a: 2, fb: "Do–Sol–Mi–Do à la basse arpège l'accord de Do majeur : Do = état fondamental, Sol = I6/4 (quinte à la basse), Mi = I6 (tierce à la basse), Do = état fondamental. C'est une prolongation tonique par arpège — une seule fonction T." },
  { q: "Pourquoi la cadence V–I est-elle le pilier final de toute Ursatz ?", opts: ["Par convention arbitraire", "Parce que V–I réalise la résolution de la tension maximale (dominante) vers le repos (tonique) — la conclusion obligatoire de toute logique tonale", "Parce que V–I est la cadence la plus longue", "Parce que I sonne plus fort que V"], a: 1, fb: "V–I est la résolution fondamentale de la logique tonale : la dominante crée la tension maximale (triton dans V7, sensible vers tonique) que seule la tonique peut résoudre. C'est la conclusion inévitable de la Bassbrechung et de l'Urlinie." },
];

const questionsEn: Question[] = [
  // ── 1. Tonal regions (T/SD/D) ──────────────────────────────────────────
  { q: "Which scale degrees belong to the tonic region (T) in C major?", opts: ["I, II, IV", "I, III, VI", "V, VII, II", "IV, VI, III"], a: 1, fb: "The tonic region includes chords that evoke the stability of the tonic: I, III, and VI. These chords share two notes with I (C–E–G) and reinforce the feeling of rest." },
  { q: "Which scale degrees belong to the subdominant region (SD) in C major?", opts: ["I, III, VI", "V, VII", "II, IV", "I, IV, V"], a: 2, fb: "The subdominant region includes II and IV. These chords prepare the dominant harmonically — they create intermediate tension between rest (T) and maximum tension (D)." },
  { q: "Which scale degrees belong to the dominant region (D) in C major?", opts: ["I, III, VI", "II, IV", "V, VII", "III, V"], a: 2, fb: "The dominant region includes V and VII. These chords carry maximum tension and demand resolution toward the tonic. V7 is the dominant chord par excellence; VII is its incomplete form." },
  { q: "In the progression I–VI–II–V–I, what region does VI belong to?", opts: ["Dominant region", "Subdominant region", "Tonic region", "No region"], a: 2, fb: "VI (A minor in C major) belongs to the tonic region because it shares two notes with I (C and E). In this progression, VI prolongs the tonic before the movement toward SD (II) and D (V)." },
  { q: "The progression T–SD–D–T describes:", opts: ["The rule of parallel fifths", "The basic functional sequence of tonal harmony", "The structure of the Urlinie", "The principle of the Bassbrechung"], a: 1, fb: "T–SD–D–T is the fundamental functional schema of tonal music: stable departure (T), preparation (SD), maximum tension (D), return to rest (T). Every tonal progression can be read as a variant of this model." },
  { q: "The II6 chord (2nd degree in first inversion) belongs to which functional region?", opts: ["Tonic region", "Dominant region", "Subdominant region", "None — inversions change the region"], a: 2, fb: "Inversion does not change the functional region. II (D–F–A) belongs to the subdominant region whether in root position or first inversion. II6 is even the preferred form of II in classical style before V." },
  { q: "Why is IV–V–IV a discouraged progression?", opts: ["Because IV and V cannot follow each other", "Because this backward motion D→SD breaks the directional logic SD→D→T", "Because IV does not belong to the scale", "Because V followed by IV systematically creates parallel fifths"], a: 1, fb: "IV–V–IV represents a functional 'backward step': leaving the subdominant for the dominant, then returning to the subdominant. This hesitation breaks the directional logic T→SD→D→T and weakens the progression." },
  { q: "In G major, the E minor chord (VIm) belongs to:", opts: ["Dominant region", "Subdominant region", "Tonic region", "None of these regions"], a: 2, fb: "In G major, VI is E minor. It belongs to the tonic region because it shares two notes with I (G and B of G–B–D). E–G–B shares G and B with G major — it has the tonic color of rest." },
  { q: "What is a tonic region prolongation?", opts: ["A chord foreign to the key", "A sequence of chords that maintains the functional color of T without changing region", "The obligatory passage through V before I", "The literal repetition of I at the octave"], a: 1, fb: "A tonic prolongation is a set of chords (e.g. I–VI–I6–I) that remain in region T. They ornament and sustain the tonic's restful color without any real functional movement toward SD or D." },
  { q: "In a classical 8-measure sentence form, measures 1–4 are often:", opts: ["D–T–D–T", "Prolonged T, then movement toward D", "SD only", "Rapid alternation T/D/T/D"], a: 1, fb: "The classical sentence begins with a presentation (mm. 1–4) that prolongs the tonic, then a continuation (mm. 5–8) that develops the SD–D–T movement toward the final cadence. This is the archetypal structure of Haydn and Mozart." },

  // ── 2. Harmonic prolongation ────────────────────────────────────────────
  { q: "What is harmonic prolongation?", opts: ["A chord played very loudly to be heard", "The maintenance of a harmonic function over several measures through changing surface harmonies", "The lengthening of all note durations", "A chord held without change for several measures"], a: 1, fb: "Harmonic prolongation is the principle by which a function (T, SD, or D) is maintained over several measures, even as the surface chords change. E.g.: I–I6–I6/4 all prolong the tonic function." },
  { q: "The progression I–VI–I6–I is an example of:", opts: ["Movement T→SD→D→T", "Prolongation of the tonic region", "Authentic cadence", "Bassbrechung"], a: 1, fb: "I–VI–I6–I prolongs the tonic region: VI belongs to T (shares two notes with I), I6 is I in inversion. All these chords maintain the functional restful color of the tonic." },
  { q: "In a dominant prolongation, which chord can 'ornament' V without leaving it functionally?", opts: ["IV", "I6/4 (before V, the cadential 6/4)", "II", "VI"], a: 1, fb: "The cadential 6/4 (I6/4) on a strong beat prolongs the dominant region: its bass is G (fifth of I but also root of V), and it resolves immediately to V. I6/4–V is said to form a dominant prolongation unit." },
  { q: "How do you recognize a prolongation in an analysis?", opts: ["All chords have the same duration", "Several successive chords share the same regional function and serve to ornament or develop a structural chord", "All chords are in the same octave", "The bass does not move at all"], a: 1, fb: "A prolongation is recognized by functional coherence: several different surface chords that maintain the same region (T, SD, or D). The structural chord is the pillar; the others are its ornaments." },
  { q: "A pedal point on G in the bass prolongs:", opts: ["The tonic region only", "The dominant region, maintaining the root of V under changing harmonies", "The subdominant region", "No specific region"], a: 1, fb: "A pedal on G (dominant) maintains the tension of V under changing harmonies. The chords passing above are surface ornaments — the structural function remains D throughout the pedal." },
  { q: "What is the difference between a passing chord and a structural chord?", opts: ["The passing chord is longer", "The structural chord is a functional pillar; the passing chord is an ornament between two pillars", "The structural chord is always in root position", "There is no difference — all chords are equal"], a: 1, fb: "The structural chord (pillar) is a functional anchor point in the layered analysis. The passing chord is a surface ornament connecting two pillars — it has no independent structural weight." },
  { q: "In the sequence I–IV–I6–V–I, which chords prolong the tonic at the beginning?", opts: ["I and IV", "I, IV, and I6", "I alone", "I and I6"], a: 3, fb: "I and I6 prolong the tonic (same chord, different inversion). IV belongs to SD — it is a move toward the subdominant, not a tonic prolongation. So only I and I6 prolong T here." },
  { q: "An ascending bass scale (C–D–E–F) under a I chord prolongs:", opts: ["The dominant", "The tonic through ornamental bass motion", "The subdominant", "No region — the scale breaks the prolongation"], a: 1, fb: "An ascending stepwise bass line (C–D–E–F) can prolong the tonic: the bass ornaments the I chord by passing through intermediate positions (I–I6–I6/4 or with passing harmonies). This is prolongation through arpeggiated or stepwise bass." },
  { q: "The concept of prolongation is central to the analysis of:", opts: ["Schoenberg", "Schenker", "Rameau", "Riemann"], a: 1, fb: "Heinrich Schenker (1868–1935) is the theorist who developed prolongation as a fundamental analytical tool. According to him, all tonal music is a prolongation of the Ursatz (fundamental structure)." },
  { q: "A typical dominant prolongation before a final cadence is:", opts: ["V–IV–V", "I6/4–V–V7", "V–VI–V", "I–V–I"], a: 1, fb: "I6/4–V–V7 is a classic dominant prolongation before the cadence: the cadential 6/4 prepares V which is amplified by V7. This entire sequence prolongs the D region before the resolution to I." },

  // ── 3. Surface vs structural harmony ────────────────────────────────────
  { q: "What is surface harmony?", opts: ["Chords played at the top of the piano", "All the chords as they appear in the score", "The main chords of the deep structure", "Chords without inversions"], a: 1, fb: "Surface harmony denotes all chords as they appear in the score — every passing chord, neighbor chord, and ornament. This is the 'visible surface' of the harmony, before any analytical reduction." },
  { q: "What is a structural chord (harmonic pillar)?", opts: ["A chord played fortissimo", "A chord that occupies a key functional position in the deep structure of the piece", "A chord without inversions", "The chord most often repeated in the piece"], a: 1, fb: "A structural chord (or pillar) is a chord that carries a key function in the tonal logic: it anchors a region (T, SD, D) and is part of the deep structure that the reduction seeks to reveal." },
  { q: "How do you distinguish a surface chord from a structural chord?", opts: ["By its duration alone", "By its functional position and its importance for the cadential logic of the phrase", "By its position in the measure (strong beat = structural)", "By the number of notes it contains"], a: 1, fb: "Duration and metric position are clues but not absolute criteria. The structural chord is the one whose removal would change the fundamental tonal logic — it is indispensable to the cadential progression." },
  { q: "In the progression I–IV–V–I, is the IV chord structural or surface?", opts: ["Always surface", "Structural — it articulates the SD movement before D", "Surface — it can be replaced by II6 without changing the structure", "Neither — IV has no harmonic role"], a: 1, fb: "IV is a structural chord of the SD region here: it articulates the functional movement T→SD→D→T. In this context, its presence carries structural meaning. A passing IV between two I's, however, would be surface." },
  { q: "In I–I6–I6/4–V–I, which is the true structural dominant chord?", opts: ["I6/4 because it is on the strong beat", "V — I6/4 is an ornamental prolongation of V (cadential 6/4)", "I6/4 and V together", "None — all are surface"], a: 1, fb: "V is the structural dominant chord. I6/4 (cadential 6/4) is an ornamental prolongation that 'prepares' V — it functionally belongs to the dominant region but is not the structural pillar." },
  { q: "A neighbor chord (harmonized neighbor note) is:", opts: ["A structural chord by definition", "A surface chord that ornaments a structural chord without changing its function", "A pivot chord between two keys", "A modulatory passing chord"], a: 1, fb: "A neighbor chord is a surface chord: it ornaments a structural chord by departing from and returning to it. It creates no independent functional movement — it prolongs the structural chord it surrounds." },
  { q: "How do you identify the structural pillars of a 4-measure phrase?", opts: ["Take all chords on strong beats", "Identify the opening chord, the medial cadence, and the final cadence — the rest are prolongations", "Keep only I and V chords", "Identify the longest chords"], a: 1, fb: "The Schenkerian strategy is to locate the cadential anchor points: opening (tonic), medial cadence (often half cadence V), final cadence (V–I). These three poles form the structural skeleton." },
  { q: "In a reduction, what is done with passing chords?", opts: ["They are transposed to the octave", "They are removed — they are not part of the deep structure", "They are moved to the strong beat", "They are replaced by seventh chords"], a: 1, fb: "In the reduction, passing chords are eliminated because they do not belong to the deep structure. Only the structural pillars (opening, cadences) and their direct prolongations are retained." },
  { q: "What is the limitation of purely surface analysis (chord by chord)?", opts: ["It is too simple for advanced musicians", "It does not reveal the deep tonal logic and may mask the directional structure of the piece", "It does not exist — surface analysis is the only valid method", "It always produces harmonic errors"], a: 1, fb: "Chord-by-chord analysis remains at the surface: it may miss prolongations and large functional arches. The deep structure (T→D→T across an entire work) is invisible if one stops at the surface." },
  { q: "Why is the surface/structure distinction pedagogically important?", opts: ["To simplify learning", "To understand that not all chords have equal importance and to develop hierarchical reading", "To avoid analyzing certain difficult chords", "To memorize progressions more easily"], a: 1, fb: "The surface/structure distinction develops hierarchical thinking: the student understands that the richness of surface harmony serves a simpler, deeper structure. It is a tool of understanding, not simplification." },

  // ── 4. The Urlinie ─────────────────────────────────────────────────────
  { q: "What is the Urlinie according to Schenker?", opts: ["The fundamental bass line", "The fundamental descending melodic soprano line, from 3̂/5̂/8̂ down to 1̂", "The tenor line in a chorale", "The main melody of the work"], a: 1, fb: "The Urlinie ('fundamental line') is the fundamental descent of the soprano, starting from 3̂, 5̂, or 8̂ and descending diatonically to 1̂ (tonic). It is the deep melodic structure that every tonal melody realizes, according to Schenker." },
  { q: "What are the three possible forms of the Urlinie?", opts: ["1̂–2̂–3̂, 3̂–4̂–5̂, 5̂–6̂–7̂", "3̂–2̂–1̂, 5̂–4̂–3̂–2̂–1̂, 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "C–D–E, G–A–B, E–F–G", "I–V–I, I–IV–I, I–II–I"], a: 1, fb: "Schenker recognizes three Urlinien: 3̂–2̂–1̂ (third descent), 5̂–4̂–3̂–2̂–1̂ (fifth descent), and 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (octave descent). Every great tonal melody realizes one of these three forms." },
  { q: "In the Urlinie 3̂–2̂–1̂ in C major, what note corresponds to 3̂?", opts: ["C", "D", "E", "G"], a: 2, fb: "In C major, 3̂ is E (3rd degree of the scale). The Urlinie 3̂–2̂–1̂ descends E–D–C. E is the Kopfton (head tone) that initiates the fundamental line." },
  { q: "In the Urlinie 5̂–4̂–3̂–2̂–1̂ in G major, what is the starting note?", opts: ["G", "D", "B", "A"], a: 1, fb: "In G major, 5̂ is D (fifth of G). The Urlinie 5̂–4̂–3̂–2̂–1̂ descends D–C–B–A–G. D is the Kopfton (head tone) that initiates the fundamental descent." },
  { q: "Why does the Urlinie always descend toward 1̂?", opts: ["By Schenker's arbitrary convention", "Because 1̂ (tonic) is the point of resolution and rest of all tonal melodic tension", "Because soprano voices always descend", "To avoid parallel fifths"], a: 1, fb: "1̂ is the tonic — the point of final resolution of all tension. In tonal logic, all melodic tension must resolve to the tonic. The Urlinie embodies this obligatory resolution at the scale of the entire work." },
  { q: "How do you locate the Kopfton (head tone, beginning of the Urlinie) in a melody?", opts: ["It is the highest note of the melody", "It is the structurally predominant note at the opening, harmonized by I, from which the fundamental descent begins", "It is the first note of the melody", "It is the longest note"], a: 1, fb: "The Kopfton is the structural opening note (3̂, 5̂, or 8̂) that belongs to the initial tonic chord and from which the Urlinie descent begins. It is not necessarily the first or highest note." },
  { q: "In the melody E–F–E–D–C (C major), what is the likely Urlinie?", opts: ["5̂–4̂–3̂–2̂–1̂", "3̂–2̂–1̂ with E as Kopfton", "8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "No Urlinie — the melody is too ornamental"], a: 1, fb: "E is 3̂ in C major. The melody E–F–E–D–C realizes the Urlinie 3̂–2̂–1̂ (E–D–C) with F as an ornamental neighbor note. The Kopfton is E, and the structural descent is 3̂(E)–2̂(D)–1̂(C)." },
  { q: "Is the Urlinie always directly audible in the surface melody?", opts: ["Yes — it always corresponds to the exact melody", "No — it is often ornamented, displaced to the octave, or interrupted by surface foreign notes", "No — it always belongs to the bass", "Yes — but only in Bach's music"], a: 1, fb: "The Urlinie is an abstraction of the surface melody — it is ornamented, prolonged, interrupted. The actual melody is a surface realization of this deep structure. One must 'hear through' the surface to extract it." },
  { q: "What does '2̂ harmonized by V' mean in the Urlinie?", opts: ["The 2nd degree is played by the tenor", "The note 2̂ coincides with the dominant chord in the deep structure", "The 2nd degree is played twice", "The V chord is in second inversion"], a: 1, fb: "In the Urlinie, each fundamental note is harmonized by a structural chord: 2̂ coincides with V (dominant) and 1̂ with I (tonic). This conjunction of Urlinie and Bassbrechung forms the Ursatz." },
  { q: "Why does Schenker say that every great tonal melody realizes the Urlinie?", opts: ["Because all melodies are identical", "Because tonal logic demands the resolution of all tension toward the tonic — the Urlinie is the universal melodic expression of this law", "Because he analyzed every existing melody", "Because composers all copy the same model"], a: 1, fb: "For Schenker, tonal logic is universal: all tension must resolve toward 1̂. The Urlinie is not a schema imposed from the outside but the inevitable consequence of tonality itself." },

  // ── 5. The Bassbrechung ────────────────────────────────────────────────
  { q: "What is the Bassbrechung?", opts: ["The descending melodic line of the soprano", "The bass arch I–V–I that structures tonality at the scale of the entire work", "A Baroque continuo technique", "The figured bass notation in a chorale"], a: 1, fb: "The Bassbrechung ('bass arpeggiation') is the fundamental arch I–V–I in the bass, describing the fundamental fifth motion of tonal harmony: from the tonic to the dominant, then back to the tonic." },
  { q: "What is the fundamental bass of the Bassbrechung in C major?", opts: ["C–F–C", "C–G–C", "C–D–C", "C–A–C"], a: 1, fb: "The Bassbrechung in C major is C–G–C (I–V–I). G is the dominant — the fifth of the scale. The arch C→G→C represents the fundamental fifth motion of the key." },
  { q: "Does the Bassbrechung span a phrase, a section, or an entire work?", opts: ["Only a 4-measure phrase", "It can extend to any scale — from a phrase to an entire work", "Only short forms (song)", "It applies only to Bach's chorales"], a: 1, fb: "The Bassbrechung is scalable: it can structure a phrase (mm. 1–4), a section (mm. 1–16), an entire movement, or a complete symphony. This fractal character makes Schenkerian analysis universal." },
  { q: "How is the Bassbrechung related to the Urlinie in the Ursatz?", opts: ["They are independent", "The Bassbrechung (bass I–V–I) supports the Urlinie (soprano 3̂–2̂–1̂) — together they form the Ursatz", "The Urlinie is the melodic version of the Bassbrechung", "The Bassbrechung replaces the Urlinie in minor mode"], a: 1, fb: "In the Ursatz, the Urlinie (soprano) and the Bassbrechung (bass) are superimposed: 3̂ over I, 2̂ over V, 1̂ over I. This two-voice counterpoint is the universal fundamental structure of tonal music according to Schenker." },
  { q: "What does the intermediate V represent in the Bassbrechung I–V–I?", opts: ["A momentary tonicization", "The point of maximum tension — the dominant that structures the progression toward final resolution on I", "A passing chord of no importance", "The subdominant in inversion"], a: 1, fb: "V in I–V–I is the tension summit of the Bassbrechung — it represents the fundamental descending fifth motion of tonality (fifth I→V or ascending fourth). Its resolution to I concludes the tonal arch." },
  { q: "In a 100-measure Bach fugue, where does the V of the Bassbrechung generally occur?", opts: ["In measure 2 only", "At the structural midpoint of the work, often at the largest intermediate cadence", "At the end of every phrase", "There is no Bassbrechung in fugues"], a: 1, fb: "In a large form, the structural V of the Bassbrechung coincides with the work's maximum tension point — often the large V cadence at mid-course. Everything before prolongs I (outward journey); everything after prolongs the return to I." },
  { q: "The Bassbrechung is analogous to what formal principle in sonata form?", opts: ["The exposition and recapitulation", "The presentation → tension (development) → resolution (recapitulation), i.e. I→V→I at large scale", "The main theme only", "The final coda"], a: 1, fb: "Sonata form realizes the Bassbrechung at large scale: exposition in I (often with 2nd theme in V), development (harmonic tension), recapitulation in I. This tonal structure I–V–I is the Bassbrechung of the entire work." },
  { q: "In minor, is the Bassbrechung Im–Vm–Im or Im–V–Im?", opts: ["Im–Vm–Im (minor at the dominant)", "Im–V–Im (major dominant, with raised leading tone)", "Im–bVII–Im", "Im–IV–Im"], a: 1, fb: "In minor, the dominant is always major V (with raised leading tone). The Bassbrechung is therefore Im–V–Im: harmonic minor is used at the dominant to preserve the maximum tension of the leading tone toward the tonic." },
  { q: "What bass interval characterizes the I→V motion in the Bassbrechung?", opts: ["Ascending third", "Descending fifth (or ascending fourth) — the fundamental motion of tonal harmony", "Ascending second", "Descending sixth"], a: 1, fb: "I→V corresponds to a descending fifth (C→G in C major) or ascending fourth. This is the most powerful motion in tonal harmony — it creates maximum tension that calls for the resolution V→I." },
  { q: "The Bassbrechung is considered by Schenker to be:", opts: ["An optional schema for bass analysis", "The universal bass motion of all tonal music — the fundamental arch of two-voice counterpoint", "A rule applicable only to Bach", "A pedagogical simplification with no analytical value"], a: 1, fb: "For Schenker, the Bassbrechung is a universal law: all tonal music realizes the I–V–I bass motion at whatever scale. It is the harmonic foundation of the Ursatz." },

  // ── 6. The Ursatz ─────────────────────────────────────────────────────
  { q: "What is the Ursatz according to Schenker?", opts: ["The fundamental rhythmic structure", "The fundamental contrapuntal structure = Urlinie (soprano) + Bassbrechung (bass)", "The fundamental scale of every key", "The main thematic motif of a work"], a: 1, fb: "The Ursatz ('fundamental structure') is the superimposition of the Urlinie (soprano descent 3̂–2̂–1̂) and the Bassbrechung (bass arch I–V–I). It is a two-voice counterpoint underlying all tonal music." },
  { q: "How many layers does the Ursatz consist of?", opts: ["One — the main melody", "Two — soprano (Urlinie) and bass (Bassbrechung)", "Three — soprano, alto, bass", "Four — the four SATB voices"], a: 1, fb: "The Ursatz is a two-voice counterpoint: the Urlinie in the soprano and the Bassbrechung in the bass. These two fundamental voices suffice to define the deep tonal structure of any work." },
  { q: "In the Ursatz, how are the Urlinie and Bassbrechung aligned?", opts: ["They are independent and never intersect", "3̂ coincides with I (bass), 2̂ with V (bass), 1̂ with I (bass)", "5̂ coincides with V (bass), 3̂ with IV, 1̂ with I", "They alternate without ever synchronizing"], a: 1, fb: "The canonical Ursatz alignment: Kopfton (3̂/5̂/8̂) over I, then intermediate motion (2̂ over V), then resolution (1̂ over I). This superimposition creates the fundamental counterpoint of tonal music." },
  { q: "Why does Schenker say all tonal music is a 'prolongation of the Ursatz'?", opts: ["Because all composers copy the same schema", "Because every tonal composition is an elaboration of this simple fundamental structure — surface ornaments develop the Ursatz", "Because the Ursatz is imposed by the conservatory", "Because the Ursatz is the only audible structure"], a: 1, fb: "The Ursatz is the deepest and simplest structure — every tonal composition elaborates it through successive layers of prolongation. Surface ornaments (melodies, progressions) are increasingly complex realizations of this fundamental arch." },
  { q: "Does the Ursatz apply to 20th-century atonal music?", opts: ["Yes — Schenker applies it to all music", "No — the Ursatz presupposes tonality; atonal music does not follow its principles", "Yes but with modifications", "No — it applies only to Bach"], a: 1, fb: "The Ursatz presupposes tonality: Urlinie descending to 1̂ and Bassbrechung I–V–I. Atonal music, which rejects the hierarchy of scale degrees, cannot be analyzed within this framework. This is an explicit limit of the Schenkerian system." },
  { q: "What is the complete version of the Ursatz with the Urlinie 5̂–4̂–3̂–2̂–1̂?", opts: ["5̂ on I, 4̂ on IV, 3̂ on I, 2̂ on V, 1̂ on I", "5̂ on I, descent 4̂–3̂ prolonged, 2̂ on V, 1̂ on I", "5̂ on V, 4̂ on IV, 3̂ on III, 2̂ on II, 1̂ on I", "5̂ on I, 4̂–3̂–2̂ ornamental, 1̂ on V"], a: 1, fb: "In the fifth-descent Urlinie, degrees 4̂ and 3̂ are often prolonged by intermediate harmonic movements, but the structural anchor points are 5̂ on I, 2̂ on V, and 1̂ on I — forming the complete Ursatz." },
  { q: "Does the Ursatz have a single model or multiple variants?", opts: ["A single unique model for all music", "Three variants according to the Kopfton (3̂, 5̂, or 8̂)", "An infinite number of variants depending on the composer", "Two variants (major and minor)"], a: 1, fb: "Schenker recognizes three Ursatz forms according to the Kopfton: 3̂–2̂–1̂ (simplest), 5̂–4̂–3̂–2̂–1̂ (very frequent), 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (rarer). The Bassbrechung remains I–V–I in all three cases." },
  { q: "How does the Ursatz manifest at large scale in a symphony?", opts: ["Only in the 1st movement", "The home key on I prolongs to the structural V (often at the development), then returns to I at the end", "It is visible only at the phrase level", "It manifests only in the basso continuo"], a: 1, fb: "In a symphony, the Ursatz spans the entire work: the opening anchors on I, the point of maximum tension (often development or central cadence) realizes V, and the conclusion returns to I. The Bassbrechung I–V–I structures the whole work." },
  { q: "What are the 'Vordergrund', 'Mittelgrund', and 'Hintergrund' in Schenkerian analysis?", opts: ["Three different instruments", "Three analytical layers: surface (Vordergrund), middle layer (Mittelgrund), deep structure (Hintergrund = Ursatz)", "Three parts of a fugue", "Three types of cadences"], a: 1, fb: "Schenker uses these three levels: Vordergrund (foreground = surface music as written), Mittelgrund (middleground = grouped prolongations), Hintergrund (background = Ursatz alone). The reduction proceeds from Vordergrund toward Hintergrund." },
  { q: "What is the main contribution of Ursatz theory to musical analysis?", opts: ["It allows memorizing scores more easily", "It reveals the deep tonal structure common to all great works and explains their large-scale coherence", "It simplifies musical notation", "It replaces traditional chord-by-chord harmonic analysis"], a: 1, fb: "The Ursatz enables understanding tonal coherence at large scale: why a 300-measure work 'holds together.' It reveals that surface complexity masks a simple and universal fundamental structure." },

  // ── 7. Layered reduction ───────────────────────────────────────────────
  { q: "How many steps does a complete Schenkerian reduction involve?", opts: ["1 step — go directly to the Ursatz", "At least 3 layers: surface (Vordergrund) → middleground (Mittelgrund) → deep (Hintergrund)", "5 fixed steps identical for each analysis", "2 steps — even chords and odd chords"], a: 1, fb: "Schenkerian reduction proceeds in successive layers: Vordergrund (surface) → Mittelgrund(s) (intermediate layers, sometimes several) → Hintergrund (Ursatz). The number of intermediate layers depends on the complexity of the work." },
  { q: "What is done first in a layered reduction?", opts: ["Identify the Urlinie immediately", "Write all the chords in the score (surface harmony)", "Reduce to the Ursatz", "Analyze the modulations"], a: 1, fb: "The first step is to write out the complete surface harmony — all chords as they appear. This is the Vordergrund: the starting point before any reduction. Do not skip steps." },
  { q: "What is a middleground reduction (Mittelgrund)?", opts: ["An analysis that keeps all surface chords", "An analysis that groups surface chords by function and eliminates ornaments, revealing the main prolongations", "A melodic-only analysis", "A reduction that keeps only I and V"], a: 1, fb: "The Mittelgrund is an intermediate layer where passing and neighbor chords are eliminated, grouping surface chords by function. One obtains a view of the main prolongations without going all the way to the complete Ursatz." },
  { q: "How do you decide that a chord is 'eliminable' in the reduction?", opts: ["By eliminating minor chords", "By eliminating chords that have no independent functional role — passing chords, neighbor chords, ornaments", "By eliminating all chords on weak beats", "By eliminating inversions"], a: 1, fb: "A chord is eliminable if it has no independent functional role: passing chord between two pillars, neighbor chord, ornamental chord. Its removal does not change the fundamental tonal logic." },
  { q: "In the reduction of I–IV–I6–V7–I, what would the middleground version be?", opts: ["I–I6–V7–I", "I–IV–V–I", "I–V–I", "I–V7–I"], a: 3, fb: "I–IV–V7–I is a reasonable middleground reduction: keep I, IV (SD), V7 (D), and I. I6 is eliminated because it is a prolongation of I (same chord in inversion). The deep reduction would be I–V–I (Bassbrechung)." },
  { q: "Layered reduction reveals what type of structure?", opts: ["Rhythmic structure only", "Hierarchical structure: from surface complexity to fundamental simplicity", "The contrapuntal structure of each voice", "The modal structure of the work"], a: 1, fb: "Layered reduction reveals the harmonic hierarchy: at each layer the structure becomes simpler and more fundamental. Surface complexity (Vordergrund) resolves into prolongations (Mittelgrund) and then into the Ursatz (Hintergrund)." },
  { q: "What does the difference between the Vordergrund and Hintergrund reveal?", opts: ["The composer's harmonic errors", "The richness of ornaments and prolongations that develop the fundamental structure — this is the 'content' of the work", "Passages copied from other composers", "The technical difficulties of the piece"], a: 1, fb: "The difference between surface and deep structure shows how the composer 'clothes' the Ursatz: the prolongations, ornaments, and developments that give each work its unique personality while resting on the same fundamental structure." },
  { q: "Can you reduce a piece in layers without knowing the key?", opts: ["Yes — the reduction is independent of the key", "No — the key is the indispensable framework for identifying functions and pillars", "Yes, if you keep only the bass", "Yes, but only for the Vordergrund"], a: 1, fb: "Schenkerian reduction presupposes the key: identifying T, SD, D, and their prolongations requires knowing the key. Without this framework, one cannot distinguish structural chords from ornamental chords." },
  { q: "How does the concept of layers apply to an 8-measure phrase?", opts: ["Each measure is a distinct layer", "Surface: all chords of the 8 measures. Middleground: I–IV–V–I (pillars). Deep: I–V–I (Ursatz)", "An 8-measure phrase has no layered structure", "Layers apply only to entire movements"], a: 1, fb: "Even a short 8-measure phrase can be analyzed in layers: surface (all chords), middleground (functional pillars T–SD–D–T), deep (Ursatz I–V–I). This is the fractal principle of Schenkerian analysis." },
  { q: "What is the practical utility of layered reduction for a composer?", opts: ["None — it is purely for theoretical analysis", "Understanding deep structure to write coherent long works and plan the harmonic trajectory at large scale", "Simplifying writing by using only I and V", "Avoiding complex chords"], a: 1, fb: "Layered reduction helps the composer plan large form: what is the Bassbrechung of the work? When does the structural V arrive? How do intermediate prolongations develop the Ursatz? It is a tool for composition as much as for analysis." },

  // ── 8. Bach/Mozart examples ────────────────────────────────────────────
  { q: "In Bach's Prelude in C major BWV 846 (arpeggios), the surface harmonic structure is:", opts: ["Only I throughout the entire piece", "A succession of changing arpeggiated chords over a functional harmonic plan T→SD→D→T", "An improvisation without structure", "A series of modulations to neighboring keys"], a: 1, fb: "Prelude BWV 846 realizes a complete functional harmonic progression through arpeggios: the surface structure is rich but the deep structure is a simple T→SD→D→T progression realizing the Ursatz." },
  { q: "In a Bach chorale, internal cadences primarily serve to:", opts: ["Definitively change the key", "Articulate the structure into phrases and sections, creating intermediate harmonic pillars in the reduction", "Avoid parallel fifths", "Introduce new voices"], a: 1, fb: "Internal cadences (half cadences, imperfect cadences) in a Bach chorale articulate the structure: they create intermediate anchor points in the reduction, revealing the hierarchy of cadences (intermediate vs. final)." },
  { q: "In Mozart's Sonata K.331 (theme with variations), the harmonic structure of the theme is:", opts: ["Complex and modulatory from the 1st phrase", "Simple — I prolonged (mm. 1–4), then V (mm. 5–8), resolution on I (mm. 9–16): clear Bassbrechung", "Only alternating IV and V", "Without clear functional structure"], a: 1, fb: "The theme of K.331 realizes the Bassbrechung over 16 measures: presentation on I (mm. 1–8), tension on V (mm. 9–14), resolution I (mm. 15–16). The structure is a model of tonal economy." },
  { q: "In a Bach fugue in C major, when the subject enters in G major (V), this represents:", opts: ["A definitive modulation to G major", "The tonal answer — a tonicization of V inscribed in the Bassbrechung I→V", "A counterpoint writing error", "The exposition of the countersubject"], a: 1, fb: "The answer in V in a fugue realizes the first movement of the Bassbrechung: I→V. The fugue 'modulates' to V but it is a tonicization inscribed in the fundamental arch I–V–I of the entire fugue." },
  { q: "In the 1st movement of Mozart's Symphony No. 40 KV550, the 2nd theme in Bb major represents:", opts: ["A definitive and independent modulation", "The tonicization of III (relative major of the minor) — harmonic motion of the exposition toward the structural 'dominant'", "A key error by Mozart", "The beginning of the recapitulation"], a: 1, fb: "In G minor, the 2nd theme in Bb (bIII = relative major) represents the structural motion of the exposition toward the dominant area. In the minor-mode Bassbrechung, bIII often plays the role of the structural dominant in the exposition." },
  { q: "In a 16-measure Haydn minuet, the cadence on V at measure 8 represents:", opts: ["The end of the work", "The structural V of the Bassbrechung — the median tension point before return to I at the end", "A definitive modulation to G", "An unplanned harmonic accident"], a: 1, fb: "The cadence on V at mid-course is typical of period form: the V at measure 8 is the structural V of the Bassbrechung. Everything that follows (mm. 9–16) prolongs the return to the final I — the second half of the arch I–V–I." },
  { q: "In Bach's Chaconne BWV 1004 (ground bass), the Bassbrechung extends over:", opts: ["Each repetition of the bass only", "The entire work — the 64 variations prolong a single Ursatz from the first to the last measure", "Only the first 4 variations", "The ground bass has no Bassbrechung"], a: 1, fb: "Bach's Chaconne realizes a Ursatz at the scale of the entire work: the 64 variations are a monumental prolongation of I–V–I. The ground bass is itself a prolongation of the fundamental Bassbrechung." },
  { q: "How do you analyze a 4-measure Bach chorale with the reduction method?", opts: ["Keep all chords and number them", "1) note all chords, 2) locate opening (T), medial cadence (V or II6–V), final cadence (V–I), 3) reduce to Bassbrechung I–V–I", "Simplify to I–IV–V–I only", "Identify only the inversions"], a: 1, fb: "The 3-step method: 1) complete surface, 2) functional pillars (opening T, intermediate and final cadences), 3) Bassbrechung I–V–I. This approach avoids purely chord-by-chord analysis and reveals the deep structure." },
  { q: "In Mozart K.545 (Sonata in C major, opening), the first 4 measures prolong:", opts: ["V only", "I (tonic) through varied surface harmonies (I–V6–I–IV6–I6/4–V–I)", "IV only", "The subdominant"], a: 1, fb: "Mm. 1–4 of K.545 prolong I (tonic): the surface harmonies (V6, IV6, I6/4–V–I) ornament and cadence the tonic. The deep structure of these 4 measures is a prolonged I — a suspended Kopfton before the real movement toward V." },
  { q: "Why are Bach and Mozart the reference composers for Schenkerian analysis?", opts: ["Because they used exactly the same formulas", "Because their tonal writing is exemplary: simple deep structure, elaborate prolongations, impeccable harmonic logic", "Because Schenker knew them personally", "Because their music is the hardest to analyze"], a: 1, fb: "Bach and Mozart are models because their tonal writing perfectly realizes the Ursatz: behind a very rich surface, the deep structure is of exemplary clarity and logic. They ideally illustrate Schenkerian principles." },

  // ── 9. Practical application ────────────────────────────────────────────
  { q: "In the progression C–G–A–F–G–C (bass, C major), what is the structural dominant chord?", opts: ["A (VI)", "F (IV)", "G (V) — both occurrences", "C (I)"], a: 2, fb: "G (V) is the structural dominant chord. Both occurrences of G can prolong V before the final resolution on I. C = T, A = T prolonged (VI), F = SD, G = D, C = T: progression T–T–SD–D–T." },
  { q: "You are analyzing 8 measures. The structure is I–IV–I6–V6–I–II6–V7–I. What are the structural pillars?", opts: ["All 8 chords are pillars", "I (opening), V (medial cadence or dominant), I (conclusion) — the rest are prolongations", "I, IV, V7, I only", "I6, V6, II6, I"], a: 1, fb: "The structural pillars are I (opening), V/V7 (dominant), and I (conclusion). IV, I6, V6, and II6 are prolongations or functional ornaments. The underlying Bassbrechung is I–V–I." },
  { q: "You are given the melody E–D–C over 3 measures (C major, harmonized by I–V–I). This is an example of:", opts: ["Bassbrechung only", "Urlinie 3̂–2̂–1̂ harmonized by the Ursatz I–V–I — a perfect example of fundamental structure", "V prolongation", "Imperfect cadence"], a: 1, fb: "E–D–C (3̂–2̂–1̂) over I–V–I is the purest example of the Ursatz: the third-descent Urlinie descends from 3̂ to 1̂ supported by the Bassbrechung I–V–I. This is the basic model Schenker illustrates in Der freie Satz." },
  { q: "How do you determine whether a modulation is structural or ornamental in a piece?", opts: ["All modulations are structural", "If the new key is confirmed by a V–I cadence and maintained over a significant section, it is structural; otherwise it is an ornamental tonicization", "A modulation is always ornamental", "If the modulation lasts more than 2 measures, it is structural"], a: 1, fb: "The key distinction: tonicization (momentary, a few chords) vs. structural modulation (confirmed by V–I, maintained over a section). In layered analysis, tonicizations disappear at the Mittelgrund; only structural modulations persist." },
  { q: "In a practical analysis, where do you start?", opts: ["At the last measure", "By identifying the key, then locating the final cadence (V–I), then working back to the beginning", "At the highest notes", "By analyzing each chord from left to right without any particular order"], a: 1, fb: "Starting with the key and final cadence is the Schenkerian strategy: the final cadence (V–I) is the V and I of the Bassbrechung. You then work back to find how the deep structure unfolds from the opening." },
  { q: "Which of these analyses of I–VI–II–V–I is correct?", opts: ["I=D, VI=T, II=SD, V=D, I=T", "I=T, VI=T (prolongation), II=SD, V=D, I=T", "I=T, VI=SD, II=D, V=T, I=D", "I=SD, VI=D, II=T, V=SD, I=T"], a: 1, fb: "I=T, VI=T (VI belongs to the tonic region), II=SD, V=D, I=T. The progression realizes T(prolonged by VI)–SD–D–T. The correct analysis identifies VI as belonging to the tonic region, not another function." },
  { q: "You must reduce I–I6–IV–II6–I6/4–V7–I to the middleground layer. What is the result?", opts: ["I–IV–II6–V7–I", "I–IV–V7–I (or I–II6–V7–I)", "I–I6/4–V7–I", "I–V–I only"], a: 1, fb: "At the middleground layer, I6 (prolongation of I) is eliminated, and IV or II6 (SD) is kept, I6/4 (prolongation of V) is sometimes eliminated. The typical result is I–IV–V7–I or I–II6–V7–I — the functional structure T–SD–D–T without ornaments." },
  { q: "What is the best surface analysis of C–G–E–C (ascending bass, C major)?", opts: ["I–V–I6–I (arpeggio of I)", "I–V–III–I (4 different chords)", "I prolonged by arpeggio (I–I6–I6/4–I) — a single tonic function", "II–V–I–I"], a: 2, fb: "C–G–E–C in the bass arpeggios the C major chord: C = root position, G = I6/4 (fifth in bass), E = I6 (third in bass), C = root position. This is a tonic prolongation through arpeggio — a single T function." },
  { q: "Why is the V–I cadence the final pillar of every Ursatz?", opts: ["By arbitrary convention", "Because V–I realizes the resolution of maximum tension (dominant) toward rest (tonic) — the obligatory conclusion of all tonal logic", "Because V–I is the longest cadence", "Because I sounds louder than V"], a: 1, fb: "V–I is the fundamental resolution of tonal logic: the dominant creates maximum tension (tritone in V7, leading tone to tonic) that only the tonic can resolve. It is the inevitable conclusion of the Bassbrechung and Urlinie." },
];

const questionsEs: Question[] = [
  { q: "¿Qué grados pertenecen a la región tónica (T) en Do mayor?", opts: ["I, II, IV", "I, III, VI", "V, VII, II", "IV, VI, III"], a: 1, fb: "La región tónica agrupa los acordes que evocan la estabilidad de la tónica: I, III y VI. Comparten dos notas con I (Do–Mi–Sol) y refuerzan el color de reposo." },
  { q: "¿Qué grados pertenecen a la región subdominante (SD) en Do mayor?", opts: ["I, III, VI", "V, VII", "II, IV", "I, IV, V"], a: 2, fb: "La región subdominante incluye II y IV. Estos acordes preparan armónicamente la dominante — crean tensión intermedia entre el reposo (T) y la tensión máxima (D)." },
  { q: "¿Qué grados pertenecen a la región dominante (D) en Do mayor?", opts: ["I, III, VI", "II, IV", "V, VII", "III, V"], a: 2, fb: "La región dominante agrupa V y VII. Llevan la tensión máxima y exigen resolución hacia la tónica. V7 es el acorde de dominante por excelencia; VII es su versión incompleta." },
  { q: "En la progresión I–VI–II–V–I, ¿a qué región pertenece VI?", opts: ["Región dominante", "Región subdominante", "Región tónica", "Ninguna región"], a: 2, fb: "VI (La menor en Do mayor) pertenece a la región tónica porque comparte dos notas con I (Do y Mi). En esta progresión, VI prolonga la tónica antes del movimiento hacia SD (II) y D (V)." },
  { q: "La progresión T–SD–D–T describe:", opts: ["La regla de las quintas paralelas", "La secuencia funcional básica de la armonía tonal", "La estructura del Urlinie", "El principio de la Bassbrechung"], a: 1, fb: "T–SD–D–T es el esquema funcional fundamental de la música tonal: partida estable (T), preparación (SD), tensión máxima (D), regreso al reposo (T). Toda progresión tonal puede leerse como una variante de este modelo." },
  { q: "El acorde II6 (2º grado en primera inversión) pertenece a qué región funcional?", opts: ["Región tónica", "Región dominante", "Región subdominante", "Ninguna — las inversiones cambian la región"], a: 2, fb: "La inversión no cambia la región funcional. II (Re–Fa–La) pertenece a la región subdominante en estado fundamental o en primera inversión. II6 es incluso la forma preferida de II en el estilo clásico antes de V." },
  { q: "¿Por qué IV–V–IV es una progresión desaconsejada?", opts: ["Porque IV y V no pueden seguirse", "Porque este retroceso D→SD rompe la lógica direccional SD→D→T", "Porque IV no pertenece a la escala", "Porque V seguido de IV crea quintas paralelas sistemáticas"], a: 1, fb: "IV–V–IV representa un 'retroceso' funcional: se abandona la subdominante para ir a la dominante y luego se vuelve a la subdominante. Esta vacilación rompe la lógica T→SD→D→T y debilita la progresión." },
  { q: "En Sol mayor, el acorde de Mi menor (VIm) pertenece a:", opts: ["Región dominante", "Región subdominante", "Región tónica", "Ninguna de estas regiones"], a: 2, fb: "En Sol mayor, VI es Mi menor. Pertenece a la región tónica porque comparte dos notas con I (Sol y Si de Sol–Si–Re). Mi–Sol–Si comparte Sol y Si con Sol mayor — es el color de reposo tónico." },
  { q: "¿Qué es una prolongación de la región tónica?", opts: ["Un acorde ajeno a la tonalidad", "Una secuencia de acordes que mantiene el color funcional de T sin cambiar de región", "El paso obligatorio por V antes de I", "La repetición literal de I a la octava"], a: 1, fb: "Una prolongación tónica es un conjunto de acordes (ej. I–VI–I6–I) que permanecen en la región T. Adornan y mantienen el color de reposo de la tónica sin movimiento funcional real hacia SD o D." },
  { q: "En una frase de 8 compases en forma sentencia clásica, los compases 1–4 suelen ser:", opts: ["D–T–D–T", "T prolongada, luego movimiento hacia D", "Solo SD", "Alternancia rápida T/D/T/D"], a: 1, fb: "La sentencia clásica comienza con una presentación (cc. 1–4) que prolonga la tónica, luego una continuación (cc. 5–8) que desarrolla el movimiento SD–D–T hacia la cadencia final. Es la estructura arquetípica de Haydn y Mozart." },
  { q: "¿Qué es la prolongación armónica?", opts: ["Un acorde tocado muy fuerte para ser oído", "El mantenimiento de una función armónica durante varios compases a través de armonías de superficie cambiantes", "El aumento de la duración de todas las notas", "Un acorde sostenido sin cambio durante varios compases"], a: 1, fb: "La prolongación armónica es el principio por el que una función (T, SD o D) se mantiene durante varios compases, aunque los acordes de superficie cambien. Ej.: I–I6–I6/4 prolongan todos la función tónica." },
  { q: "La progresión I–VI–I6–I es un ejemplo de:", opts: ["Movimiento T→SD→D→T", "Prolongación de la región tónica", "Cadencia auténtica", "Bassbrechung"], a: 1, fb: "I–VI–I6–I prolonga la región tónica: VI pertenece a T (comparte dos notas con I), I6 es I en inversión. Todos estos acordes mantienen el color funcional de reposo de la tónica." },
  { q: "En una prolongación de dominante, ¿qué acorde puede 'adornar' V sin abandonarlo funcionalmente?", opts: ["IV", "I6/4 (antes de V, el 6/4 cadencial)", "II", "VI"], a: 1, fb: "El 6/4 cadencial (I6/4) en tiempo fuerte prolonga la región dominante: su bajo es Sol (quinta de I pero también fundamental de V), y resuelve inmediatamente en V. Se dice que I6/4–V forma una unidad de prolongación dominante." },
  { q: "¿Cómo reconocer una prolongación en un análisis?", opts: ["Todos los acordes tienen la misma duración", "Varios acordes sucesivos comparten la misma función regional y sirven para adornar o desarrollar un acorde estructural", "Todos los acordes están en la misma octava", "El bajo no se mueve en absoluto"], a: 1, fb: "Una prolongación se reconoce por la coherencia funcional: varios acordes de superficie distintos que mantienen la misma región (T, SD o D). El acorde estructural es el pilar; los demás son sus adornos." },
  { q: "Un pedal de bajo en Sol prolonga:", opts: ["La región tónica únicamente", "La región dominante, manteniendo la fundamental de V bajo armonías cambiantes", "La región subdominante", "Ninguna región concreta"], a: 1, fb: "Un pedal en Sol (dominante) mantiene la tensión de V bajo armonías cambiantes. Los acordes que pasan por encima son adornos de superficie — la función estructural sigue siendo D durante todo el pedal." },
  { q: "¿Cuál es la diferencia entre un acorde de paso y un acorde estructural?", opts: ["El acorde de paso es más largo", "El acorde estructural es un pilar funcional; el acorde de paso es un adorno entre dos pilares", "El acorde estructural siempre está en estado fundamental", "No hay diferencia — todos los acordes son iguales"], a: 1, fb: "El acorde estructural (pilar) es un punto de anclaje funcional en el análisis por capas. El acorde de paso es un adorno de superficie que une dos pilares — no tiene peso estructural independiente." },
  { q: "En la secuencia I–IV–I6–V–I, ¿qué acordes prolongan la tónica al inicio?", opts: ["I y IV", "I, IV e I6", "Solo I", "I e I6"], a: 3, fb: "I e I6 prolongan la tónica (mismo acorde, inversión diferente). IV pertenece a SD — es un movimiento hacia la subdominante, no una prolongación tónica. Por tanto, solo I e I6 prolongan T aquí." },
  { q: "Una escala ascendente en el bajo (Do–Re–Mi–Fa) sobre un acorde de I prolonga:", opts: ["La dominante", "La tónica mediante movimiento de bajo ornamental", "La subdominante", "Ninguna región — la escala rompe la prolongación"], a: 1, fb: "Una línea de bajo conjunta ascendente (Do–Re–Mi–Fa) puede prolongar la tónica: el bajo adorna el acorde de I pasando por posiciones intermedias (I–I6–I6/4 o con armonías de paso). Es prolongación por bajo arpegiado o conjunto." },
  { q: "El concepto de prolongación es central en el análisis de:", opts: ["Schoenberg", "Schenker", "Rameau", "Riemann"], a: 1, fb: "Heinrich Schenker (1868–1935) es el teórico que desarrolló la prolongación como herramienta analítica fundamental. Según él, toda música tonal es una prolongación del Ursatz (estructura fundamental)." },
  { q: "Una prolongación de dominante típica antes de una cadencia final es:", opts: ["V–IV–V", "I6/4–V–V7", "V–VI–V", "I–V–I"], a: 1, fb: "I6/4–V–V7 es una prolongación clásica de la dominante antes de la cadencia: el 6/4 cadencial prepara V que se amplifica con V7. Toda esta secuencia prolonga la región D antes de la resolución en I." },
  { q: "¿Qué es la armonía de superficie?", opts: ["Los acordes tocados en la parte superior del piano", "El conjunto de todos los acordes tal como aparecen en la partitura", "Los acordes principales de la estructura profunda", "Los acordes sin inversiones"], a: 1, fb: "La armonía de superficie designa todos los acordes tal como aparecen en la partitura — cada acorde de paso, bordura, vecino. Es la 'superficie' visible de la armonía, antes de cualquier reducción analítica." },
  { q: "¿Qué es un acorde estructural (pilar armónico)?", opts: ["Un acorde tocado fortísimo", "Un acorde que ocupa una posición funcional clave en la estructura profunda de la pieza", "Un acorde sin inversiones", "El acorde más repetido en la pieza"], a: 1, fb: "Un acorde estructural (o pilar) es un acorde que lleva una función clave en la lógica tonal: ancla una región (T, SD, D) y forma parte de la estructura profunda que la reducción trata de revelar." },
  { q: "¿Cómo distinguir un acorde de superficie de un acorde estructural?", opts: ["Por su duración únicamente", "Por su posición funcional y su importancia para la lógica cadencial de la frase", "Por su posición en el compás (tiempo fuerte = estructural)", "Por el número de notas que contiene"], a: 1, fb: "La duración y la posición métrica son indicios pero no criterios absolutos. El acorde estructural es aquel cuya supresión cambiaría la lógica tonal fundamental — es indispensable para la progresión cadencial." },
  { q: "En la progresión I–IV–V–I, ¿el acorde IV es estructural o de superficie?", opts: ["Siempre de superficie", "Estructural — articula el movimiento SD antes de D", "De superficie — puede reemplazarse por II6 sin cambiar la estructura", "Ninguno de los dos — IV no tiene ningún papel armónico"], a: 1, fb: "IV es un acorde estructural de la región SD: articula el movimiento funcional T→SD→D→T. En este contexto, su presencia tiene significado estructural. Un IV de paso entre dos I sería de superficie." },
  { q: "En I–I6–I6/4–V–I, ¿cuál es el verdadero acorde estructural de dominante?", opts: ["I6/4 porque está en el tiempo fuerte", "V — I6/4 es una prolongación ornamental de V (6/4 cadencial)", "I6/4 y V juntos", "Ninguno — todos son de superficie"], a: 1, fb: "V es el acorde estructural de dominante. I6/4 (6/4 cadencial) es una prolongación ornamental que 'prepara' V — pertenece funcionalmente a la región dominante pero no es el pilar estructural." },
  { q: "Un acorde de bordura (nota de adorno armonizada) es:", opts: ["Un acorde estructural por definición", "Un acorde de superficie que adorna un acorde estructural sin cambiar su función", "Un acorde pivote entre dos tonalidades", "Un acorde de paso modulante"], a: 1, fb: "Un acorde de bordura es un acorde de superficie: adorna un acorde estructural alejándose y volviendo a él. No crea movimiento funcional independiente — prolonga el acorde estructural que lo rodea." },
  { q: "¿Cómo identificar los pilares estructurales de una frase de 4 compases?", opts: ["Tomar todos los acordes en tiempos fuertes", "Identificar el acorde de apertura, la cadencia medial y la cadencia final — los demás son prolongaciones", "Conservar solo los acordes de I y V", "Identificar los acordes más largos"], a: 1, fb: "La estrategia schenkeriana consiste en localizar los puntos de anclaje cadenciales: inicio (tónica), cadencia medial (a menudo semicadencia V), cadencia final (V–I). Estos tres polos forman el esqueleto estructural." },
  { q: "En una reducción, ¿qué se hace con los acordes de paso?", opts: ["Se transponen a la octava", "Se suprimen — no forman parte de la estructura profunda", "Se desplazan al tiempo fuerte", "Se reemplazan por acordes de séptima"], a: 1, fb: "En la reducción, los acordes de paso se eliminan porque no pertenecen a la estructura profunda. Solo se conservan los pilares estructurales (inicio, cadencias) y sus prolongaciones directas." },
  { q: "¿Cuál es la limitación del análisis puramente de superficie (acorde por acorde)?", opts: ["Es demasiado simple para músicos avanzados", "No revela la lógica tonal profunda y puede enmascarar la estructura direccional de la pieza", "No existe — el análisis de superficie es el único método válido", "Siempre produce errores de armonía"], a: 1, fb: "El análisis acorde por acorde permanece en la superficie: puede pasar por alto las prolongaciones y los grandes arcos funcionales. La estructura profunda (T→D→T a lo largo de toda una obra) es invisible si uno se detiene en la superficie." },
  { q: "¿Por qué la distinción superficie/estructura es pedagógicamente importante?", opts: ["Para simplificar el aprendizaje", "Para comprender que no todos los acordes tienen la misma importancia y desarrollar una lectura jerárquica", "Para evitar analizar ciertos acordes difíciles", "Para memorizar más fácilmente las progresiones"], a: 1, fb: "La distinción superficie/estructura desarrolla el pensamiento jerárquico: el estudiante comprende que la riqueza de la armonía de superficie sirve a una estructura más simple y profunda. Es una herramienta de comprensión, no de simplificación." },
  { q: "¿Qué es el Urlinie según Schenker?", opts: ["La línea de bajo fundamental", "La línea melódica fundamental descendente del soprano, de 3̂/5̂/8̂ hacia 1̂", "La línea del tenor en un coral", "La melodía principal de la obra"], a: 1, fb: "El Urlinie ('línea fundamental') es el descenso melódico fundamental del soprano, partiendo de 3̂, 5̂ o 8̂ y descendiendo diatónicamente hasta 1̂ (tónica). Es la estructura melódica profunda que toda melodía tonal realiza, según Schenker." },
  { q: "¿Cuáles son las tres formas posibles del Urlinie?", opts: ["1̂–2̂–3̂, 3̂–4̂–5̂, 5̂–6̂–7̂", "3̂–2̂–1̂, 5̂–4̂–3̂–2̂–1̂, 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "Do–Re–Mi, Sol–La–Si, Mi–Fa–Sol", "I–V–I, I–IV–I, I–II–I"], a: 1, fb: "Schenker reconoce tres Urlinien: 3̂–2̂–1̂ (descenso de tercera), 5̂–4̂–3̂–2̂–1̂ (descenso de quinta) y 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (descenso de octava). Toda gran melodía tonal realiza una de estas tres formas." },
  { q: "En el Urlinie 3̂–2̂–1̂ en Do mayor, ¿qué nota corresponde a 3̂?", opts: ["Do", "Re", "Mi", "Sol"], a: 2, fb: "En Do mayor, 3̂ es Mi (3er grado de la escala). El Urlinie 3̂–2̂–1̂ desciende Mi–Re–Do. Mi es el Kopfton (nota de cabeza) que inicia la línea fundamental." },
  { q: "En el Urlinie 5̂–4̂–3̂–2̂–1̂ en Sol mayor, ¿cuál es la nota de inicio?", opts: ["Sol", "Re", "Si", "La"], a: 1, fb: "En Sol mayor, 5̂ es Re (quinta de Sol). El Urlinie 5̂–4̂–3̂–2̂–1̂ desciende Re–Do–Si–La–Sol. Re es el Kopfton (nota de cabeza) que inicia el descenso fundamental." },
  { q: "¿Por qué el Urlinie siempre desciende hacia 1̂?", opts: ["Por convención arbitraria de Schenker", "Porque 1̂ (tónica) es el punto de resolución y reposo de toda tensión melódica tonal", "Porque las voces de soprano siempre descienden", "Para evitar las quintas paralelas"], a: 1, fb: "1̂ es la tónica — el punto de resolución final de toda tensión. En la lógica tonal, toda tensión melódica debe resolver en la tónica. El Urlinie materializa esta resolución obligatoria a escala de toda la obra." },
  { q: "¿Cómo localizar el Kopfton (nota de cabeza, inicio del Urlinie) en una melodía?", opts: ["Es la nota más aguda de la melodía", "Es la nota estructuralmente predominante al inicio, armonizada por I, desde la que comienza el descenso fundamental", "Es la primera nota de la melodía", "Es la nota más larga"], a: 1, fb: "El Kopfton es la nota de apertura estructural (3̂, 5̂ o 8̂) que pertenece al acorde de tónica inicial y desde la que comienza el descenso del Urlinie. No es necesariamente la primera nota ni la más alta." },
  { q: "En la melodía Mi–Fa–Mi–Re–Do (Do mayor), ¿cuál es el Urlinie probable?", opts: ["5̂–4̂–3̂–2̂–1̂", "3̂–2̂–1̂ con Mi como Kopfton", "8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "Sin Urlinie — la melodía es demasiado ornamental"], a: 1, fb: "Mi es 3̂ en Do mayor. La melodía Mi–Fa–Mi–Re–Do realiza el Urlinie 3̂–2̂–1̂ (Mi–Re–Do) con Fa como nota de bordura ornamental. El Kopfton es Mi, y el descenso estructural es 3̂(Mi)–2̂(Re)–1̂(Do)." },
  { q: "¿El Urlinie es siempre directamente audible en la melodía de superficie?", opts: ["Sí — siempre corresponde a la melodía exacta", "No — a menudo está adornado, desplazado a la octava o interrumpido por notas ajenas de superficie", "No — siempre pertenece al bajo", "Sí — pero solo en la música de Bach"], a: 1, fb: "El Urlinie es una abstracción de la melodía de superficie — está adornado, prolongado, interrumpido. La melodía real es una realización de superficie de esta estructura profunda. Hay que 'escuchar a través' de la superficie para extraerlo." },
  { q: "¿Qué significa '2̂ armonizado por V' en el Urlinie?", opts: ["El 2º grado es tocado por la voz de tenor", "La nota 2̂ coincide con el acorde de dominante en la estructura profunda", "El 2º grado se toca dos veces", "El acorde V está en segunda inversión"], a: 1, fb: "En el Urlinie, cada nota fundamental está armonizada por un acorde estructural: 2̂ coincide con V (dominante) y 1̂ con I (tónica). Es la conjunción del Urlinie y la Bassbrechung la que forma el Ursatz." },
  { q: "¿Por qué Schenker dice que toda gran melodía tonal realiza el Urlinie?", opts: ["Porque todas las melodías son idénticas", "Porque la lógica tonal exige la resolución de toda tensión hacia la tónica — el Urlinie es la expresión melódica universal de esta ley", "Porque analizó todas las melodías existentes", "Porque los compositores copian todos el mismo modelo"], a: 1, fb: "Para Schenker, la lógica tonal es universal: toda tensión debe resolver hacia 1̂. El Urlinie no es un esquema impuesto desde fuera sino la consecuencia inevitable de la tonalidad misma." },
  { q: "¿Qué es la Bassbrechung?", opts: ["La línea melódica descendente del soprano", "El arco de bajo I–V–I que estructura la tonalidad a escala de toda la obra", "Una técnica de bajo continuo barroca", "El cifrado de bajo en un coral"], a: 1, fb: "La Bassbrechung ('arpegio de bajo') es el arco fundamental I–V–I en el bajo, que describe el movimiento de quinta fundamental de la armonía tonal: desde la tónica hacia la dominante, y vuelta a la tónica." },
  { q: "¿Cuál es el bajo fundamental de la Bassbrechung en Do mayor?", opts: ["Do–Fa–Do", "Do–Sol–Do", "Do–Re–Do", "Do–La–Do"], a: 1, fb: "La Bassbrechung en Do mayor es Do–Sol–Do (I–V–I). Sol es la dominante — la quinta de la escala. El arco Do→Sol→Do representa el movimiento de quinta fundamental de la tonalidad." },
  { q: "¿La Bassbrechung abarca una frase, una sección o una obra entera?", opts: ["Solo una frase de 4 compases", "Puede extenderse a cualquier escala — desde la frase hasta la obra entera", "Solo formas cortas (canción)", "Solo se aplica a los corales de Bach"], a: 1, fb: "La Bassbrechung es escalable: puede estructurar una frase (cc. 1–4), una sección (cc. 1–16), un movimiento entero o una sinfonía completa. Este carácter fractal hace que el análisis schenkeriano sea universal." },
  { q: "¿Cómo se relaciona la Bassbrechung con el Urlinie en el Ursatz?", opts: ["Son independientes", "La Bassbrechung (bajo I–V–I) sostiene el Urlinie (soprano 3̂–2̂–1̂) — juntos forman el Ursatz", "El Urlinie es la versión melódica de la Bassbrechung", "La Bassbrechung reemplaza al Urlinie en modo menor"], a: 1, fb: "En el Ursatz, el Urlinie (soprano) y la Bassbrechung (bajo) se superponen: 3̂ sobre I, 2̂ sobre V, 1̂ sobre I. Este contrapunto a dos voces es la estructura fundamental universal de la música tonal según Schenker." },
  { q: "¿Qué representa el V intermedio en la Bassbrechung I–V–I?", opts: ["Una tonicización momentánea", "El punto de tensión máxima — la dominante que estructura la progresión hacia la resolución final en I", "Un acorde de paso sin importancia", "La subdominante en inversión"], a: 1, fb: "V en I–V–I es la cumbre de tensión de la Bassbrechung — representa el movimiento de quinta descendente fundamental de la tonalidad (quinta I→V o cuarta ascendente). Su resolución en I concluye el arco tonal." },
  { q: "En una fuga de Bach de 100 compases, ¿dónde se sitúa generalmente el V de la Bassbrechung?", opts: ["Solo en el compás 2", "En el punto estructural central de la obra, a menudo en la mayor cadencia intermedia", "Al final de cada frase", "No hay Bassbrechung en las fugas"], a: 1, fb: "En una forma grande, el V estructural de la Bassbrechung coincide con el punto de tensión máxima de la obra — a menudo la gran cadencia en V a mitad de camino. Todo lo anterior prolonga I (viaje de ida); todo lo posterior prolonga el regreso a I." },
  { q: "La Bassbrechung es análoga a qué principio formal en la forma sonata?", opts: ["La exposición y la recapitulación", "La presentación → tensión (desarrollo) → resolución (recapitulación), es decir I→V→I a gran escala", "El tema principal únicamente", "La coda final"], a: 1, fb: "La forma sonata realiza la Bassbrechung a gran escala: exposición en I (a menudo con 2º tema en V), desarrollo (tensión armónica), recapitulación en I. Esta estructura tonal I–V–I es la Bassbrechung de la obra entera." },
  { q: "En modo menor, ¿la Bassbrechung es Im–Vm–Im o Im–V–Im?", opts: ["Im–Vm–Im (menor en la dominante)", "Im–V–Im (dominante mayor, con sensible elevada)", "Im–bVII–Im", "Im–IV–Im"], a: 1, fb: "En modo menor, la dominante es siempre V mayor (con sensible elevada). La Bassbrechung es pues Im–V–Im: se usa el menor armónico en la dominante para conservar la tensión máxima de la sensible hacia la tónica." },
  { q: "¿Qué intervalo de bajo caracteriza el movimiento I→V en la Bassbrechung?", opts: ["Tercera ascendente", "Quinta descendente (o cuarta ascendente) — el movimiento fundamental de la armonía tonal", "Segunda ascendente", "Sexta descendente"], a: 1, fb: "I→V corresponde a una quinta descendente (Do→Sol en Do mayor) o cuarta ascendente. Es el movimiento más poderoso de la armonía tonal — crea la tensión máxima que exige la resolución V→I." },
  { q: "Schenker considera la Bassbrechung como:", opts: ["Un esquema opcional para analizar el bajo", "El movimiento de bajo universal de toda música tonal — el arco fundamental del contrapunto a dos voces", "Una regla aplicable solo a Bach", "Una simplificación pedagógica sin valor analítico"], a: 1, fb: "Para Schenker, la Bassbrechung es una ley universal: toda música tonal realiza el movimiento I–V–I en el bajo, a cualquier escala. Es la base armónica del Ursatz." },
  { q: "¿Qué es el Ursatz según Schenker?", opts: ["La estructura rítmica fundamental", "La estructura contrapuntística fundamental = Urlinie (soprano) + Bassbrechung (bajo)", "La escala fundamental de toda tonalidad", "El motivo temático principal de una obra"], a: 1, fb: "El Ursatz ('estructura fundamental') es la superposición del Urlinie (descenso del soprano 3̂–2̂–1̂) y la Bassbrechung (arco de bajo I–V–I). Es un contrapunto a dos voces que subyace a toda la música tonal." },
  { q: "¿De cuántas capas se compone el Ursatz?", opts: ["Una sola — la melodía principal", "Dos — soprano (Urlinie) y bajo (Bassbrechung)", "Tres — soprano, contralto, bajo", "Cuatro — las cuatro voces SATB"], a: 1, fb: "El Ursatz es un contrapunto a dos voces: el Urlinie en el soprano y la Bassbrechung en el bajo. Estas dos voces fundamentales son suficientes para definir la estructura tonal profunda de cualquier obra." },
  { q: "En el Ursatz, ¿cómo se alinean el Urlinie y la Bassbrechung?", opts: ["Son independientes y nunca se cruzan", "3̂ coincide con I (bajo), 2̂ con V (bajo), 1̂ con I (bajo)", "5̂ coincide con V (bajo), 3̂ con IV, 1̂ con I", "Se alternan sin sincronizarse jamás"], a: 1, fb: "La alineación canónica del Ursatz: Kopfton (3̂/5̂/8̂) sobre I, luego el movimiento intermedio (2̂ sobre V), luego la resolución (1̂ sobre I). Esta superposición crea el contrapunto fundamental de la música tonal." },
  { q: "¿Por qué Schenker dice que toda música tonal es una 'prolongación del Ursatz'?", opts: ["Porque todos los compositores copian el mismo esquema", "Porque toda composición tonal es una elaboración de esta estructura fundamental simple — los adornos de superficie desarrollan el Ursatz", "Porque el Ursatz es impuesto por el conservatorio", "Porque el Ursatz es la única estructura audible"], a: 1, fb: "El Ursatz es la estructura más profunda y simple — toda composición tonal la elabora a través de capas sucesivas de prolongación. Los adornos de superficie son realizaciones cada vez más complejas de este arco fundamental." },
  { q: "¿El Ursatz se aplica a la música atonal del siglo XX?", opts: ["Sí — Schenker lo aplica a toda música", "No — el Ursatz presupone la tonalidad; la música atonal no sigue sus principios", "Sí pero con modificaciones", "No — solo se aplica a Bach"], a: 1, fb: "El Ursatz presupone la tonalidad: Urlinie descendiendo hacia 1̂ y Bassbrechung I–V–I. La música atonal, que rechaza la jerarquía de los grados, no puede analizarse en este marco. Es un límite explícito del sistema schenkeriano." },
  { q: "¿Cuál es la versión completa del Ursatz con el Urlinie 5̂–4̂–3̂–2̂–1̂?", opts: ["5̂ sobre I, 4̂ sobre IV, 3̂ sobre I, 2̂ sobre V, 1̂ sobre I", "5̂ sobre I, descenso 4̂–3̂ prolongado, 2̂ sobre V, 1̂ sobre I", "5̂ sobre V, 4̂ sobre IV, 3̂ sobre III, 2̂ sobre II, 1̂ sobre I", "5̂ sobre I, 4̂–3̂–2̂ ornamentales, 1̂ sobre V"], a: 1, fb: "En el Urlinie de quinta, los grados 4̂ y 3̂ a menudo se prolongan con movimientos armónicos intermedios, pero los puntos de anclaje estructurales son 5̂ sobre I, 2̂ sobre V y 1̂ sobre I — formando el Ursatz completo." },
  { q: "¿El Ursatz tiene un solo modelo o varias variantes?", opts: ["Un único modelo para toda la música", "Tres variantes según el Kopfton (3̂, 5̂ o 8̂)", "Un número infinito de variantes según el compositor", "Dos variantes (mayor y menor)"], a: 1, fb: "Schenker reconoce tres formas de Ursatz según el Kopfton: 3̂–2̂–1̂ (más simple), 5̂–4̂–3̂–2̂–1̂ (muy frecuente), 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (más rara). La Bassbrechung sigue siendo I–V–I en los tres casos." },
  { q: "¿Cómo se manifiesta el Ursatz a gran escala en una sinfonía?", opts: ["Solo en el 1er movimiento", "La tonalidad principal en I se prolonga hasta el V estructural (a menudo en el desarrollo), luego vuelve a I al final", "Solo es visible a nivel de las frases", "Se manifiesta solo en el bajo continuo"], a: 1, fb: "En una sinfonía, el Ursatz se extiende sobre toda la obra: el inicio se ancla en I, el punto de tensión máxima (a menudo desarrollo o cadencia central) realiza V, y la conclusión vuelve a I. La Bassbrechung I–V–I estructura la obra entera." },
  { q: "¿Qué son el 'Vordergrund', 'Mittelgrund' y 'Hintergrund' en el análisis schenkeriano?", opts: ["Tres instrumentos diferentes", "Las tres capas de análisis: superficie (Vordergrund), capa intermedia (Mittelgrund), estructura profunda (Hintergrund = Ursatz)", "Tres partes de una fuga", "Tres tipos de cadencias"], a: 1, fb: "Schenker usa estos tres niveles: Vordergrund (primer plano = música de superficie tal como está escrita), Mittelgrund (plano intermedio = prolongaciones agrupadas), Hintergrund (fondo = solo el Ursatz). La reducción avanza del Vordergrund hacia el Hintergrund." },
  { q: "¿Cuál es la aportación principal de la teoría del Ursatz al análisis musical?", opts: ["Permite memorizar las partituras más fácilmente", "Revela la estructura tonal profunda común a todas las grandes obras y explica su coherencia a gran escala", "Simplifica la notación musical", "Reemplaza el análisis armónico tradicional acorde por acorde"], a: 1, fb: "El Ursatz permite comprender la coherencia tonal a gran escala: por qué una obra de 300 compases 'se mantiene unida'. Revela que la complejidad de superficie enmascara una estructura fundamental simple y universal." },
  { q: "¿Cuántos pasos tiene una reducción schenkeriana completa?", opts: ["1 paso — pasar directamente al Ursatz", "Al menos 3 capas: superficie (Vordergrund) → intermedia (Mittelgrund) → profunda (Hintergrund)", "5 pasos fijos idénticos para cada análisis", "2 pasos — acordes pares y acordes impares"], a: 1, fb: "La reducción schenkeriana procede en capas sucesivas: Vordergrund (superficie) → Mittelgrund(s) (capas intermedias, a veces varias) → Hintergrund (Ursatz). El número de capas intermedias depende de la complejidad de la obra." },
  { q: "¿Qué se hace primero en una reducción por capas?", opts: ["Identificar el Urlinie inmediatamente", "Escribir todos los acordes de la partitura (armonía de superficie)", "Reducir al Ursatz", "Analizar las modulaciones"], a: 1, fb: "El primer paso es escribir la armonía de superficie completa — todos los acordes tal como aparecen. Es el Vordergrund: el punto de partida antes de cualquier reducción. No se saltan pasos." },
  { q: "¿Qué es una reducción de capa intermedia (Mittelgrund)?", opts: ["Un análisis que conserva todos los acordes de superficie", "Un análisis que agrupa los acordes de superficie por funciones y elimina los adornos, revelando las prolongaciones principales", "Un análisis solo melódico", "Una reducción que conserva únicamente I y V"], a: 1, fb: "El Mittelgrund es una capa intermedia donde se eliminan los acordes de paso y de bordura, agrupando los acordes de superficie por función. Se obtiene una visión de las prolongaciones principales sin llegar al Ursatz completo." },
  { q: "¿Cómo se decide que un acorde es 'eliminable' en la reducción?", opts: ["Eliminando los acordes menores", "Eliminando los acordes que no tienen papel funcional propio — acordes de paso, borduras, adornos", "Eliminando todos los acordes en tiempos débiles", "Eliminando las inversiones"], a: 1, fb: "Un acorde es eliminable si no tiene papel funcional independiente: acorde de paso entre dos pilares, acorde de bordura, acorde ornamental. Su supresión no cambia la lógica tonal fundamental." },
  { q: "En la reducción de I–IV–I6–V7–I, ¿cuál sería la versión reducida a la capa intermedia?", opts: ["I–I6–V7–I", "I–IV–V–I", "I–V–I", "I–V7–I"], a: 3, fb: "I–IV–V7–I es una reducción intermedia razonable: se conservan I, IV (SD), V7 (D) e I. I6 se elimina porque es una prolongación de I (mismo acorde en inversión). La reducción profunda sería I–V–I (Bassbrechung)." },
  { q: "La reducción por capas revela qué tipo de estructura?", opts: ["La estructura rítmica únicamente", "La estructura jerárquica: de la complejidad de superficie a la simplicidad fundamental", "La estructura contrapuntística de cada voz", "La estructura modal de la obra"], a: 1, fb: "La reducción por capas revela la jerarquía armónica: en cada capa la estructura se vuelve más simple y más fundamental. La complejidad de superficie (Vordergrund) se resuelve en prolongaciones (Mittelgrund) y luego en el Ursatz (Hintergrund)." },
  { q: "¿Qué revela la diferencia entre el Vordergrund y el Hintergrund?", opts: ["Los errores armónicos del compositor", "La riqueza de los adornos y prolongaciones que desarrollan la estructura fundamental — es el 'contenido' de la obra", "Los pasajes copiados de otros compositores", "Las dificultades técnicas de la pieza"], a: 1, fb: "La diferencia entre superficie y estructura profunda muestra cómo el compositor 'viste' el Ursatz: las prolongaciones, adornos y desarrollos que dan a cada obra su personalidad única descansando sobre la misma estructura fundamental." },
  { q: "¿Se puede reducir una pieza por capas sin conocer la tonalidad?", opts: ["Sí — la reducción es independiente de la tonalidad", "No — la tonalidad es el marco indispensable para identificar las funciones y los pilares", "Sí, si solo se conserva el bajo", "Sí, pero solo para el Vordergrund"], a: 1, fb: "La reducción schenkeriana presupone la tonalidad: identificar T, SD, D y sus prolongaciones exige conocer la tonalidad. Sin este marco, no se puede distinguir acorde estructural de acorde ornamental." },
  { q: "¿Cómo se aplica la noción de capas a una frase de 8 compases?", opts: ["Cada compás es una capa distinta", "Superficie: todos los acordes de los 8 compases. Intermedia: I–IV–V–I (pilares). Profunda: I–V–I (Ursatz)", "La frase de 8 compases no tiene estructura por capas", "Las capas solo se aplican a movimientos enteros"], a: 1, fb: "Incluso una frase corta de 8 compases puede analizarse en capas: superficie (todos los acordes), intermedia (pilares funcionales T–SD–D–T), profunda (Ursatz I–V–I). Es el principio fractal del análisis schenkeriano." },
  { q: "¿Cuál es la utilidad práctica de la reducción por capas para un compositor?", opts: ["Ninguna — es solo para el análisis teórico", "Comprender la estructura profunda para escribir obras largas coherentes y planificar la trayectoria armónica a gran escala", "Simplificar la escritura usando solo I y V", "Evitar los acordes complejos"], a: 1, fb: "La reducción por capas ayuda al compositor a planificar la gran forma: ¿cuál es la Bassbrechung de la obra? ¿Cuándo llega el V estructural? ¿Cómo las prolongaciones intermedias desarrollan el Ursatz? Es una herramienta de composición tanto como de análisis." },
  { q: "En el Preludio en Do mayor BWV 846 de Bach (arpeggios), la estructura armónica de superficie es:", opts: ["Solo I durante toda la pieza", "Una sucesión de acordes arpeggiados cambiantes sobre un plan armónico funcional T→SD→D→T", "Una improvisación sin estructura", "Una serie de modulaciones a tonos vecinos"], a: 1, fb: "El Preludio BWV 846 realiza una progresión armónica funcional completa a través de arpeggios: la estructura de superficie es rica pero la estructura profunda es una simple progresión T→SD→D→T que realiza el Ursatz." },
  { q: "En un coral de Bach, las cadencias internas sirven principalmente para:", opts: ["Cambiar de tonalidad definitivamente", "Articular la estructura en frases y secciones, creando pilares armónicos intermedios en la reducción", "Evitar las quintas paralelas", "Introducir nuevas voces"], a: 1, fb: "Las cadencias internas (semicadencias, cadencias imperfectas) de un coral de Bach articulan la estructura: crean puntos de anclaje intermedios en la reducción, revelando la jerarquía de las cadencias (intermedias vs. final)." },
  { q: "En la Sonata K.331 de Mozart (tema con variaciones), la estructura armónica del tema es:", opts: ["Compleja y modulante desde la 1ª frase", "Simple — I prolongada (cc. 1–4), luego V (cc. 5–8), resolución en I (cc. 9–16): Bassbrechung clara", "Solo sobre IV y V alternados", "Sin estructura funcional clara"], a: 1, fb: "El tema de K.331 realiza la Bassbrechung en 16 compases: presentación en I (cc. 1–8), tensión en V (cc. 9–14), resolución I (cc. 15–16). La estructura es un modelo de economía tonal." },
  { q: "En una fuga de Bach en Do mayor, cuando el sujeto entra en Sol mayor (V), esto representa:", opts: ["Una modulación definitiva en Sol mayor", "La respuesta tonal — una tonicización de V que se inscribe en la Bassbrechung I→V", "Un error de escritura contrapuntística", "La exposición del contrasujeto"], a: 1, fb: "La respuesta en V en una fuga realiza el primer movimiento de la Bassbrechung: I→V. La fuga 'modula' a V pero es una tonicización que se inscribe en el arco fundamental I–V–I de toda la fuga." },
  { q: "En el 1er movimiento de la Sinfonía nº 40 KV550 de Mozart, el 2º tema en Si b mayor representa:", opts: ["Una modulación definitiva e independiente", "La tonicización del III (relativo mayor del menor) — movimiento armónico de la exposición hacia la 'dominante' estructural", "Un error de tonalidad de Mozart", "El inicio de la recapitulación"], a: 1, fb: "En Sol menor, el 2º tema en Sib (bIII = relativo mayor) representa el movimiento estructural de la exposición hacia la zona de dominante. En la Bassbrechung en menor, bIII suele hacer el papel de dominante estructural de la exposición." },
  { q: "En un minueto de Haydn de 16 compases, la cadencia en V en el compás 8 representa:", opts: ["El final de la obra", "El V estructural de la Bassbrechung — punto de tensión mediano antes del regreso a I al final", "Una modulación definitiva en Sol", "Un accidente armónico no planificado"], a: 1, fb: "La cadencia en V a mitad de camino es típica de la forma período: el V del compás 8 es el V estructural de la Bassbrechung. Todo lo que sigue (cc. 9–16) prolonga el regreso al I final — es la segunda mitad del arco I–V–I." },
  { q: "En la Chacona BWV 1004 de Bach (bajo obstinado), la Bassbrechung se extiende sobre:", opts: ["Cada repetición del bajo únicamente", "La obra entera — las 64 variaciones prolongan un Ursatz único de principio a fin", "Solo las 4 primeras variaciones", "El bajo obstinado no tiene Bassbrechung"], a: 1, fb: "La Chacona de Bach realiza un Ursatz a escala de la obra entera: las 64 variaciones son una prolongación monumental de I–V–I. El bajo obstinado es en sí mismo una prolongación de la Bassbrechung fundamental." },
  { q: "¿Cómo analizar un coral de Bach de 4 compases con el método de reducción?", opts: ["Conservar todos los acordes y numerarlos", "1) anotar todos los acordes, 2) localizar apertura (T), cadencia medial (V o II6–V), cadencia final (V–I), 3) reducir a la Bassbrechung I–V–I", "Simplificar a I–IV–V–I únicamente", "Identificar solo las inversiones"], a: 1, fb: "El método en 3 pasos: 1) superficie completa, 2) pilares funcionales (apertura T, cadencias intermedias y final), 3) Bassbrechung I–V–I. Este enfoque evita el análisis puramente acorde por acorde y revela la estructura profunda." },
  { q: "En Mozart K.545 (Sonata en Do mayor, inicio), los 4 primeros compases prolongan:", opts: ["Solo V", "I (tónica) a través de armonías de superficie variadas (I–V6–I–IV6–I6/4–V–I)", "Solo IV", "La subdominante"], a: 1, fb: "Los cc. 1–4 de K.545 prolongan I (tónica): las armonías de superficie (V6, IV6, I6/4–V–I) adornan y cadencian la tónica. La estructura profunda de estos 4 compases es I prolongada — un Kopfton suspendido antes del movimiento real hacia V." },
  { q: "¿Por qué Bach y Mozart son los autores de referencia para el análisis schenkeriano?", opts: ["Porque usaban exactamente las mismas fórmulas", "Porque su escritura tonal es ejemplar: estructura profunda simple, prolongaciones elaboradas, lógica armónica irreprochable", "Porque Schenker los conocía personalmente", "Porque su música es la más difícil de analizar"], a: 1, fb: "Bach y Mozart son modelos porque su escritura tonal realiza perfectamente el Ursatz: detrás de una superficie de gran riqueza, la estructura profunda tiene una claridad y una lógica ejemplares. Ilustran idealmente los principios schenkerianos." },
  { q: "En la progresión Do–Sol–La–Fa–Sol–Do (bajo, Do mayor), ¿cuál es el acorde estructural de dominante?", opts: ["La (VI)", "Fa (IV)", "Sol (V) — las dos ocurrencias", "Do (I)"], a: 2, fb: "Sol (V) es el acorde estructural de dominante. Las dos ocurrencias de Sol pueden prolongar V antes de la resolución final en I. Do = T, La = T prolongada (VI), Fa = SD, Sol = D, Do = T: progresión T–T–SD–D–T." },
  { q: "Analizas 8 compases. La estructura es I–IV–I6–V6–I–II6–V7–I. ¿Cuáles son los pilares estructurales?", opts: ["Los 8 acordes son pilares", "I (inicio), V (cadencia medial o dominante), I (conclusión) — los demás son prolongaciones", "I, IV, V7, I únicamente", "I6, V6, II6, I"], a: 1, fb: "Los pilares estructurales son I (apertura), V/V7 (dominante) e I (conclusión). IV, I6, V6 y II6 son prolongaciones o adornos funcionales. La Bassbrechung subyacente es I–V–I." },
  { q: "Se te da la melodía Mi–Re–Do en 3 compases (Do mayor, armonizada por I–V–I). Es un ejemplo de:", opts: ["Solo Bassbrechung", "Urlinie 3̂–2̂–1̂ armonizado por el Ursatz I–V–I — un ejemplo perfecto de estructura fundamental", "Prolongación de V", "Cadencia imperfecta"], a: 1, fb: "Mi–Re–Do (3̂–2̂–1̂) sobre I–V–I es el ejemplo más puro del Ursatz: el Urlinie de tercera desciende de 3̂ a 1̂ sustentado por la Bassbrechung I–V–I. Es el modelo básico que Schenker ilustra en Der freie Satz." },
  { q: "¿Cómo determinar si una modulación es estructural u ornamental en una pieza?", opts: ["Todas las modulaciones son estructurales", "Si la nueva tonalidad se confirma por una cadencia V–I y se mantiene durante una sección significativa, es estructural; en caso contrario es una tonicización ornamental", "Una modulación siempre es ornamental", "Si la modulación dura más de 2 compases, es estructural"], a: 1, fb: "La distinción clave: tonicización (momentánea, unos acordes) vs. modulación estructural (confirmada por V–I, mantenida en una sección). En el análisis por capas, las tonicizaciones desaparecen en el Mittelgrund; solo las modulaciones estructurales persisten." },
  { q: "En un análisis práctico, ¿por dónde empezar?", opts: ["Por el último compás", "Identificando la tonalidad, luego localizando la cadencia final (V–I), luego remontando hacia el inicio", "Por las notas más agudas", "Analizando cada acorde de izquierda a derecha sin orden particular"], a: 1, fb: "Comenzar por la tonalidad y la cadencia final es la estrategia schenkeriana: la cadencia final (V–I) es el V y el I de la Bassbrechung. Luego se remonta para descubrir cómo la estructura profunda se despliega desde la apertura." },
  { q: "¿Cuál de estos análisis de I–VI–II–V–I es correcto?", opts: ["I=D, VI=T, II=SD, V=D, I=T", "I=T, VI=T (prolongación), II=SD, V=D, I=T", "I=T, VI=SD, II=D, V=T, I=D", "I=SD, VI=D, II=T, V=SD, I=T"], a: 1, fb: "I=T, VI=T (VI pertenece a la región tónica), II=SD, V=D, I=T. La progresión realiza T(prolongada por VI)–SD–D–T. El análisis correcto identifica VI como perteneciente a la región tónica, no a otra función." },
  { q: "Debes reducir I–I6–IV–II6–I6/4–V7–I a la capa intermedia. ¿Cuál es el resultado?", opts: ["I–IV–II6–V7–I", "I–IV–V7–I (o I–II6–V7–I)", "I–I6/4–V7–I", "Solo I–V–I"], a: 1, fb: "En la capa intermedia, I6 (prolongación de I) se elimina, IV o II6 (SD) se conservan, I6/4 (prolongación de V) a veces se elimina. El resultado típico es I–IV–V7–I o I–II6–V7–I — la estructura funcional T–SD–D–T sin adornos." },
  { q: "¿Cuál es el mejor análisis de superficie para Do–Sol–Mi–Do (bajo ascendente, Do mayor)?", opts: ["I–V–I6–I (arpegio de I)", "I–V–III–I (4 acordes diferentes)", "I prolongado por arpegio (I–I6–I6/4–I) — una sola función tónica", "II–V–I–I"], a: 2, fb: "Do–Sol–Mi–Do en el bajo arpegía el acorde de Do mayor: Do = estado fundamental, Sol = I6/4 (quinta en el bajo), Mi = I6 (tercera en el bajo), Do = estado fundamental. Es una prolongación tónica por arpegio — una sola función T." },
  { q: "¿Por qué la cadencia V–I es el pilar final de todo Ursatz?", opts: ["Por convención arbitraria", "Porque V–I realiza la resolución de la tensión máxima (dominante) hacia el reposo (tónica) — la conclusión obligatoria de toda lógica tonal", "Porque V–I es la cadencia más larga", "Porque I suena más fuerte que V"], a: 1, fb: "V–I es la resolución fundamental de la lógica tonal: la dominante crea tensión máxima (tritono en V7, sensible hacia tónica) que solo la tónica puede resolver. Es la conclusión inevitable de la Bassbrechung y del Urlinie." },
];

const questionsDe: Question[] = [
  { q: "Welche Stufen gehören zum Tonika-Bereich (T) in C-Dur?", opts: ["I, II, IV", "I, III, VI", "V, VII, II", "IV, VI, III"], a: 1, fb: "Der Tonika-Bereich umfasst die Akkorde, die die Stabilität der Tonika evozieren: I, III und VI. Diese Akkorde teilen zwei Noten mit I (C–E–G) und verstärken die Ruhewirkung." },
  { q: "Welche Stufen gehören zum Subdominant-Bereich (SD) in C-Dur?", opts: ["I, III, VI", "V, VII", "II, IV", "I, IV, V"], a: 2, fb: "Der Subdominant-Bereich umfasst II und IV. Diese Akkorde bereiten die Dominante harmonisch vor — sie erzeugen eine Zwischenspannung zwischen Ruhe (T) und maximaler Spannung (D)." },
  { q: "Welche Stufen gehören zum Dominant-Bereich (D) in C-Dur?", opts: ["I, III, VI", "II, IV", "V, VII", "III, V"], a: 2, fb: "Der Dominant-Bereich umfasst V und VII. Diese Akkorde tragen die maximale Spannung und verlangen Auflösung zur Tonika. V7 ist der Dominantakkord par excellence; VII ist seine unvollständige Form." },
  { q: "In der Progression I–VI–II–V–I, zu welchem Bereich gehört VI?", opts: ["Dominantbereich", "Subdominantbereich", "Tonikabereich", "Keinem Bereich"], a: 2, fb: "VI (A-Moll in C-Dur) gehört zum Tonikabereich, da er zwei Noten mit I teilt (C und E). In dieser Progression prolongiert VI die Tonika, bevor die Bewegung zu SD (II) und D (V) einsetzt." },
  { q: "Die Progression T–SD–D–T beschreibt:", opts: ["Die Regel der Quintparallelen", "Die grundlegende Funktionsfolge der Tonalharmonik", "Die Struktur des Urlinien", "Das Prinzip der Bassbrechung"], a: 1, fb: "T–SD–D–T ist das grundlegende Funktionsschema der tonalen Musik: stabiler Ausgangspunkt (T), Vorbereitung (SD), maximale Spannung (D), Rückkehr zur Ruhe (T). Jede tonale Progression lässt sich als Variante dieses Modells lesen." },
  { q: "Der II6-Akkord (2. Stufe in der ersten Umkehrung) gehört zu welchem Funktionsbereich?", opts: ["Tonikabereich", "Dominantbereich", "Subdominantbereich", "Keinem — Umkehrungen ändern den Bereich"], a: 2, fb: "Die Umkehrung ändert den Funktionsbereich nicht. II (D–F–A) gehört zum Subdominantbereich, ob in der Grundstellung oder erster Umkehrung. II6 ist sogar die bevorzugte Form von II im klassischen Stil vor V." },
  { q: "Warum ist IV–V–IV eine bedenkliche Progression?", opts: ["Weil IV und V nicht aufeinanderfolgen können", "Weil dieser Rückschritt D→SD die Richtungslogik SD→D→T bricht", "Weil IV nicht zur Tonleiter gehört", "Weil V gefolgt von IV systematisch Quintparallelen erzeugt"], a: 1, fb: "IV–V–IV stellt einen funktionalen 'Rückschritt' dar: man verlässt die Subdominante für die Dominante und kehrt dann zur Subdominante zurück. Dieses Zögern bricht die Logik T→SD→D→T und schwächt die Progression." },
  { q: "In G-Dur gehört der E-Moll-Akkord (VIm) zu:", opts: ["Dominantbereich", "Subdominantbereich", "Tonikabereich", "Keinem dieser Bereiche"], a: 2, fb: "In G-Dur ist VI E-Moll. Er gehört zum Tonikabereich, da er zwei Noten mit I teilt (G und H von G–H–D). E–G–H teilt G und H mit G-Dur — er hat die Ruhefarbe der Tonika." },
  { q: "Was ist eine Tonika-Prolongation?", opts: ["Ein tonartfremder Akkord", "Eine Akkordfolge, die die funktionale Farbe von T beibehält, ohne den Bereich zu wechseln", "Der Pflichtdurchgang durch V vor I", "Die wörtliche Wiederholung von I in der Oktave"], a: 1, fb: "Eine Tonika-Prolongation ist ein Akkordgefüge (z.B. I–VI–I6–I), das im T-Bereich verbleibt. Es schmückt und verlängert die Ruhefarbe der Tonika ohne wirkliche funktionale Bewegung zu SD oder D." },
  { q: "In einem klassischen 8-taktigen Satz sind die Takte 1–4 oft:", opts: ["D–T–D–T", "Verlängerte T, dann Bewegung zu D", "Nur SD", "Schneller Wechsel T/D/T/D"], a: 1, fb: "Der klassische Satz beginnt mit einer Präsentation (T.1–4), die die Tonika prolongiert, dann einer Fortsetzung (T.5–8), die SD–D–T bis zur Schlusskadenz entwickelt. Dies ist die Urstruktur bei Haydn und Mozart." },
  { q: "Was ist harmonische Prolongation?", opts: ["Ein sehr laut gespielter Akkord", "Die Beibehaltung einer harmonischen Funktion über mehrere Takte durch wechselnde Oberflächenharmonien", "Die Verlängerung aller Notendauern", "Ein gehaltener Akkord ohne Änderung über mehrere Takte"], a: 1, fb: "Harmonische Prolongation ist das Prinzip, durch das eine Funktion (T, SD oder D) über mehrere Takte beibehalten wird, auch wenn die Oberflächenakkorde wechseln. Bsp.: I–I6–I6/4 prolongieren alle die Tonikafunktion." },
  { q: "Die Progression I–VI–I6–I ist ein Beispiel für:", opts: ["Bewegung T→SD→D→T", "Prolongation des Tonikabereichs", "Authentische Kadenz", "Bassbrechung"], a: 1, fb: "I–VI–I6–I prolongiert den Tonikabereich: VI gehört zu T (teilt zwei Noten mit I), I6 ist I in der Umkehrung. Alle diese Akkorde bewahren die funktionale Ruhefarbe der Tonika." },
  { q: "In einer Dominant-Prolongation, welcher Akkord kann V 'schmücken', ohne ihn funktional zu verlassen?", opts: ["IV", "I6/4 (vor V, der Kadenzsextakkord)", "II", "VI"], a: 1, fb: "Der Kadenz-Quartsextakkord (I6/4) auf einem schweren Taktteil prolongiert den Dominantbereich: sein Bass ist G (Quinte von I, aber auch Grundton von V), und er löst unmittelbar nach V auf. I6/4–V bildet eine Einheit der Dominantprolongation." },
  { q: "Woran erkennt man eine Prolongation in einer Analyse?", opts: ["Alle Akkorde haben dieselbe Dauer", "Mehrere aufeinanderfolgende Akkorde teilen dieselbe Bereichsfunktion und dienen dazu, einen Strukturakkord zu schmücken oder zu entwickeln", "Alle Akkorde befinden sich in derselben Oktave", "Der Bass bewegt sich überhaupt nicht"], a: 1, fb: "Eine Prolongation erkennt man an der funktionalen Kohärenz: mehrere verschiedene Oberflächenakkorde, die denselben Bereich (T, SD oder D) aufrechterhalten. Der Strukturakkord ist der Pfeiler; die anderen sind seine Ornamente." },
  { q: "Ein Orgelpunkt auf G im Bass prolongiert:", opts: ["Nur den Tonikabereich", "Den Dominantbereich, indem er den Grundton von V unter wechselnden Harmonien hält", "Den Subdominantbereich", "Keinen bestimmten Bereich"], a: 1, fb: "Ein Orgelpunkt auf G (Dominante) erhält die Spannung von V unter wechselnden Harmonien aufrecht. Die darüber liegenden Akkorde sind Oberflächenornamente — die strukturelle Funktion bleibt D während des gesamten Orgelpunkts." },
  { q: "Was ist der Unterschied zwischen einem Durchgangsakkord und einem Strukturakkord?", opts: ["Der Durchgangsakkord ist länger", "Der Strukturakkord ist ein funktionaler Pfeiler; der Durchgangsakkord ist ein Ornament zwischen zwei Pfeilern", "Der Strukturakkord steht immer in der Grundstellung", "Es gibt keinen Unterschied — alle Akkorde sind gleich"], a: 1, fb: "Der Strukturakkord (Pfeiler) ist ein funktionaler Ankerpunkt in der Schichtenanalyse. Der Durchgangsakkord ist ein Oberflächenornament, das zwei Pfeiler verbindet — er hat kein eigenständiges strukturelles Gewicht." },
  { q: "In der Folge I–IV–I6–V–I, welche Akkorde prolongieren die Tonika am Anfang?", opts: ["I und IV", "I, IV und I6", "Nur I", "I und I6"], a: 3, fb: "I und I6 prolongieren die Tonika (gleicher Akkord, andere Umkehrung). IV gehört zu SD — es ist eine Bewegung zur Subdominante, keine Tonika-Prolongation. Daher prolongieren hier nur I und I6 das T." },
  { q: "Eine aufsteigende Bassskala (C–D–E–F) unter einem I-Akkord prolongiert:", opts: ["Die Dominante", "Die Tonika durch ornamentale Bassbewegung", "Die Subdominante", "Keinen Bereich — die Skala bricht die Prolongation"], a: 1, fb: "Eine stufenweise aufsteigende Basslinie (C–D–E–F) kann die Tonika prolongieren: der Bass schmückt den I-Akkord durch Zwischenpositionen (I–I6–I6/4 oder mit Durchgangsharmonien). Es ist eine Prolongation durch arpeggierte oder stufenweise Bassbewegung." },
  { q: "Das Konzept der Prolongation ist zentral in der Analyse von:", opts: ["Schönberg", "Schenker", "Rameau", "Riemann"], a: 1, fb: "Heinrich Schenker (1868–1935) ist der Theoretiker, der die Prolongation als grundlegendes Analysewerkzeug entwickelte. Seiner Ansicht nach ist alle tonale Musik eine Prolongation der Ursatz (Grundstruktur)." },
  { q: "Eine typische Dominant-Prolongation vor einer Schlusskadenz ist:", opts: ["V–IV–V", "I6/4–V–V7", "V–VI–V", "I–V–I"], a: 1, fb: "I6/4–V–V7 ist eine klassische Dominantprolongation vor der Kadenz: der Kadenz-Quartsextakkord bereitet V vor, das durch V7 verstärkt wird. Diese gesamte Sequenz prolongiert den D-Bereich vor der Auflösung auf I." },
  { q: "Was ist Oberflächenharmonik?", opts: ["Akkorde, die oben am Klavier gespielt werden", "Alle Akkorde, wie sie in der Partitur erscheinen", "Die Hauptakkorde der Tiefenstruktur", "Akkorde ohne Umkehrungen"], a: 1, fb: "Oberflächenharmonik bezeichnet alle Akkorde, wie sie in der Partitur erscheinen — jeden Durchgangs-, Wechselnoten- und Ornamentakkord. Dies ist die 'sichtbare Oberfläche' der Harmonik vor jeder analytischen Reduktion." },
  { q: "Was ist ein Strukturakkord (harmonischer Pfeiler)?", opts: ["Ein fortissimo gespielter Akkord", "Ein Akkord, der eine Schlüsselfunktionsposition in der Tiefenstruktur des Stücks einnimmt", "Ein Akkord ohne Umkehrungen", "Der am häufigsten wiederholte Akkord im Stück"], a: 1, fb: "Ein Strukturakkord (oder Pfeiler) ist ein Akkord, der eine Schlüsselfunktion in der Tonallogik trägt: er verankert einen Bereich (T, SD, D) und ist Teil der Tiefenstruktur, die die Reduktion offenzulegen sucht." },
  { q: "Wie unterscheidet man einen Oberflächenakkord von einem Strukturakkord?", opts: ["Nur durch seine Dauer", "Durch seine funktionale Position und seine Bedeutung für die Kadenzlogik der Phrase", "Durch seine Position im Takt (schwerer Taktteil = strukturell)", "Durch die Anzahl der enthaltenen Noten"], a: 1, fb: "Dauer und Metrik sind Hinweise, aber keine absoluten Kriterien. Der Strukturakkord ist derjenige, dessen Entfernung die grundlegende Tonallogik verändern würde — er ist für die Kadenzprogression unverzichtbar." },
  { q: "In der Progression I–IV–V–I, ist der IV-Akkord strukturell oder Oberfläche?", opts: ["Immer Oberfläche", "Strukturell — er artikuliert die SD-Bewegung vor D", "Oberfläche — er kann durch II6 ersetzt werden ohne die Struktur zu ändern", "Weder noch — IV hat keine harmonische Rolle"], a: 1, fb: "IV ist hier ein Strukturakkord des SD-Bereichs: er artikuliert die funktionale Bewegung T→SD→D→T. In diesem Kontext hat seine Anwesenheit strukturelle Bedeutung. Ein durchgehender IV zwischen zwei I wäre hingegen Oberfläche." },
  { q: "In I–I6–I6/4–V–I, welcher ist der wahre Dominantstrukturakkord?", opts: ["I6/4, weil er auf dem schweren Taktteil steht", "V — I6/4 ist eine ornamentale Prolongation von V (Kadenz-Quartsextakkord)", "I6/4 und V zusammen", "Keiner — alle sind Oberfläche"], a: 1, fb: "V ist der Dominantstrukturakkord. I6/4 (Kadenz-Quartsextakkord) ist eine ornamentale Prolongation, die V 'vorbereitet' — er gehört funktional zum Dominantbereich, ist aber nicht der strukturelle Pfeiler." },
  { q: "Ein Wechselnotenakkord ist:", opts: ["Per Definition ein Strukturakkord", "Ein Oberflächenakkord, der einen Strukturakkord schmückt, ohne seine Funktion zu ändern", "Ein Pivot-Akkord zwischen zwei Tonarten", "Ein modulierender Durchgangsakkord"], a: 1, fb: "Ein Wechselnotenakkord ist ein Oberflächenakkord: er schmückt einen Strukturakkord, indem er sich von ihm entfernt und zu ihm zurückkehrt. Er schafft keine eigenständige funktionale Bewegung — er prolongiert den Strukturakkord, den er umgibt." },
  { q: "Wie identifiziert man die Strukturpfeiler einer 4-taktigen Phrase?", opts: ["Alle Akkorde auf schweren Taktzeiten nehmen", "Eröffnungsakkord, Zwischenkadenz und Schlusskadenz identifizieren — der Rest sind Prolongationen", "Nur I- und V-Akkorde behalten", "Die längsten Akkorde identifizieren"], a: 1, fb: "Die schenkersche Strategie besteht darin, die kadentiellen Ankerpunkte zu lokalisieren: Beginn (Tonika), Zwischenkadenz (oft Halbkadenz V), Schlusskadenz (V–I). Diese drei Pole bilden das strukturelle Skelett." },
  { q: "Was macht man in einer Reduktion mit Durchgangsakkorden?", opts: ["Man transponiert sie in die Oktave", "Man eliminiert sie — sie gehören nicht zur Tiefenstruktur", "Man verschiebt sie auf den schweren Taktteil", "Man ersetzt sie durch Septakkorde"], a: 1, fb: "In der Reduktion werden Durchgangsakkorde eliminiert, da sie nicht zur Tiefenstruktur gehören. Nur die Strukturpfeiler (Beginn, Kadenzen) und ihre direkten Prolongationen werden behalten." },
  { q: "Was ist die Grenze der rein oberflächlichen Analyse (Akkord für Akkord)?", opts: ["Sie ist zu einfach für fortgeschrittene Musiker", "Sie enthüllt nicht die tiefe Tonallogik und kann die Richtungsstruktur des Stücks verdecken", "Sie existiert nicht — Oberflächenanalyse ist die einzige gültige Methode", "Sie erzeugt immer harmonische Fehler"], a: 1, fb: "Die Akkord-für-Akkord-Analyse bleibt an der Oberfläche: sie kann Prolongationen und große funktionale Bögen übersehen. Die Tiefenstruktur (T→D→T über ein ganzes Werk) ist unsichtbar, wenn man an der Oberfläche stehen bleibt." },
  { q: "Warum ist die Oberfläche/Struktur-Unterscheidung pädagogisch wichtig?", opts: ["Um das Lernen zu vereinfachen", "Um zu verstehen, dass nicht alle Akkorde gleich wichtig sind, und hierarchisches Lesen zu entwickeln", "Um bestimmte schwierige Akkorde nicht analysieren zu müssen", "Um Progressionen leichter zu memorieren"], a: 1, fb: "Die Oberfläche/Struktur-Unterscheidung entwickelt hierarchisches Denken: der Schüler versteht, dass der Reichtum der Oberflächenharmonik einer einfacheren, tieferen Struktur dient. Es ist ein Verständniswerkzeug, keine Vereinfachung." },
  { q: "Was ist der Urlinie nach Schenker?", opts: ["Die fundamentale Basslinie", "Die fundamentale absteigende melodische Sopranstimme, von 3̂/5̂/8̂ nach 1̂", "Die Tenorstimme in einem Choral", "Die Hauptmelodie des Werkes"], a: 1, fb: "Der Urlinie ist der fundamentale melodische Abstieg des Soprans, ausgehend von 3̂, 5̂ oder 8̂ und diatonisch absteigend bis 1̂ (Tonika). Es ist die tiefe melodische Struktur, die jede tonale Melodie laut Schenker realisiert." },
  { q: "Welche sind die drei möglichen Formen des Urlinien?", opts: ["1̂–2̂–3̂, 3̂–4̂–5̂, 5̂–6̂–7̂", "3̂–2̂–1̂, 5̂–4̂–3̂–2̂–1̂, 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "C–D–E, G–A–H, E–F–G", "I–V–I, I–IV–I, I–II–I"], a: 1, fb: "Schenker erkennt drei Urlinien: 3̂–2̂–1̂ (Terzfall), 5̂–4̂–3̂–2̂–1̂ (Quintfall) und 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (Oktavfall). Jede große tonale Melodie realisiert eine dieser drei Formen." },
  { q: "In der Urlinie 3̂–2̂–1̂ in C-Dur, welche Note entspricht 3̂?", opts: ["C", "D", "E", "G"], a: 2, fb: "In C-Dur ist 3̂ E (3. Stufe der Tonleiter). Die Urlinie 3̂–2̂–1̂ steigt also E–D–C ab. E ist der Kopfton, der die Grundlinie einleitet." },
  { q: "In der Urlinie 5̂–4̂–3̂–2̂–1̂ in G-Dur, was ist die Anfangsnote?", opts: ["G", "D", "H", "A"], a: 1, fb: "In G-Dur ist 5̂ D (Quinte von G). Die Urlinie 5̂–4̂–3̂–2̂–1̂ steigt D–C–H–A–G ab. D ist der Kopfton, der den fundamentalen Abstieg einleitet." },
  { q: "Warum fällt die Urlinie immer nach 1̂?", opts: ["Durch Schenkers willkürliche Konvention", "Weil 1̂ (Tonika) der Auflösungs- und Ruhepunkt aller tonalen melodischen Spannung ist", "Weil Sopranstimmen immer absteigen", "Um Quintparallelen zu vermeiden"], a: 1, fb: "1̂ ist die Tonika — der Punkt der endgültigen Auflösung aller Spannung. In der Tonallogik muss alle melodische Spannung zur Tonika auflösen. Die Urlinie verkörpert diese obligatorische Auflösung im Maßstab des gesamten Werkes." },
  { q: "Wie findet man den Kopfton (Beginn der Urlinie) in einer Melodie?", opts: ["Es ist die höchste Note der Melodie", "Es ist die strukturell überragende Note am Anfang, harmonisiert durch I, von der der fundamentale Abstieg ausgeht", "Es ist die erste Note der Melodie", "Es ist die längste Note"], a: 1, fb: "Der Kopfton ist die strukturelle Anfangsnote (3̂, 5̂ oder 8̂), die zum anfänglichen Tonikaakkord gehört und von der der Urlinie-Abstieg beginnt. Es ist nicht notwendigerweise die erste oder höchste Note." },
  { q: "In der Melodie E–F–E–D–C (C-Dur), was ist die wahrscheinliche Urlinie?", opts: ["5̂–4̂–3̂–2̂–1̂", "3̂–2̂–1̂ mit E als Kopfton", "8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "Keine Urlinie — die Melodie ist zu ornamental"], a: 1, fb: "E ist 3̂ in C-Dur. Die Melodie E–F–E–D–C realisiert die Urlinie 3̂–2̂–1̂ (E–D–C) mit F als ornamentale Wechselnote. Der Kopfton ist E, und der strukturelle Abstieg ist 3̂(E)–2̂(D)–1̂(C)." },
  { q: "Ist die Urlinie immer direkt in der Oberflächenmelodie hörbar?", opts: ["Ja — sie entspricht immer der genauen Melodie", "Nein — sie ist oft ornamentiert, in die Oktave versetzt oder durch oberflächenfremde Noten unterbrochen", "Nein — sie gehört immer zum Bass", "Ja — aber nur in Bachs Musik"], a: 1, fb: "Die Urlinie ist eine Abstraktion der Oberflächenmelodie — sie ist ornamentiert, prolongiert, unterbrochen. Die tatsächliche Melodie ist eine Oberflächenrealisierung dieser Tiefenstruktur. Man muss 'durch' die Oberfläche 'hören', um sie herauszulösen." },
  { q: "Was bedeutet '2̂ durch V harmonisiert' in der Urlinie?", opts: ["Die 2. Stufe wird von der Tenorstimme gespielt", "Die Note 2̂ fällt in der Tiefenstruktur mit dem Dominantakkord zusammen", "Die 2. Stufe wird zweimal gespielt", "Der V-Akkord steht in der zweiten Umkehrung"], a: 1, fb: "In der Urlinie wird jede fundamentale Note durch einen Strukturakkord harmonisiert: 2̂ fällt mit V (Dominante) zusammen, 1̂ mit I (Tonika). Aus der Verbindung von Urlinie und Bassbrechung entsteht die Ursatz." },
  { q: "Warum sagt Schenker, dass jede große tonale Melodie die Urlinie realisiert?", opts: ["Weil alle Melodien identisch sind", "Weil die Tonallogik die Auflösung aller Spannung zur Tonika fordert — die Urlinie ist der universelle melodische Ausdruck dieses Gesetzes", "Weil er alle bestehenden Melodien analysiert hat", "Weil alle Komponisten dasselbe Modell kopieren"], a: 1, fb: "Für Schenker ist die Tonallogik universal: alle Spannung muss nach 1̂ auflösen. Die Urlinie ist kein von außen aufgezwungenes Schema, sondern die unvermeidliche Konsequenz der Tonalität selbst." },
  { q: "Was ist die Bassbrechung?", opts: ["Die absteigende melodische Sopranstimme", "Der Bass-Bogen I–V–I, der die Tonalität im Maßstab des gesamten Werkes strukturiert", "Eine barocke Generalbasstechnik", "Die Basszifferung in einem Choral"], a: 1, fb: "Die Bassbrechung ist der fundamentale Bogen I–V–I im Bass, der die fundamentale Quintbewegung der Tonalharmonik beschreibt: von der Tonika zur Dominante und zurück zur Tonika." },
  { q: "Was ist die Fundamentalbass der Bassbrechung in C-Dur?", opts: ["C–F–C", "C–G–C", "C–D–C", "C–A–C"], a: 1, fb: "Die Bassbrechung in C-Dur lautet C–G–C (I–V–I). G ist die Dominante — die Quinte der Tonleiter. Der Bogen C→G→C stellt die fundamentale Quintbewegung der Tonart dar." },
  { q: "Erstreckt sich die Bassbrechung über eine Phrase, einen Abschnitt oder ein ganzes Werk?", opts: ["Nur über eine 4-taktige Phrase", "Sie kann sich auf jede Ebene ausdehnen — von der Phrase bis zum gesamten Werk", "Nur bei kurzen Formen (Lied)", "Sie gilt nur für Bachs Choräle"], a: 1, fb: "Die Bassbrechung ist skalierbar: sie kann eine Phrase (T.1–4), einen Abschnitt (T.1–16), einen ganzen Satz oder eine vollständige Sinfonie strukturieren. Dieser fraktale Charakter macht die Schenker-Analyse universal." },
  { q: "Wie hängt die Bassbrechung mit der Urlinie in der Ursatz zusammen?", opts: ["Sie sind unabhängig", "Die Bassbrechung (Bass I–V–I) trägt die Urlinie (Sopran 3̂–2̂–1̂) — zusammen bilden sie die Ursatz", "Die Urlinie ist die melodische Version der Bassbrechung", "Die Bassbrechung ersetzt die Urlinie in Moll"], a: 1, fb: "In der Ursatz sind Urlinie (Sopran) und Bassbrechung (Bass) überlagert: 3̂ über I, 2̂ über V, 1̂ über I. Dieser zweistimmige Kontrapunkt ist die universelle Grundstruktur der tonalen Musik laut Schenker." },
  { q: "Was repräsentiert das mittlere V in der Bassbrechung I–V–I?", opts: ["Eine kurzzeitige Tonikalisierung", "Den Punkt maximaler Spannung — die Dominante, die die Progression zur endgültigen Auflösung auf I strukturiert", "Einen unwichtigen Durchgangsakkord", "Die Subdominante in Umkehrung"], a: 1, fb: "V in I–V–I ist der Spannungsgipfel der Bassbrechung — er stellt die fundamentale Quintabwärtsbewegung der Tonalität dar (Quinte I→V oder aufsteigende Quarte). Seine Auflösung auf I schließt den tonalen Bogen." },
  { q: "In einer 100-taktigen Fuge von Bach, wo befindet sich üblicherweise das V der Bassbrechung?", opts: ["Nur in Takt 2", "Am strukturellen Mittelpunkt des Werkes, oft bei der größten Zwischenkadenz", "Am Ende jeder Phrase", "In Fugen gibt es keine Bassbrechung"], a: 1, fb: "In einer großen Form fällt das strukturelle V der Bassbrechung mit dem Spannungsgipfel des Werkes zusammen — oft die große V-Kadenz auf halbem Weg. Alles Vorherige prolongiert I (Hinweg); alles Nachfolgende prolongiert die Rückkehr zu I." },
  { q: "Die Bassbrechung ist analog zu welchem formalen Prinzip in der Sonatenform?", opts: ["Exposition und Reprise", "Vorstellung → Spannung (Durchführung) → Auflösung (Reprise), d.h. I→V→I im großen Maßstab", "Nur das Hauptthema", "Die Schlusskoda"], a: 1, fb: "Die Sonatenform realisiert die Bassbrechung im großen Maßstab: Exposition in I (oft mit 2. Thema in V), Durchführung (harmonische Spannung), Reprise in I. Diese Tonalstruktur I–V–I ist die Bassbrechung des gesamten Werkes." },
  { q: "In Moll, lautet die Bassbrechung Im–Vm–Im oder Im–V–Im?", opts: ["Im–Vm–Im (Moll bei der Dominante)", "Im–V–Im (Dur-Dominante mit erhöhtem Leitton)", "Im–bVII–Im", "Im–IV–Im"], a: 1, fb: "In Moll ist die Dominante immer V-Dur (mit erhöhtem Leitton). Die Bassbrechung lautet daher Im–V–Im: das harmonische Moll wird bei der Dominante verwendet, um die maximale Spannung des Leittons zur Tonika zu erhalten." },
  { q: "Welches Bassintervall charakterisiert die I→V-Bewegung in der Bassbrechung?", opts: ["Aufsteigende Terz", "Absteigende Quinte (oder aufsteigende Quarte) — die fundamentale Bewegung der Tonalharmonik", "Aufsteigende Sekunde", "Absteigende Sexte"], a: 1, fb: "I→V entspricht einer absteigenden Quinte (C→G in C-Dur) oder aufsteigenden Quarte. Dies ist die stärkste Bewegung der Tonalharmonik — sie erzeugt die maximale Spannung, die die Auflösung V→I fordert." },
  { q: "Schenker betrachtet die Bassbrechung als:", opts: ["Ein optionales Schema zur Bassanalyse", "Die universelle Bassbewegung aller tonalen Musik — den fundamentalen Bogen des zweistimmigen Kontrapunkts", "Eine nur auf Bach anwendbare Regel", "Eine pädagogische Vereinfachung ohne analytischen Wert"], a: 1, fb: "Für Schenker ist die Bassbrechung ein universelles Gesetz: alle tonale Musik realisiert die I–V–I-Bassbewegung auf jeder Ebene. Es ist das harmonische Fundament der Ursatz." },
  { q: "Was ist die Ursatz nach Schenker?", opts: ["Die fundamentale rhythmische Struktur", "Die fundamentale kontrapunktische Struktur = Urlinie (Sopran) + Bassbrechung (Bass)", "Die Grundtonleiter jeder Tonart", "Das thematische Hauptmotiv eines Werkes"], a: 1, fb: "Die Ursatz ('Grundstruktur') ist die Überlagerung von Urlinie (Sopranabstieg 3̂–2̂–1̂) und Bassbrechung (Bass-Bogen I–V–I). Es ist ein zweistimmiger Kontrapunkt, der aller tonalen Musik zugrunde liegt." },
  { q: "Aus wie vielen Schichten besteht die Ursatz?", opts: ["Einer — der Hauptmelodie", "Zwei — Sopran (Urlinie) und Bass (Bassbrechung)", "Drei — Sopran, Alt, Bass", "Vier — die vier SATB-Stimmen"], a: 1, fb: "Die Ursatz ist ein zweistimmiger Kontrapunkt: die Urlinie im Sopran und die Bassbrechung im Bass. Diese beiden Grundstimmen genügen, um die tiefe Tonalstruktur jedes Werkes zu definieren." },
  { q: "Wie sind Urlinie und Bassbrechung in der Ursatz ausgerichtet?", opts: ["Sie sind unabhängig und kreuzen sich nie", "3̂ fällt mit I (Bass) zusammen, 2̂ mit V (Bass), 1̂ mit I (Bass)", "5̂ fällt mit V (Bass) zusammen, 3̂ mit IV, 1̂ mit I", "Sie wechseln sich ab, ohne sich je zu synchronisieren"], a: 1, fb: "Die kanonische Ursatz-Ausrichtung: Kopfton (3̂/5̂/8̂) über I, dann die Zwischenbewegung (2̂ über V), dann die Auflösung (1̂ über I). Diese Überlagerung erzeugt den fundamentalen Kontrapunkt der tonalen Musik." },
  { q: "Warum sagt Schenker, alle tonale Musik sei eine 'Prolongation der Ursatz'?", opts: ["Weil alle Komponisten dasselbe Schema kopieren", "Weil jede tonale Komposition eine Ausarbeitung dieser einfachen Grundstruktur ist — Oberflächenornamente entwickeln die Ursatz", "Weil die Ursatz vom Konservatorium vorgeschrieben wird", "Weil die Ursatz die einzige hörbare Struktur ist"], a: 1, fb: "Die Ursatz ist die tiefste und einfachste Struktur — jede tonale Komposition arbeitet sie durch aufeinanderfolgende Prolongationsschichten aus. Oberflächenornamente sind immer komplexere Realisierungen dieses Grundbogens." },
  { q: "Gilt die Ursatz für die atonale Musik des 20. Jahrhunderts?", opts: ["Ja — Schenker wendet sie auf alle Musik an", "Nein — die Ursatz setzt Tonalität voraus; atonale Musik folgt nicht ihren Prinzipien", "Ja, aber mit Modifikationen", "Nein — sie gilt nur für Bach"], a: 1, fb: "Die Ursatz setzt Tonalität voraus: Urlinie absteigend nach 1̂ und Bassbrechung I–V–I. Atonale Musik, die die Stufenhierarchie ablehnt, kann in diesem Rahmen nicht analysiert werden. Dies ist eine explizite Grenze des schenkerschen Systems." },
  { q: "Was ist die vollständige Version der Ursatz mit der Urlinie 5̂–4̂–3̂–2̂–1̂?", opts: ["5̂ über I, 4̂ über IV, 3̂ über I, 2̂ über V, 1̂ über I", "5̂ über I, Abstieg 4̂–3̂ prolongiert, 2̂ über V, 1̂ über I", "5̂ über V, 4̂ über IV, 3̂ über III, 2̂ über II, 1̂ über I", "5̂ über I, 4̂–3̂–2̂ ornamental, 1̂ über V"], a: 1, fb: "In der Quintfall-Urlinie werden die Stufen 4̂ und 3̂ oft durch intermediäre harmonische Bewegungen prolongiert, aber die strukturellen Ankerpunkte sind 5̂ über I, 2̂ über V und 1̂ über I — die vollständige Ursatz bildend." },
  { q: "Hat die Ursatz ein einziges Modell oder mehrere Varianten?", opts: ["Ein einziges universelles Modell", "Drei Varianten je nach Kopfton (3̂, 5̂ oder 8̂)", "Unendlich viele Varianten je nach Komponist", "Zwei Varianten (Dur und Moll)"], a: 1, fb: "Schenker erkennt drei Ursatz-Formen je nach Kopfton: 3̂–2̂–1̂ (am einfachsten), 5̂–4̂–3̂–2̂–1̂ (sehr häufig), 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (seltener). Die Bassbrechung bleibt in allen drei Fällen I–V–I." },
  { q: "Wie manifestiert sich die Ursatz im großen Maßstab in einer Sinfonie?", opts: ["Nur im 1. Satz", "Die Grundtonart in I prolongiert sich bis zum strukturellen V (oft in der Durchführung), kehrt dann am Ende zu I zurück", "Nur auf Phrasenebene sichtbar", "Manifestiert sich nur im Basso continuo"], a: 1, fb: "In einer Sinfonie erstreckt sich die Ursatz über das gesamte Werk: der Beginn verankert sich in I, der Punkt maximaler Spannung (oft Durchführung oder zentrale Kadenz) realisiert V, und der Schluss kehrt zu I zurück. Die Bassbrechung I–V–I strukturiert das gesamte Werk." },
  { q: "Was sind 'Vordergrund', 'Mittelgrund' und 'Hintergrund' in der Schenker-Analyse?", opts: ["Drei verschiedene Instrumente", "Die drei Analyseschichten: Oberfläche (Vordergrund), Mittelschicht (Mittelgrund), Tiefenstruktur (Hintergrund = Ursatz)", "Drei Teile einer Fuge", "Drei Kadenzkarten"], a: 1, fb: "Schenker verwendet diese drei Ebenen: Vordergrund (Oberflächenmusik wie notiert), Mittelgrund (gruppierte Prolongationen), Hintergrund (nur die Ursatz). Die Reduktion schreitet vom Vordergrund zum Hintergrund voran." },
  { q: "Was ist der Hauptbeitrag der Ursatz-Theorie zur Musikanalyse?", opts: ["Sie erlaubt das einfachere Auswendiglernen von Partituren", "Sie enthüllt die gemeinsame tiefe Tonalstruktur aller großen Werke und erklärt ihre Kohärenz im großen Maßstab", "Sie vereinfacht die Musiknotation", "Sie ersetzt die traditionelle Akkord-für-Akkord-Harmonieanalyse"], a: 1, fb: "Die Ursatz ermöglicht das Verständnis tonaler Kohärenz im großen Maßstab: warum ein 300-taktiges Werk 'zusammenhält'. Sie enthüllt, dass Oberflächenkomplexität eine einfache und universelle Grundstruktur verdeckt." },
  { q: "Wie viele Schritte umfasst eine vollständige Schenker-Reduktion?", opts: ["1 Schritt — direkt zur Ursatz übergehen", "Mindestens 3 Schichten: Oberfläche (Vordergrund) → Mittel (Mittelgrund) → Tiefe (Hintergrund)", "5 feste Schritte für jede Analyse", "2 Schritte — gerade und ungerade Akkorde"], a: 1, fb: "Die Schenker-Reduktion verläuft in aufeinanderfolgenden Schichten: Vordergrund (Oberfläche) → Mittelgrund(e) (Zwischenschichten, manchmal mehrere) → Hintergrund (Ursatz). Die Anzahl der Zwischenschichten hängt von der Komplexität des Werkes ab." },
  { q: "Was macht man als erstes bei einer Schichtenreduktion?", opts: ["Sofort die Urlinie identifizieren", "Alle Akkorde der Partitur aufschreiben (Oberflächenharmonik)", "Zur Ursatz reduzieren", "Modulationen analysieren"], a: 1, fb: "Der erste Schritt ist, die vollständige Oberflächenharmonik zu notieren — alle Akkorde wie sie erscheinen. Dies ist der Vordergrund: der Ausgangspunkt vor jeder Reduktion. Man überspringt keine Schritte." },
  { q: "Was ist eine Mittelgrundreduktion?", opts: ["Eine Analyse, die alle Oberflächenakkorde beibehält", "Eine Analyse, die Oberflächenakkorde nach Funktion gruppiert und Ornamente eliminiert, die Hauptprolongationen offenbarend", "Eine rein melodische Analyse", "Eine Reduktion, die nur I und V behält"], a: 1, fb: "Der Mittelgrund ist eine Zwischenschicht, wo Durchgangs- und Wechselnotenakkorde eliminiert werden, Oberflächenakkorde nach Funktion gruppiert. Man erhält einen Blick auf die Hauptprolongationen ohne zur vollständigen Ursatz zu gehen." },
  { q: "Wie entscheidet man, dass ein Akkord in der Reduktion 'eliminierbar' ist?", opts: ["Durch Eliminierung der Mollakkorde", "Durch Eliminierung von Akkorden ohne eigenständige Funktion — Durchgangsakkorde, Wechselnotakkorde, Ornamente", "Durch Eliminierung aller Akkorde auf leichten Taktzeiten", "Durch Eliminierung von Umkehrungen"], a: 1, fb: "Ein Akkord ist eliminierbar, wenn er keine eigenständige Funktion hat: Durchgangsakkord zwischen zwei Pfeilern, Wechselnotenakkord, ornamentaler Akkord. Seine Entfernung ändert die fundamentale Tonallogik nicht." },
  { q: "In der Reduktion von I–IV–I6–V7–I, wie würde die Mittelgrundversion aussehen?", opts: ["I–I6–V7–I", "I–IV–V–I", "I–V–I", "I–V7–I"], a: 3, fb: "I–IV–V7–I ist eine vernünftige Mittelgrundreduktion: I, IV (SD), V7 (D) und I werden behalten. I6 wird eliminiert, da es eine Prolongation von I ist (gleicher Akkord in Umkehrung). Die Tiefenreduktion wäre I–V–I (Bassbrechung)." },
  { q: "Die Schichtenreduktion enthüllt welchen Strukturtyp?", opts: ["Nur die rhythmische Struktur", "Die hierarchische Struktur: von der Oberflächenkomplexität zur fundamentalen Einfachheit", "Die kontrapunktische Struktur jeder Stimme", "Die modale Struktur des Werkes"], a: 1, fb: "Die Schichtenreduktion enthüllt die harmonische Hierarchie: auf jeder Schicht wird die Struktur einfacher und fundamentaler. Oberflächenkomplexität (Vordergrund) löst sich in Prolongationen (Mittelgrund) und schließlich in die Ursatz (Hintergrund) auf." },
  { q: "Was enthüllt der Unterschied zwischen Vordergrund und Hintergrund?", opts: ["Die harmonischen Fehler des Komponisten", "Den Reichtum der Ornamente und Prolongationen, die die Grundstruktur entwickeln — dies ist der 'Inhalt' des Werkes", "Passagen, die von anderen Komponisten kopiert wurden", "Die technischen Schwierigkeiten des Stücks"], a: 1, fb: "Der Unterschied zwischen Oberfläche und Tiefenstruktur zeigt, wie der Komponist die Ursatz 'kleidet': die Prolongationen, Ornamente und Entwicklungen, die jedem Werk seine einzigartige Persönlichkeit verleihen, während sie auf derselben Grundstruktur ruhen." },
  { q: "Kann man ein Stück in Schichten reduzieren, ohne die Tonart zu kennen?", opts: ["Ja — die Reduktion ist von der Tonart unabhängig", "Nein — die Tonart ist das unverzichtbare Rahmenwerk zur Identifizierung von Funktionen und Pfeilern", "Ja, wenn man nur den Bass behält", "Ja, aber nur für den Vordergrund"], a: 1, fb: "Die Schenker-Reduktion setzt die Tonart voraus: T, SD, D und ihre Prolongationen zu identifizieren erfordert die Kenntnis der Tonart. Ohne diesen Rahmen kann man Strukturakkorde nicht von ornamentalen Akkorden unterscheiden." },
  { q: "Wie gilt das Schichtenkonzept für eine 8-taktige Phrase?", opts: ["Jeder Takt ist eine eigene Schicht", "Oberfläche: alle Akkorde der 8 Takte. Mittelschicht: I–IV–V–I (Pfeiler). Tiefe: I–V–I (Ursatz)", "Eine 8-taktige Phrase hat keine Schichtenstruktur", "Schichten gelten nur für ganze Sätze"], a: 1, fb: "Selbst eine kurze 8-taktige Phrase kann in Schichten analysiert werden: Oberfläche (alle Akkorde), Mittelschicht (funktionale Pfeiler T–SD–D–T), Tiefe (Ursatz I–V–I). Dies ist das fraktale Prinzip der Schenker-Analyse." },
  { q: "Was ist der praktische Nutzen der Schichtenreduktion für einen Komponisten?", opts: ["Keiner — sie dient nur der theoretischen Analyse", "Die Tiefenstruktur verstehen, um kohärente lange Werke zu schreiben und die harmonische Trajektorie im großen Maßstab zu planen", "Das Schreiben vereinfachen, indem man nur I und V verwendet", "Komplexe Akkorde vermeiden"], a: 1, fb: "Die Schichtenreduktion hilft dem Komponisten, die große Form zu planen: Was ist die Bassbrechung des Werkes? Wann kommt das strukturelle V? Wie entwickeln die Zwischenprolongationen die Ursatz? Es ist ein Kompositionswerkzeug ebenso wie ein Analysewerkzeug." },
  { q: "In Bachs C-Dur-Präludium BWV 846 (Arpeggios) ist die harmonische Oberflächenstruktur:", opts: ["Nur I während des gesamten Stücks", "Eine Folge wechselnder arpeggiierter Akkorde über einem funktionalen harmonischen Plan T→SD→D→T", "Eine Improvisation ohne Struktur", "Eine Reihe von Modulationen in Nachbartonarten"], a: 1, fb: "Das Präludium BWV 846 realisiert eine vollständige funktionale Harmonikprogression durch Arpeggios: die Oberflächenstruktur ist reich, aber die Tiefenstruktur ist eine einfache T→SD→D→T-Progression, die die Ursatz realisiert." },
  { q: "In einem Bach-Choral dienen die internen Kadenzen hauptsächlich dazu:", opts: ["Die Tonart endgültig zu wechseln", "Die Struktur in Phrasen und Abschnitte zu gliedern und intermediäre harmonische Pfeiler in der Reduktion zu schaffen", "Quintparallelen zu vermeiden", "Neue Stimmen einzuführen"], a: 1, fb: "Die internen Kadenzen (Halbkadenzen, unvollkommene Kadenzen) eines Bach-Chorals gliedern die Struktur: sie schaffen intermediäre Ankerpunkte in der Reduktion, die die Hierarchie der Kadenzen (intermediär vs. abschließend) enthüllen." },
  { q: "In Mozarts Sonate K.331 (Thema mit Variationen) ist die harmonische Struktur des Themas:", opts: ["Komplex und modulierend ab dem 1. Satz", "Einfach — I prolongiert (T.1–4), dann V (T.5–8), Auflösung auf I (T.9–16): klare Bassbrechung", "Nur auf wechselnden IV und V", "Ohne klare funktionale Struktur"], a: 1, fb: "Das Thema von K.331 realisiert die Bassbrechung über 16 Takte: Präsentation auf I (T.1–8), Spannung auf V (T.9–14), Auflösung I (T.15–16). Die Struktur ist ein Modell tonaler Ökonomie." },
  { q: "In einer Bach-Fuge in C-Dur, wenn das Thema in G-Dur (V) eintritt, stellt das dar:", opts: ["Eine endgültige Modulation nach G-Dur", "Die tonale Antwort — eine Tonikalisierung von V, die sich in die Bassbrechung I→V einfügt", "Einen Kontrapunktfehler", "Die Exposition des Kontrasubjekts"], a: 1, fb: "Die Antwort in V in einer Fuge realisiert die erste Bewegung der Bassbrechung: I→V. Die Fuge 'moduliert' nach V, aber es ist eine Tonikalisierung, die sich in den fundamentalen Bogen I–V–I der gesamten Fuge einfügt." },
  { q: "Im 1. Satz von Mozarts Sinfonie Nr. 40 KV550 repräsentiert das 2. Thema in B-Dur:", opts: ["Eine endgültige und eigenständige Modulation", "Die Tonikalisierung von III (paralleles Dur des Moll) — harmonische Bewegung der Exposition zur strukturellen 'Dominante'", "Einen Tonartfehler Mozarts", "Den Beginn der Reprise"], a: 1, fb: "In G-Moll repräsentiert das 2. Thema in B (bIII = Tonikaparallele) die strukturelle Bewegung der Exposition in die Dominantzone. In der Moll-Bassbrechung übernimmt bIII oft die Rolle der strukturellen Dominante der Exposition." },
  { q: "In einem 16-taktigen Haydn-Menuett stellt die V-Kadenz in Takt 8 dar:", opts: ["Das Ende des Werkes", "Das strukturelle V der Bassbrechung — der mediane Spannungspunkt vor der Rückkehr zu I am Ende", "Eine endgültige Modulation nach G", "Einen ungeplanten harmonischen Unfall"], a: 1, fb: "Die V-Kadenz auf halbem Weg ist typisch für die Periodenform: das V in Takt 8 ist das strukturelle V der Bassbrechung. Alles Folgende (T.9–16) prolongiert die Rückkehr zum abschließenden I — die zweite Hälfte des Bogens I–V–I." },
  { q: "In Bachs Chaconne BWV 1004 (Ostinato-Bass) erstreckt sich die Bassbrechung über:", opts: ["Jede Basswiederholung einzeln", "Das gesamte Werk — die 64 Variationen prolongieren eine einzige Ursatz von der ersten bis zur letzten Note", "Nur die ersten 4 Variationen", "Der Ostinato-Bass hat keine Bassbrechung"], a: 1, fb: "Bachs Chaconne realisiert eine Ursatz im Maßstab des gesamten Werkes: die 64 Variationen sind eine monumentale Prolongation von I–V–I. Der Ostinato-Bass ist selbst eine Prolongation der fundamentalen Bassbrechung." },
  { q: "Wie analysiert man einen 4-taktigen Bach-Choral mit der Reduktionsmethode?", opts: ["Alle Akkorde behalten und nummerieren", "1) alle Akkorde notieren, 2) Eröffnung (T), Zwischenkadenz (V oder II6–V), Schlusskadenz (V–I) lokalisieren, 3) zur Bassbrechung I–V–I reduzieren", "Nur auf I–IV–V–I vereinfachen", "Nur Umkehrungen identifizieren"], a: 1, fb: "Die 3-Schritte-Methode: 1) vollständige Oberfläche, 2) funktionale Pfeiler (Eröffnung T, Zwischen- und Schlusskadenzen), 3) Bassbrechung I–V–I. Dieser Ansatz vermeidet reine Akkord-für-Akkord-Analyse und enthüllt die Tiefenstruktur." },
  { q: "In Mozart K.545 (Sonate in C-Dur, Beginn) prolongieren die ersten 4 Takte:", opts: ["Nur V", "I (Tonika) durch verschiedene Oberflächenharmonien (I–V6–I–IV6–I6/4–V–I)", "Nur IV", "Die Subdominante"], a: 1, fb: "T.1–4 von K.545 prolongieren I (Tonika): die Oberflächenharmonien (V6, IV6, I6/4–V–I) schmücken und kadenzieren die Tonika. Die Tiefenstruktur dieser 4 Takte ist ein prolongiertes I — ein aufgehängter Kopfton vor der eigentlichen Bewegung zu V." },
  { q: "Warum sind Bach und Mozart die Referenzkomponisten für die Schenker-Analyse?", opts: ["Weil sie genau dieselben Formeln verwendeten", "Weil ihre tonale Schreibweise musterhaft ist: einfache Tiefenstruktur, ausgearbeitete Prolongationen, tadellose harmonische Logik", "Weil Schenker sie persönlich kannte", "Weil ihre Musik die schwierigste zu analysieren ist"], a: 1, fb: "Bach und Mozart sind Modelle, weil ihre tonale Schreibweise die Ursatz perfekt realisiert: hinter einer sehr reichen Oberfläche ist die Tiefenstruktur von musterhafter Klarheit und Logik. Sie illustrieren ideal die schenkerschen Prinzipien." },
  { q: "In der Progression C–G–A–F–G–C (Bass, C-Dur), was ist der strukturelle Dominantakkord?", opts: ["A (VI)", "F (IV)", "G (V) — beide Vorkommen", "C (I)"], a: 2, fb: "G (V) ist der strukturelle Dominantakkord. Beide G-Vorkommen können V prolongieren, bevor die endgültige Auflösung auf I erfolgt. C = T, A = T prolongiert (VI), F = SD, G = D, C = T: Progression T–T–SD–D–T." },
  { q: "Sie analysieren 8 Takte. Die Struktur ist I–IV–I6–V6–I–II6–V7–I. Was sind die Strukturpfeiler?", opts: ["Alle 8 Akkorde sind Pfeiler", "I (Beginn), V (Zwischenkadenz oder Dominante), I (Schluss) — die anderen sind Prolongationen", "Nur I, IV, V7, I", "I6, V6, II6, I"], a: 1, fb: "Die Strukturpfeiler sind I (Eröffnung), V/V7 (Dominante) und I (Schluss). IV, I6, V6 und II6 sind Prolongationen oder funktionale Ornamente. Die zugrunde liegende Bassbrechung ist I–V–I." },
  { q: "Ihnen wird die Melodie E–D–C über 3 Takte gegeben (C-Dur, harmonisiert durch I–V–I). Dies ist ein Beispiel für:", opts: ["Nur Bassbrechung", "Urlinie 3̂–2̂–1̂ harmonisiert durch die Ursatz I–V–I — ein perfektes Beispiel für Grundstruktur", "V-Prolongation", "Unvollkommene Kadenz"], a: 1, fb: "E–D–C (3̂–2̂–1̂) über I–V–I ist das reinste Beispiel der Ursatz: die Terzfall-Urlinie steigt von 3̂ auf 1̂ ab, gestützt von der Bassbrechung I–V–I. Dies ist das Grundmodell, das Schenker in Der freie Satz illustriert." },
  { q: "Wie bestimmt man, ob eine Modulation in einem Stück strukturell oder ornamental ist?", opts: ["Alle Modulationen sind strukturell", "Wenn die neue Tonart durch eine V–I-Kadenz bestätigt und über einen bedeutenden Abschnitt aufrechterhalten wird, ist sie strukturell; sonst ist es eine ornamentale Tonikalisierung", "Eine Modulation ist immer ornamental", "Wenn die Modulation länger als 2 Takte dauert, ist sie strukturell"], a: 1, fb: "Die Schlüsselunterscheidung: Tonikalisierung (vorübergehend, wenige Akkorde) vs. strukturelle Modulation (durch V–I bestätigt, über einen Abschnitt aufrechterhalten). In der Schichtenanalyse verschwinden Tonikalisierungen im Mittelgrund; nur strukturelle Modulationen bleiben." },
  { q: "Wo beginnt man bei einer praktischen Analyse?", opts: ["Beim letzten Takt", "Mit der Tonartidentifikation, dann die Schlusskadenz (V–I) lokalisieren, dann zum Beginn zurückgehen", "Bei den höchsten Noten", "Jeden Akkord von links nach rechts ohne bestimmte Reihenfolge analysieren"], a: 1, fb: "Mit der Tonart und Schlusskadenz zu beginnen ist die schenkersche Strategie: die Schlusskadenz (V–I) ist V und I der Bassbrechung. Man geht dann zurück, um zu finden, wie sich die Tiefenstruktur vom Beginn an entfaltet." },
  { q: "Welche dieser Analysen von I–VI–II–V–I ist korrekt?", opts: ["I=D, VI=T, II=SD, V=D, I=T", "I=T, VI=T (Prolongation), II=SD, V=D, I=T", "I=T, VI=SD, II=D, V=T, I=D", "I=SD, VI=D, II=T, V=SD, I=T"], a: 1, fb: "I=T, VI=T (VI gehört zum Tonikabereich), II=SD, V=D, I=T. Die Progression realisiert T(prolongiert durch VI)–SD–D–T. Die korrekte Analyse identifiziert VI als zum Tonikabereich gehörig." },
  { q: "Sie müssen I–I6–IV–II6–I6/4–V7–I auf die Mittelschicht reduzieren. Was ist das Ergebnis?", opts: ["I–IV–II6–V7–I", "I–IV–V7–I (oder I–II6–V7–I)", "I–I6/4–V7–I", "Nur I–V–I"], a: 1, fb: "In der Mittelschicht wird I6 (Prolongation von I) eliminiert, IV oder II6 (SD) behalten, I6/4 (Prolongation von V) manchmal eliminiert. Das typische Ergebnis ist I–IV–V7–I oder I–II6–V7–I — die funktionale Struktur T–SD–D–T ohne Ornamente." },
  { q: "Was ist die beste Oberflächenanalyse von C–G–E–C (aufsteigender Bass, C-Dur)?", opts: ["I–V–I6–I (Arpeggio von I)", "I–V–III–I (4 verschiedene Akkorde)", "I prolongiert durch Arpeggio (I–I6–I6/4–I) — eine einzige Tonikafunktion", "II–V–I–I"], a: 2, fb: "C–G–E–C im Bass arpegiert den C-Dur-Akkord: C = Grundstellung, G = I6/4 (Quinte im Bass), E = I6 (Terz im Bass), C = Grundstellung. Dies ist eine Tonika-Prolongation durch Arpeggio — eine einzige T-Funktion." },
  { q: "Warum ist die V–I-Kadenz der abschließende Pfeiler jeder Ursatz?", opts: ["Durch willkürliche Konvention", "Weil V–I die Auflösung der maximalen Spannung (Dominante) zur Ruhe (Tonika) realisiert — der obligatorische Abschluss aller Tonallogik", "Weil V–I die längste Kadenz ist", "Weil I lauter klingt als V"], a: 1, fb: "V–I ist die fundamentale Auflösung der Tonallogik: die Dominante erzeugt maximale Spannung (Tritonus in V7, Leitton zur Tonika), die nur die Tonika auflösen kann. Es ist der unvermeidliche Abschluss von Bassbrechung und Urlinie." },
];

const questionsIt: Question[] = [
  // ── 1. Regioni tonali (T/SD/D) ──────────────────────────────────────────
  { q: "Quali gradi appartengono alla regione tonica (T) in Do maggiore?", opts: ["I, II, IV", "I, III, VI", "V, VII, II", "IV, VI, III"], a: 1, fb: "La regione tonica raggruppa gli accordi che evocano la stabilità della tonica: I, III e VI. Questi accordi condividono due note con I (Do–Mi–Sol) e rinforzano il colore di riposo." },
  { q: "Quali gradi appartengono alla regione della sottodominante (SD) in Do maggiore?", opts: ["I, III, VI", "V, VII", "II, IV", "I, IV, V"], a: 2, fb: "La regione della sottodominante comprende II e IV. Questi accordi preparano armonicamente la dominante — creano tensione intermedia tra il riposo (T) e la tensione massima (D)." },
  { q: "Quali gradi appartengono alla regione della dominante (D) in Do maggiore?", opts: ["I, III, VI", "II, IV", "V, VII", "III, V"], a: 2, fb: "La regione della dominante raggruppa V e VII. Portano la tensione massima ed esigono la risoluzione verso la tonica. V7 è l'accordo di dominante per eccellenza; VII ne è la versione incompleta." },
  { q: "Nella progressione I–VI–II–V–I, a quale regione appartiene VI?", opts: ["Regione dominante", "Regione della sottodominante", "Regione tonica", "Nessuna regione"], a: 2, fb: "VI (La minore in Do maggiore) appartiene alla regione tonica perché condivide due note con I (Do e Mi). In questa progressione, VI prolunga la tonica prima del movimento verso SD (II) e D (V)." },
  { q: "La progressione T–SD–D–T descrive:", opts: ["La regola delle quinte parallele", "La sequenza funzionale di base dell'armonia tonale", "La struttura dell'Urlinie", "Il principio della Bassbrechung"], a: 1, fb: "T–SD–D–T è lo schema funzionale fondamentale della musica tonale: partenza stabile (T), preparazione (SD), tensione massima (D), ritorno al riposo (T). Ogni progressione tonale può essere letta come una variante di questo modello." },
  { q: "L'accordo II6 (2° grado al primo rivolto) appartiene a quale regione funzionale?", opts: ["Regione tonica", "Regione della dominante", "Regione della sottodominante", "Nessuna — i rivolti cambiano la regione"], a: 2, fb: "Il rivolto non cambia la regione funzionale. II (Re–Fa–La) appartiene alla regione della sottodominante sia in stato fondamentale sia al primo rivolto. II6 è addirittura la forma preferita di II nello stile classico prima di V." },
  { q: "Perché IV–V–IV è una progressione sconsigliata?", opts: ["Perché IV e V non possono seguirsi", "Perché questo regresso D→SD rompe la logica direzionale SD→D→T", "Perché IV non appartiene alla scala", "Perché V seguito da IV crea quinte parallele sistematiche"], a: 1, fb: "IV–V–IV rappresenta un 'passo indietro' funzionale: si lascia la sottodominante per la dominante, poi si torna alla sottodominante. Questa esitazione rompe la logica T→SD→D→T e indebolisce la progressione." },
  { q: "In Sol maggiore, l'accordo di Mi minore (VIm) appartiene a:", opts: ["Regione della dominante", "Regione della sottodominante", "Regione tonica", "Nessuna di queste regioni"], a: 2, fb: "In Sol maggiore, VI è Mi minore. Appartiene alla regione tonica perché condivide due note con I (Sol e Si di Sol–Si–Re). Mi–Sol–Si condivide Sol e Si con Sol maggiore — è il colore di riposo tonico." },
  { q: "Che cos'è un prolungamento della regione tonica?", opts: ["Un accordo estraneo alla tonalità", "Una sequenza di accordi che mantiene il colore funzionale di T senza cambiare regione", "Il passaggio obbligatorio per V prima di I", "La ripetizione letterale di I all'ottava"], a: 1, fb: "Un prolungamento tonico è un insieme di accordi (es. I–VI–I6–I) che rimangono nella regione T. Ornano e sostengono il colore di riposo della tonica senza alcun movimento funzionale reale verso SD o D." },
  { q: "In una frase di 8 battute in forma sentence classica, le battute 1–4 sono spesso:", opts: ["D–T–D–T", "T prolungata, poi movimento verso D", "Solo SD", "Alternanza rapida T/D/T/D"], a: 1, fb: "La sentence classica inizia con una presentazione (bb. 1–4) che prolunga la tonica, poi una continuazione (bb. 5–8) che sviluppa il movimento SD–D–T verso la cadenza finale. È la struttura archetipica di Haydn e Mozart." },

  // ── 2. Prolungamento armonico ────────────────────────────────────────────
  { q: "Che cos'è il prolungamento armonico?", opts: ["Un accordo suonato molto forte per essere udito", "Il mantenimento di una funzione armonica per diverse battute attraverso armonie di superficie mutevoli", "L'aumento della durata di tutte le note", "Un accordo tenuto senza cambiamento per diverse battute"], a: 1, fb: "Il prolungamento armonico è il principio per cui una funzione (T, SD o D) viene mantenuta per diverse battute, anche se gli accordi di superficie cambiano. Es.: I–I6–I6/4 prolungano tutti la funzione tonica." },
  { q: "La progressione I–VI–I6–I è un esempio di:", opts: ["Movimento T→SD→D→T", "Prolungamento della regione tonica", "Cadenza autentica", "Bassbrechung"], a: 1, fb: "I–VI–I6–I prolunga la regione tonica: VI appartiene a T (condivide due note con I), I6 è I al rivolto. Tutti questi accordi mantengono il colore funzionale di riposo della tonica." },
  { q: "In un prolungamento di dominante, quale accordo può 'ornare' V senza abbandonarlo funzionalmente?", opts: ["IV", "I6/4 (prima di V, il 6/4 cadenzale)", "II", "VI"], a: 1, fb: "Il 6/4 cadenzale (I6/4) su un tempo forte prolunga la regione della dominante: il suo basso è Sol (quinta di I ma anche fondamentale di V), e risolve immediatamente su V. Si dice che I6/4–V formi un'unità di prolungamento della dominante." },
  { q: "Come si riconosce un prolungamento in un'analisi?", opts: ["Tutti gli accordi hanno la stessa durata", "Diversi accordi successivi condividono la stessa funzione regionale e servono a ornare o sviluppare un accordo strutturale", "Tutti gli accordi sono nella stessa ottava", "Il basso non si muove affatto"], a: 1, fb: "Un prolungamento si riconosce dalla coerenza funzionale: diversi accordi di superficie diversi che mantengono la stessa regione (T, SD o D). L'accordo strutturale è il pilastro; gli altri sono i suoi ornamenti." },
  { q: "Una nota di pedale al basso su Sol prolunga:", opts: ["La regione tonica soltanto", "La regione della dominante, mantenendo la fondamentale di V sotto armonie mutevoli", "La regione della sottodominante", "Nessuna regione precisa"], a: 1, fb: "Un pedale su Sol (dominante) mantiene la tensione di V sotto armonie mutevoli. Gli accordi che passano sopra sono ornamenti di superficie — la funzione strutturale rimane D per tutto il pedale." },
  { q: "Qual è la differenza tra un accordo di passaggio e un accordo strutturale?", opts: ["L'accordo di passaggio è più lungo", "L'accordo strutturale è un pilastro funzionale; l'accordo di passaggio è un ornamento tra due pilastri", "L'accordo strutturale è sempre in stato fondamentale", "Non c'è differenza — tutti gli accordi sono uguali"], a: 1, fb: "L'accordo strutturale (pilastro) è un punto d'ancoraggio funzionale nell'analisi a strati. L'accordo di passaggio è un ornamento di superficie che collega due pilastri — non ha peso strutturale indipendente." },
  { q: "Nella sequenza I–IV–I6–V–I, quali accordi prolungano la tonica all'inizio?", opts: ["I e IV", "I, IV e I6", "Solo I", "I e I6"], a: 3, fb: "I e I6 prolungano la tonica (stesso accordo, rivolto diverso). IV appartiene a SD — è un movimento verso la sottodominante, non un prolungamento tonico. Quindi solo I e I6 prolungano T qui." },
  { q: "Una scala ascendente al basso (Do–Re–Mi–Fa) sotto un accordo di I prolunga:", opts: ["La dominante", "La tonica attraverso un movimento ornamentale del basso", "La sottodominante", "Nessuna regione — la scala rompe il prolungamento"], a: 1, fb: "Una linea di basso congiunta ascendente (Do–Re–Mi–Fa) può prolungare la tonica: il basso orna l'accordo di I passando per posizioni intermedie (I–I6–I6/4 o con armonie di passaggio). È un prolungamento per basso arpeggiato o congiunto." },
  { q: "Il concetto di prolungamento è centrale nell'analisi di:", opts: ["Schoenberg", "Schenker", "Rameau", "Riemann"], a: 1, fb: "Heinrich Schenker (1868–1935) è il teorico che ha sviluppato il prolungamento come strumento analitico fondamentale. Secondo lui, tutta la musica tonale è un prolungamento dell'Ursatz (struttura fondamentale)." },
  { q: "Un tipico prolungamento di dominante prima di una cadenza finale è:", opts: ["V–IV–V", "I6/4–V–V7", "V–VI–V", "I–V–I"], a: 1, fb: "I6/4–V–V7 è un classico prolungamento della dominante prima della cadenza: il 6/4 cadenzale prepara V che viene amplificato da V7. Tutta questa sequenza prolunga la regione D prima della risoluzione su I." },

  // ── 3. Armonia di superficie vs strutturale ────────────────────────────
  { q: "Che cos'è l'armonia di superficie?", opts: ["Gli accordi suonati nella parte superiore del pianoforte", "L'insieme di tutti gli accordi così come appaiono nella partitura", "Gli accordi principali della struttura profonda", "Gli accordi senza rivolti"], a: 1, fb: "L'armonia di superficie designa tutti gli accordi così come appaiono nella partitura — ogni accordo di passaggio, ornamento, nota ausiliaria. È la 'superficie' visibile dell'armonia, prima di qualsiasi riduzione analitica." },
  { q: "Che cos'è un accordo strutturale (pilastro armonico)?", opts: ["Un accordo suonato fortissimo", "Un accordo che occupa una posizione funzionale chiave nella struttura profonda del pezzo", "Un accordo senza rivolti", "L'accordo più spesso ripetuto nel pezzo"], a: 1, fb: "Un accordo strutturale (o pilastro) è un accordo che porta una funzione chiave nella logica tonale: ancora una regione (T, SD, D) e fa parte della struttura profonda che la riduzione cerca di rivelare." },
  { q: "Come si distingue un accordo di superficie da un accordo strutturale?", opts: ["Solo per la durata", "Per la sua posizione funzionale e la sua importanza per la logica cadenzale della frase", "Per la sua posizione nella battuta (tempo forte = strutturale)", "Per il numero di note che contiene"], a: 1, fb: "La durata e la posizione metrica sono indizi ma non criteri assoluti. L'accordo strutturale è quello la cui rimozione cambierebbe la logica tonale fondamentale — è indispensabile alla progressione cadenzale." },
  { q: "Nella progressione I–IV–V–I, l'accordo IV è strutturale o di superficie?", opts: ["Sempre di superficie", "Strutturale — articola il movimento SD prima di D", "Di superficie — può essere sostituito da II6 senza cambiare la struttura", "Né l'uno né l'altro — IV non ha alcun ruolo armonico"], a: 1, fb: "IV è qui un accordo strutturale della regione SD: articola il movimento funzionale T→SD→D→T. In questo contesto, la sua presenza ha significato strutturale. Un IV di passaggio tra due I sarebbe invece di superficie." },
  { q: "In I–I6–I6/4–V–I, qual è il vero accordo strutturale di dominante?", opts: ["I6/4 perché è sul tempo forte", "V — I6/4 è un prolungamento ornamentale di V (6/4 cadenzale)", "I6/4 e V insieme", "Nessuno — tutti sono di superficie"], a: 1, fb: "V è l'accordo strutturale di dominante. I6/4 (6/4 cadenzale) è un prolungamento ornamentale che 'prepara' V — appartiene funzionalmente alla regione della dominante ma non ne è il pilastro strutturale." },
  { q: "Un accordo di bordura (nota di bordura armonizzata) è:", opts: ["Un accordo strutturale per definizione", "Un accordo di superficie che orna un accordo strutturale senza cambiarne la funzione", "Un accordo pivot tra due tonalità", "Un accordo di passaggio modulante"], a: 1, fb: "Un accordo di bordura è un accordo di superficie: orna un accordo strutturale allontanandosene e tornandovi. Non crea movimento funzionale indipendente — prolunga l'accordo strutturale che circonda." },
  { q: "Come si identificano i pilastri strutturali di una frase di 4 battute?", opts: ["Prendere tutti gli accordi sui tempi forti", "Identificare l'accordo d'apertura, la cadenza mediana e la cadenza finale — gli altri sono prolungamenti", "Conservare solo gli accordi di I e V", "Identificare gli accordi più lunghi"], a: 1, fb: "La strategia schenkeriana consiste nel localizzare i punti d'ancoraggio cadenzali: inizio (tonica), cadenza mediana (spesso semicadenza V), cadenza finale (V–I). Questi tre poli formano lo scheletro strutturale." },
  { q: "In una riduzione, cosa si fa con gli accordi di passaggio?", opts: ["Li si traspone all'ottava", "Li si elimina — non fanno parte della struttura profonda", "Li si sposta sul tempo forte", "Li si sostituisce con accordi di settima"], a: 1, fb: "Nella riduzione, gli accordi di passaggio vengono eliminati perché non appartengono alla struttura profonda. Si conservano solo i pilastri strutturali (inizio, cadenze) e i loro prolungamenti diretti." },
  { q: "Qual è il limite dell'analisi puramente di superficie (accordo per accordo)?", opts: ["È troppo semplice per i musicisti avanzati", "Non rivela la logica tonale profonda e può mascherare la struttura direzionale del pezzo", "Non esiste — l'analisi di superficie è il solo metodo valido", "Produce sempre errori armonici"], a: 1, fb: "L'analisi accordo per accordo rimane in superficie: può mancare i prolungamenti e i grandi archi funzionali. La struttura profonda (T→D→T su un'intera opera) è invisibile se ci si ferma alla superficie." },
  { q: "Perché la distinzione superficie/struttura è pedagogicamente importante?", opts: ["Per semplificare l'apprendimento", "Per comprendere che non tutti gli accordi hanno la stessa importanza e sviluppare una lettura gerarchica", "Per evitare di analizzare certi accordi difficili", "Per memorizzare più facilmente le progressioni"], a: 1, fb: "La distinzione superficie/struttura sviluppa il pensiero gerarchico: lo studente comprende che la ricchezza dell'armonia di superficie serve una struttura più semplice e profonda. È uno strumento di comprensione, non di semplificazione." },

  // ── 4. L'Urlinie ─────────────────────────────────────────────────────
  { q: "Che cos'è l'Urlinie secondo Schenker?", opts: ["La linea fondamentale del basso", "La linea melodica fondamentale discendente del soprano, da 3̂/5̂/8̂ verso 1̂", "La linea del tenore in un corale", "La melodia principale dell'opera"], a: 1, fb: "L'Urlinie ('linea fondamentale') è la discesa melodica fondamentale del soprano, che parte da 3̂, 5̂ o 8̂ e scende diatonicamente fino a 1̂ (tonica). È la struttura melodica profonda che ogni melodia tonale realizza, secondo Schenker." },
  { q: "Quali sono le tre forme possibili dell'Urlinie?", opts: ["1̂–2̂–3̂, 3̂–4̂–5̂, 5̂–6̂–7̂", "3̂–2̂–1̂, 5̂–4̂–3̂–2̂–1̂, 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "Do–Re–Mi, Sol–La–Si, Mi–Fa–Sol", "I–V–I, I–IV–I, I–II–I"], a: 1, fb: "Schenker riconosce tre Urlinien: 3̂–2̂–1̂ (discesa di terza), 5̂–4̂–3̂–2̂–1̂ (discesa di quinta) e 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (discesa di ottava). Ogni grande melodia tonale realizza una di queste tre forme." },
  { q: "Nell'Urlinie 3̂–2̂–1̂ in Do maggiore, quale nota corrisponde a 3̂?", opts: ["Do", "Re", "Mi", "Sol"], a: 2, fb: "In Do maggiore, 3̂ è Mi (3° grado della scala). L'Urlinie 3̂–2̂–1̂ discende Mi–Re–Do. Mi è il Kopfton (nota di testa) che avvia la linea fondamentale." },
  { q: "Nell'Urlinie 5̂–4̂–3̂–2̂–1̂ in Sol maggiore, quale è la nota d'inizio?", opts: ["Sol", "Re", "Si", "La"], a: 1, fb: "In Sol maggiore, 5̂ è Re (quinta di Sol). L'Urlinie 5̂–4̂–3̂–2̂–1̂ discende Re–Do–Si–La–Sol. Re è il Kopfton (nota di testa) che avvia la discesa fondamentale." },
  { q: "Perché l'Urlinie discende sempre verso 1̂?", opts: ["Per convenzione arbitraria di Schenker", "Perché 1̂ (tonica) è il punto di risoluzione e di riposo di tutta la tensione melodica tonale", "Perché le voci di soprano scendono sempre", "Per evitare le quinte parallele"], a: 1, fb: "1̂ è la tonica — il punto di risoluzione finale di ogni tensione. Nella logica tonale, ogni tensione melodica deve risolvere sulla tonica. L'Urlinie materializza questa risoluzione obbligatoria alla scala dell'intera opera." },
  { q: "Come si localizza il Kopfton (nota di testa, inizio dell'Urlinie) in una melodia?", opts: ["È la nota più acuta della melodia", "È la nota strutturalmente predominante all'inizio, armonizzata da I, dalla quale la discesa fondamentale prende avvio", "È la prima nota della melodia", "È la nota più lunga"], a: 1, fb: "Il Kopfton è la nota strutturale d'apertura (3̂, 5̂ o 8̂) che appartiene all'accordo tonico iniziale e dalla quale inizia la discesa dell'Urlinie. Non è necessariamente la prima nota né la più alta." },
  { q: "Nella melodia Mi–Fa–Mi–Re–Do (Do maggiore), quale è l'Urlinie probabile?", opts: ["5̂–4̂–3̂–2̂–1̂", "3̂–2̂–1̂ con Mi come Kopfton", "8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "Nessuna Urlinie — la melodia è troppo ornamentale"], a: 1, fb: "Mi è 3̂ in Do maggiore. La melodia Mi–Fa–Mi–Re–Do realizza l'Urlinie 3̂–2̂–1̂ (Mi–Re–Do) con Fa come nota di bordura ornamentale. Il Kopfton è Mi, e la discesa strutturale è 3̂(Mi)–2̂(Re)–1̂(Do)." },
  { q: "L'Urlinie è sempre direttamente udibile nella melodia di superficie?", opts: ["Sì — corrisponde sempre alla melodia esatta", "No — è spesso ornamentata, spostata all'ottava o interrotta da note estranee di superficie", "No — appartiene sempre al basso", "Sì — ma solo nella musica di Bach"], a: 1, fb: "L'Urlinie è un'astrazione della melodia di superficie — è ornamentata, prolungata, interrotta. La melodia reale è una realizzazione di superficie di questa struttura profonda. Bisogna 'sentire attraverso' la superficie per estrarla." },
  { q: "Cosa significa '2̂ armonizzato da V' nell'Urlinie?", opts: ["Il 2° grado è suonato dalla voce del tenore", "La nota 2̂ coincide con l'accordo di dominante nella struttura profonda", "Il 2° grado viene suonato due volte", "L'accordo V è al secondo rivolto"], a: 1, fb: "Nell'Urlinie, ogni nota fondamentale è armonizzata da un accordo strutturale: 2̂ coincide con V (dominante) e 1̂ con I (tonica). È la congiunzione dell'Urlinie e della Bassbrechung che forma l'Ursatz." },
  { q: "Perché Schenker dice che ogni grande melodia tonale realizza l'Urlinie?", opts: ["Perché tutte le melodie sono identiche", "Perché la logica tonale esige la risoluzione di ogni tensione verso la tonica — l'Urlinie è l'espressione melodica universale di questa legge", "Perché ha analizzato tutte le melodie esistenti", "Perché i compositori copiano tutti lo stesso modello"], a: 1, fb: "Per Schenker, la logica tonale è universale: ogni tensione deve risolvere verso 1̂. L'Urlinie non è uno schema imposto dall'esterno ma la conseguenza inevitabile della tonalità stessa." },

  // ── 5. La Bassbrechung ────────────────────────────────────────────────
  { q: "Che cos'è la Bassbrechung?", opts: ["La linea melodica discendente del soprano", "L'arco di basso I–V–I che struttura la tonalità alla scala dell'intera opera", "Una tecnica di basso continuo barocca", "La cifratura del basso in un corale"], a: 1, fb: "La Bassbrechung ('arpeggio di basso') è l'arco fondamentale I–V–I al basso, che descrive il movimento di quinta fondamentale dell'armonia tonale: dalla tonica alla dominante, poi ritorno alla tonica." },
  { q: "Qual è il basso fondamentale della Bassbrechung in Do maggiore?", opts: ["Do–Fa–Do", "Do–Sol–Do", "Do–Re–Do", "Do–La–Do"], a: 1, fb: "La Bassbrechung in Do maggiore è Do–Sol–Do (I–V–I). Sol è la dominante — la quinta della scala. L'arco Do→Sol→Do rappresenta il movimento di quinta fondamentale della tonalità." },
  { q: "La Bassbrechung copre una frase, una sezione o un'intera opera?", opts: ["Solo una frase di 4 battute", "Può estendersi a qualsiasi scala — dalla frase all'intera opera", "Solo forme brevi (canzone)", "Si applica solo ai corali di Bach"], a: 1, fb: "La Bassbrechung è scalabile: può strutturare una frase (bb. 1–4), una sezione (bb. 1–16), un intero movimento o una sinfonia completa. Questo carattere frattale rende l'analisi schenkeriana universale." },
  { q: "Come si relaziona la Bassbrechung all'Urlinie nell'Ursatz?", opts: ["Sono indipendenti", "La Bassbrechung (basso I–V–I) sostiene l'Urlinie (soprano 3̂–2̂–1̂) — insieme formano l'Ursatz", "L'Urlinie è la versione melodica della Bassbrechung", "La Bassbrechung sostituisce l'Urlinie in modo minore"], a: 1, fb: "Nell'Ursatz, l'Urlinie (soprano) e la Bassbrechung (basso) sono sovrapposte: 3̂ su I, 2̂ su V, 1̂ su I. Questo contrappunto a due voci è la struttura fondamentale universale della musica tonale secondo Schenker." },
  { q: "Cosa rappresenta il V intermedio nella Bassbrechung I–V–I?", opts: ["Una tonicizzazione momentanea", "Il punto di tensione massima — la dominante che struttura la progressione verso la risoluzione finale su I", "Un accordo di passaggio senza importanza", "La sottodominante al rivolto"], a: 1, fb: "V in I–V–I è il vertice di tensione della Bassbrechung — rappresenta il movimento di quinta discendente fondamentale della tonalità (quinta I→V o quarta ascendente). La sua risoluzione su I conclude l'arco tonale." },
  { q: "In una fuga di Bach di 100 battute, dove si trova generalmente il V della Bassbrechung?", opts: ["Solo alla battuta 2", "Al punto strutturale centrale dell'opera, spesso alla grande cadenza intermedia", "Alla fine di ogni frase", "Non c'è Bassbrechung nelle fughe"], a: 1, fb: "In una grande forma, il V strutturale della Bassbrechung coincide con il punto di tensione massima dell'opera — spesso la grande cadenza su V a metà percorso. Tutto ciò che precede prolunga I (andata); tutto ciò che segue prolunga il ritorno a I." },
  { q: "La Bassbrechung è analoga a quale principio formale nella forma sonata?", opts: ["L'esposizione e la ricapitolazione", "La presentazione → tensione (sviluppo) → risoluzione (ricapitolazione), ovvero I→V→I su grande scala", "Il tema principale soltanto", "La coda finale"], a: 1, fb: "La forma sonata realizza la Bassbrechung su grande scala: esposizione in I (spesso con 2° tema in V), sviluppo (tensione armonica), ricapitolazione in I. Questa struttura tonale I–V–I è la Bassbrechung dell'intera opera." },
  { q: "In minore, la Bassbrechung è Im–Vm–Im o Im–V–Im?", opts: ["Im–Vm–Im (minore alla dominante)", "Im–V–Im (dominante maggiore, con sensibile elevata)", "Im–bVII–Im", "Im–IV–Im"], a: 1, fb: "In minore, la dominante è sempre V maggiore (con sensibile elevata). La Bassbrechung è quindi Im–V–Im: si usa il minore armonico alla dominante per conservare la massima tensione della sensibile verso la tonica." },
  { q: "Quale intervallo di basso caratterizza il movimento I→V nella Bassbrechung?", opts: ["Terza ascendente", "Quinta discendente (o quarta ascendente) — il movimento fondamentale dell'armonia tonale", "Seconda ascendente", "Sesta discendente"], a: 1, fb: "I→V corrisponde a una quinta discendente (Do→Sol in Do maggiore) o quarta ascendente. È il movimento più potente dell'armonia tonale — crea la tensione massima che richiede la risoluzione V→I." },
  { q: "Schenker considera la Bassbrechung come:", opts: ["Uno schema opzionale per analizzare il basso", "Il movimento di basso universale di tutta la musica tonale — l'arco fondamentale del contrappunto a due voci", "Una regola applicabile solo a Bach", "Una semplificazione pedagogica senza valore analitico"], a: 1, fb: "Per Schenker, la Bassbrechung è una legge universale: tutta la musica tonale realizza il movimento I–V–I al basso, a qualunque scala. È la fondazione armonica dell'Ursatz." },

  // ── 6. L'Ursatz ─────────────────────────────────────────────────────
  { q: "Che cos'è l'Ursatz secondo Schenker?", opts: ["La struttura ritmica fondamentale", "La struttura contrappuntistica fondamentale = Urlinie (soprano) + Bassbrechung (basso)", "La scala fondamentale di ogni tonalità", "Il motivo tematico principale di un'opera"], a: 1, fb: "L'Ursatz ('struttura fondamentale') è la sovrapposizione dell'Urlinie (discesa del soprano 3̂–2̂–1̂) e della Bassbrechung (arco di basso I–V–I). È un contrappunto a due voci che sottende tutta la musica tonale." },
  { q: "Di quanti strati è composto l'Ursatz?", opts: ["Uno solo — la melodia principale", "Due — soprano (Urlinie) e basso (Bassbrechung)", "Tre — soprano, contralto, basso", "Quattro — le quattro voci SATB"], a: 1, fb: "L'Ursatz è un contrappunto a due voci: l'Urlinie al soprano e la Bassbrechung al basso. Queste due voci fondamentali sono sufficienti a definire la struttura tonale profonda di qualsiasi opera." },
  { q: "Nell'Ursatz, come sono allineate l'Urlinie e la Bassbrechung?", opts: ["Sono indipendenti e non si incrociano mai", "3̂ coincide con I (basso), 2̂ con V (basso), 1̂ con I (basso)", "5̂ coincide con V (basso), 3̂ con IV, 1̂ con I", "Si alternano senza mai sincronizzarsi"], a: 1, fb: "L'allineamento canonico dell'Ursatz: Kopfton (3̂/5̂/8̂) su I, poi il movimento intermedio (2̂ su V), poi la risoluzione (1̂ su I). Questa sovrapposizione crea il contrappunto fondamentale della musica tonale." },
  { q: "Perché Schenker dice che tutta la musica tonale è un 'prolungamento dell'Ursatz'?", opts: ["Perché tutti i compositori copiano lo stesso schema", "Perché ogni composizione tonale è un'elaborazione di questa semplice struttura fondamentale — gli ornamenti di superficie sviluppano l'Ursatz", "Perché l'Ursatz è imposto dal conservatorio", "Perché l'Ursatz è la sola struttura udibile"], a: 1, fb: "L'Ursatz è la struttura più profonda e semplice — ogni composizione tonale la elabora attraverso strati successivi di prolungamento. Gli ornamenti di superficie sono realizzazioni sempre più complesse di questo arco fondamentale." },
  { q: "L'Ursatz si applica alla musica atonale del XX secolo?", opts: ["Sì — Schenker lo applica a tutta la musica", "No — l'Ursatz presuppone la tonalità; la musica atonale non segue i suoi principi", "Sì ma con modifiche", "No — si applica solo a Bach"], a: 1, fb: "L'Ursatz presuppone la tonalità: Urlinie discendente verso 1̂ e Bassbrechung I–V–I. La musica atonale, che rifiuta la gerarchia dei gradi, non può essere analizzata in questo quadro. È un limite esplicito del sistema schenkeriano." },
  { q: "Qual è la versione completa dell'Ursatz con l'Urlinie 5̂–4̂–3̂–2̂–1̂?", opts: ["5̂ su I, 4̂ su IV, 3̂ su I, 2̂ su V, 1̂ su I", "5̂ su I, discesa 4̂–3̂ prolungata, 2̂ su V, 1̂ su I", "5̂ su V, 4̂ su IV, 3̂ su III, 2̂ su II, 1̂ su I", "5̂ su I, 4̂–3̂–2̂ ornamentali, 1̂ su V"], a: 1, fb: "Nell'Urlinie di quinta discendente, i gradi 4̂ e 3̂ sono spesso prolungati da movimenti armonici intermedi, ma i punti d'ancoraggio strutturali sono 5̂ su I, 2̂ su V e 1̂ su I — formando l'Ursatz completo." },
  { q: "L'Ursatz ha un solo modello o più varianti?", opts: ["Un unico modello per tutta la musica", "Tre varianti secondo il Kopfton (3̂, 5̂ o 8̂)", "Un numero infinito di varianti secondo il compositore", "Due varianti (maggiore e minore)"], a: 1, fb: "Schenker riconosce tre forme di Ursatz secondo il Kopfton: 3̂–2̂–1̂ (più semplice), 5̂–4̂–3̂–2̂–1̂ (molto frequente), 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (più rara). La Bassbrechung rimane I–V–I in tutti e tre i casi." },
  { q: "Come si manifesta l'Ursatz su grande scala in una sinfonia?", opts: ["Solo nel 1° movimento", "La tonalità principale su I si prolunga fino al V strutturale (spesso nello sviluppo), poi ritorna a I alla fine", "È visibile solo a livello delle frasi", "Si manifesta solo nel basso continuo"], a: 1, fb: "In una sinfonia, l'Ursatz si estende sull'intera opera: l'inizio si ancora su I, il punto di tensione massima (spesso sviluppo o cadenza centrale) realizza V, e la conclusione ritorna a I. La Bassbrechung I–V–I struttura l'intera opera." },
  { q: "Cosa sono il 'Vordergrund', il 'Mittelgrund' e l'Hintergrund nell'analisi schenkeriana?", opts: ["Tre strumenti diversi", "I tre strati di analisi: superficie (Vordergrund), strato intermedio (Mittelgrund), struttura profonda (Hintergrund = Ursatz)", "Tre parti di una fuga", "Tre tipi di cadenze"], a: 1, fb: "Schenker usa questi tre livelli: Vordergrund (primo piano = musica di superficie così come è scritta), Mittelgrund (piano intermedio = prolungamenti raggruppati), Hintergrund (sfondo = solo l'Ursatz). La riduzione procede dal Vordergrund verso l'Hintergrund." },
  { q: "Qual è il contributo principale della teoria dell'Ursatz all'analisi musicale?", opts: ["Permette di memorizzare più facilmente le partiture", "Rivela la struttura tonale profonda comune a tutte le grandi opere e spiega la loro coerenza su grande scala", "Semplifica la notazione musicale", "Sostituisce l'analisi armonica tradizionale accordo per accordo"], a: 1, fb: "L'Ursatz permette di comprendere la coerenza tonale su grande scala: perché un'opera di 300 battute 'tiene insieme'. Rivela che la complessità di superficie maschera una struttura fondamentale semplice e universale." },

  // ── 7. Riduzione a strati ───────────────────────────────────────────
  { q: "Quante fasi comporta una riduzione schenkeriana completa?", opts: ["1 fase — passare direttamente all'Ursatz", "Almeno 3 strati: superficie (Vordergrund) → intermedio (Mittelgrund) → profondo (Hintergrund)", "5 fasi fisse identiche per ogni analisi", "2 fasi — accordi pari e accordi dispari"], a: 1, fb: "La riduzione schenkeriana procede per strati successivi: Vordergrund (superficie) → Mittelgrund(s) (strati intermedi, a volte più di uno) → Hintergrund (Ursatz). Il numero di strati intermedi dipende dalla complessità dell'opera." },
  { q: "Cosa si fa per prima cosa in una riduzione a strati?", opts: ["Identificare subito l'Urlinie", "Scrivere tutti gli accordi della partitura (armonia di superficie)", "Ridurre all'Ursatz", "Analizzare le modulazioni"], a: 1, fb: "Il primo passo è scrivere l'armonia di superficie completa — tutti gli accordi così come appaiono. Questo è il Vordergrund: il punto di partenza prima di qualsiasi riduzione. Non si saltano le fasi." },
  { q: "Che cos'è una riduzione di strato intermedio (Mittelgrund)?", opts: ["Un'analisi che conserva tutti gli accordi di superficie", "Un'analisi che raggruppa gli accordi di superficie per funzioni ed elimina gli ornamenti, rivelando i prolungamenti principali", "Un'analisi solo melodica", "Una riduzione che conserva solo I e V"], a: 1, fb: "Il Mittelgrund è uno strato intermedio in cui si eliminano gli accordi di passaggio e di bordura, raggruppando gli accordi di superficie per funzione. Si ottiene una visione dei prolungamenti principali senza arrivare all'Ursatz completo." },
  { q: "Come si decide che un accordo è 'eliminabile' nella riduzione?", opts: ["Eliminando gli accordi minori", "Eliminando gli accordi che non hanno un ruolo funzionale autonomo — accordi di passaggio, bordure, ornamenti", "Eliminando tutti gli accordi sui tempi deboli", "Eliminando i rivolti"], a: 1, fb: "Un accordo è eliminabile se non ha un ruolo funzionale indipendente: accordo di passaggio tra due pilastri, accordo di bordura, accordo ornamentale. La sua rimozione non cambia la logica tonale fondamentale." },
  { q: "Nella riduzione di I–IV–I6–V7–I, quale sarebbe la versione ridotta allo strato intermedio?", opts: ["I–I6–V7–I", "I–IV–V–I", "I–V–I", "I–V7–I"], a: 3, fb: "I–IV–V7–I è una riduzione intermedia ragionevole: si conservano I, IV (SD), V7 (D) e I. I6 viene eliminato perché è un prolungamento di I (stesso accordo al rivolto). La riduzione profonda sarebbe I–V–I (Bassbrechung)." },
  { q: "La riduzione a strati rivela quale tipo di struttura?", opts: ["Solo la struttura ritmica", "La struttura gerarchica: dalla complessità di superficie alla semplicità fondamentale", "La struttura contrappuntistica di ogni voce", "La struttura modale dell'opera"], a: 1, fb: "La riduzione a strati rivela la gerarchia armonica: a ogni strato la struttura diventa più semplice e più fondamentale. La complessità di superficie (Vordergrund) si risolve in prolungamenti (Mittelgrund) e poi nell'Ursatz (Hintergrund)." },
  { q: "Cosa rivela la differenza tra Vordergrund e Hintergrund?", opts: ["Gli errori armonici del compositore", "La ricchezza degli ornamenti e dei prolungamenti che sviluppano la struttura fondamentale — è il 'contenuto' dell'opera", "I passi copiati da altri compositori", "Le difficoltà tecniche del pezzo"], a: 1, fb: "La differenza tra superficie e struttura profonda mostra come il compositore 'veste' l'Ursatz: i prolungamenti, gli ornamenti e gli sviluppi che danno a ogni opera la sua personalità unica pur riposando sulla stessa struttura fondamentale." },
  { q: "Si può ridurre un brano a strati senza conoscere la tonalità?", opts: ["Sì — la riduzione è indipendente dalla tonalità", "No — la tonalità è il quadro indispensabile per identificare le funzioni e i pilastri", "Sì, se si conserva solo il basso", "Sì, ma solo per il Vordergrund"], a: 1, fb: "La riduzione schenkeriana presuppone la tonalità: identificare T, SD, D e i loro prolungamenti richiede di conoscere la tonalità. Senza questo quadro, non si può distinguere accordo strutturale da accordo ornamentale." },
  { q: "Come si applica la nozione di strati a una frase di 8 battute?", opts: ["Ogni battuta è uno strato distinto", "Superficie: tutti gli accordi delle 8 battute. Intermedio: I–IV–V–I (pilastri). Profondo: I–V–I (Ursatz)", "La frase di 8 battute non ha struttura a strati", "Gli strati si applicano solo ai movimenti interi"], a: 1, fb: "Anche una breve frase di 8 battute può essere analizzata a strati: superficie (tutti gli accordi), intermedio (pilastri funzionali T–SD–D–T), profondo (Ursatz I–V–I). È il principio frattale dell'analisi schenkeriana." },
  { q: "Qual è l'utilità pratica della riduzione a strati per un compositore?", opts: ["Nessuna — è solo per l'analisi teorica", "Comprendere la struttura profonda per scrivere opere lunghe coerenti e pianificare la traiettoria armonica su grande scala", "Semplificare la scrittura usando solo I e V", "Evitare gli accordi complessi"], a: 1, fb: "La riduzione a strati aiuta il compositore a pianificare la grande forma: qual è la Bassbrechung dell'opera? Quando arriva il V strutturale? Come i prolungamenti intermedi sviluppano l'Ursatz? È uno strumento di composizione tanto quanto di analisi." },

  // ── 8. Esempi Bach/Mozart ────────────────────────────────────────────
  { q: "Nel Preludio in Do maggiore BWV 846 di Bach (arpeggi), la struttura armonica di superficie è:", opts: ["Solo I per tutta la durata del pezzo", "Una successione di accordi arpeggiati mutevoli su un piano armonico funzionale T→SD→D→T", "Un'improvvisazione senza struttura", "Una serie di modulazioni nelle tonalità vicine"], a: 1, fb: "Il Preludio BWV 846 realizza una progressione armonica funzionale completa attraverso gli arpeggi: la struttura di superficie è ricca ma la struttura profonda è una semplice progressione T→SD→D→T che realizza l'Ursatz." },
  { q: "In un corale di Bach, le cadenze interne servono principalmente a:", opts: ["Cambiare tonalità definitivamente", "Articolare la struttura in frasi e sezioni, creando pilastri armonici intermedi nella riduzione", "Evitare le quinte parallele", "Introdurre nuove voci"], a: 1, fb: "Le cadenze interne (semicadenze, cadenze imperfette) di un corale di Bach articolano la struttura: creano punti d'ancoraggio intermedi nella riduzione, rivelando la gerarchia delle cadenze (intermedie vs. finale)." },
  { q: "Nella Sonata K.331 di Mozart (tema con variazioni), la struttura armonica del tema è:", opts: ["Complessa e modulante dalla 1ª frase", "Semplice — I prolungata (bb. 1–4), poi V (bb. 5–8), risoluzione su I (bb. 9–16): Bassbrechung chiara", "Solo su IV e V alternati", "Senza struttura funzionale chiara"], a: 1, fb: "Il tema di K.331 realizza la Bassbrechung in 16 battute: presentazione su I (bb. 1–8), tensione su V (bb. 9–14), risoluzione I (bb. 15–16). La struttura è un modello di economia tonale." },
  { q: "In una fuga di Bach in Do maggiore, quando il soggetto entra in Sol maggiore (V), questo rappresenta:", opts: ["Una modulazione definitiva in Sol maggiore", "La risposta tonale — una tonicizzazione di V che si inscrive nella Bassbrechung I→V", "Un errore di scrittura contrappuntistica", "L'esposizione del controsoggetto"], a: 1, fb: "La risposta in V in una fuga realizza il primo movimento della Bassbrechung: I→V. La fuga 'modula' verso V ma è una tonicizzazione che si inscrive nell'arco fondamentale I–V–I dell'intera fuga." },
  { q: "Nel 1° movimento della Sinfonia n. 40 KV550 di Mozart, il 2° tema in Sib maggiore rappresenta:", opts: ["Una modulazione definitiva e indipendente", "La tonicizzazione del III (relativo maggiore del minore) — movimento armonico dell'esposizione verso la 'dominante' strutturale", "Un errore di tonalità di Mozart", "L'inizio della ricapitolazione"], a: 1, fb: "In Sol minore, il 2° tema in Sib (bIII = relativo maggiore) rappresenta il movimento strutturale dell'esposizione verso la zona della dominante. Nella Bassbrechung in minore, bIII svolge spesso il ruolo di dominante strutturale dell'esposizione." },
  { q: "In un minuetto di Haydn di 16 battute, la cadenza su V alla battuta 8 rappresenta:", opts: ["La fine dell'opera", "Il V strutturale della Bassbrechung — punto di tensione mediano prima del ritorno a I alla fine", "Una modulazione definitiva in Sol", "Un incidente armonico non pianificato"], a: 1, fb: "La cadenza su V a metà percorso è tipica della forma periodo: il V della battuta 8 è il V strutturale della Bassbrechung. Tutto ciò che segue (bb. 9–16) prolunga il ritorno all'I finale — è la seconda metà dell'arco I–V–I." },
  { q: "Nella Ciaccona BWV 1004 di Bach (basso ostinato), la Bassbrechung si estende su:", opts: ["Ogni ripetizione del basso soltanto", "L'intera opera — le 64 variazioni prolungano un unico Ursatz dalla prima all'ultima battuta", "Solo le prime 4 variazioni", "Il basso ostinato non ha Bassbrechung"], a: 1, fb: "La Ciaccona di Bach realizza un Ursatz alla scala dell'intera opera: le 64 variazioni sono un prolungamento monumentale di I–V–I. Il basso ostinato è esso stesso un prolungamento della Bassbrechung fondamentale." },
  { q: "Come si analizza un corale di Bach di 4 battute con il metodo di riduzione?", opts: ["Conservare tutti gli accordi e numerarli", "1) annotare tutti gli accordi, 2) localizzare apertura (T), cadenza mediana (V o II6–V), cadenza finale (V–I), 3) ridurre alla Bassbrechung I–V–I", "Semplificare a I–IV–V–I soltanto", "Identificare solo i rivolti"], a: 1, fb: "Il metodo in 3 fasi: 1) superficie completa, 2) pilastri funzionali (apertura T, cadenze intermedie e finale), 3) Bassbrechung I–V–I. Questo approccio evita l'analisi puramente accordo per accordo e rivela la struttura profonda." },
  { q: "In Mozart K.545 (Sonata in Do maggiore, inizio), le prime 4 battute prolungano:", opts: ["Solo V", "I (tonica) attraverso armonie di superficie variate (I–V6–I–IV6–I6/4–V–I)", "Solo IV", "La sottodominante"], a: 1, fb: "Le bb. 1–4 di K.545 prolungano I (tonica): le armonie di superficie (V6, IV6, I6/4–V–I) ornano e cadenzano la tonica. La struttura profonda di queste 4 battute è un I prolungato — un Kopfton sospeso prima del movimento reale verso V." },
  { q: "Perché Bach e Mozart sono i compositori di riferimento per l'analisi schenkeriana?", opts: ["Perché usavano esattamente le stesse formule", "Perché la loro scrittura tonale è esemplare: struttura profonda semplice, prolungamenti elaborati, logica armonica irreprensibile", "Perché Schenker li conosceva personalmente", "Perché la loro musica è la più difficile da analizzare"], a: 1, fb: "Bach e Mozart sono modelli perché la loro scrittura tonale realizza perfettamente l'Ursatz: dietro una superficie di grande ricchezza, la struttura profonda è di esemplare chiarezza e logica. Illustrano idealmente i principi schenkeriani." },

  // ── 9. Applicazione pratica ────────────────────────────────────────────
  { q: "Nella progressione Do–Sol–La–Fa–Sol–Do (basso, Do maggiore), qual è l'accordo strutturale di dominante?", opts: ["La (VI)", "Fa (IV)", "Sol (V) — le due occorrenze", "Do (I)"], a: 2, fb: "Sol (V) è l'accordo strutturale di dominante. Le due occorrenze di Sol possono prolungare V prima della risoluzione finale su I. Do = T, La = T prolungata (VI), Fa = SD, Sol = D, Do = T: progressione T–T–SD–D–T." },
  { q: "Si analizzano 8 battute. La struttura è I–IV–I6–V6–I–II6–V7–I. Quali sono i pilastri strutturali?", opts: ["Tutti gli 8 accordi sono pilastri", "I (inizio), V (cadenza mediana o dominante), I (conclusione) — gli altri sono prolungamenti", "Solo I, IV, V7, I", "I6, V6, II6, I"], a: 1, fb: "I pilastri strutturali sono I (apertura), V/V7 (dominante) e I (conclusione). IV, I6, V6 e II6 sono prolungamenti o ornamenti funzionali. La Bassbrechung sottostante è I–V–I." },
  { q: "Si dà la melodia Mi–Re–Do in 3 battute (Do maggiore, armonizzata da I–V–I). È un esempio di:", opts: ["Solo Bassbrechung", "Urlinie 3̂–2̂–1̂ armonizzata dall'Ursatz I–V–I — un esempio perfetto di struttura fondamentale", "Prolungamento di V", "Cadenza imperfetta"], a: 1, fb: "Mi–Re–Do (3̂–2̂–1̂) su I–V–I è l'esempio più puro dell'Ursatz: l'Urlinie di terza discende da 3̂ a 1̂ sostenuta dalla Bassbrechung I–V–I. È il modello di base che Schenker illustra nel Der freie Satz." },
  { q: "Come si determina se una modulazione è strutturale o ornamentale in un brano?", opts: ["Tutte le modulazioni sono strutturali", "Se la nuova tonalità è confermata da una cadenza V–I e mantenuta per una sezione significativa, è strutturale; altrimenti è una tonicizzazione ornamentale", "Una modulazione è sempre ornamentale", "Se la modulazione dura più di 2 battute, è strutturale"], a: 1, fb: "La distinzione chiave: tonicizzazione (momentanea, pochi accordi) vs. modulazione strutturale (confermata da V–I, mantenuta su una sezione). Nell'analisi a strati, le tonicizzazioni scompaiono al Mittelgrund; solo le modulazioni strutturali permangono." },
  { q: "In un'analisi pratica, da dove si comincia?", opts: ["Dall'ultima battuta", "Identificando la tonalità, poi localizzando la cadenza finale (V–I), poi risalendo verso l'inizio", "Dalle note più acute", "Analizzando ogni accordo da sinistra a destra senza un ordine particolare"], a: 1, fb: "Iniziare dalla tonalità e dalla cadenza finale è la strategia schenkeriana: la cadenza finale (V–I) è il V e l'I della Bassbrechung. Si risale poi per trovare come la struttura profonda si dispiega dall'apertura." },
  { q: "Quale di queste analisi di I–VI–II–V–I è corretta?", opts: ["I=D, VI=T, II=SD, V=D, I=T", "I=T, VI=T (prolungamento), II=SD, V=D, I=T", "I=T, VI=SD, II=D, V=T, I=D", "I=SD, VI=D, II=T, V=SD, I=T"], a: 1, fb: "I=T, VI=T (VI appartiene alla regione tonica), II=SD, V=D, I=T. La progressione realizza T(prolungata da VI)–SD–D–T. L'analisi corretta identifica VI come appartenente alla regione tonica, non a un'altra funzione." },
  { q: "Si deve ridurre I–I6–IV–II6–I6/4–V7–I allo strato intermedio. Qual è il risultato?", opts: ["I–IV–II6–V7–I", "I–IV–V7–I (o I–II6–V7–I)", "I–I6/4–V7–I", "Solo I–V–I"], a: 1, fb: "Nello strato intermedio, I6 (prolungamento di I) viene eliminato, IV o II6 (SD) sono conservati, I6/4 (prolungamento di V) a volte eliminato. Il risultato tipico è I–IV–V7–I o I–II6–V7–I — la struttura funzionale T–SD–D–T senza ornamenti." },
  { q: "Qual è la migliore analisi di superficie per Do–Sol–Mi–Do (basso ascendente, Do maggiore)?", opts: ["I–V–I6–I (arpeggio di I)", "I–V–III–I (4 accordi diversi)", "I prolungato per arpeggio (I–I6–I6/4–I) — un'unica funzione tonica", "II–V–I–I"], a: 2, fb: "Do–Sol–Mi–Do al basso arpeggia l'accordo di Do maggiore: Do = stato fondamentale, Sol = I6/4 (quinta al basso), Mi = I6 (terza al basso), Do = stato fondamentale. È un prolungamento tonico per arpeggio — un'unica funzione T." },
  { q: "Perché la cadenza V–I è il pilastro finale di ogni Ursatz?", opts: ["Per convenzione arbitraria", "Perché V–I realizza la risoluzione della tensione massima (dominante) verso il riposo (tonica) — la conclusione obbligatoria di ogni logica tonale", "Perché V–I è la cadenza più lunga", "Perché I suona più forte di V"], a: 1, fb: "V–I è la risoluzione fondamentale della logica tonale: la dominante crea tensione massima (tritono in V7, sensibile verso tonica) che solo la tonica può risolvere. È la conclusione inevitabile della Bassbrechung e dell'Urlinie." },
];

const questionsPt: Question[] = [
  // ── 1. Regiões tonais (T/SD/D) ──────────────────────────────────────────
  { q: "Quais graus pertencem à região tônica (T) em Dó maior?", opts: ["I, II, IV", "I, III, VI", "V, VII, II", "IV, VI, III"], a: 1, fb: "A região tônica agrupa os acordes que evocam a estabilidade da tônica: I, III e VI. Esses acordes compartilham duas notas com I (Dó–Mi–Sol) e reforçam a cor de repouso." },
  { q: "Quais graus pertencem à região da subdominante (SD) em Dó maior?", opts: ["I, III, VI", "V, VII", "II, IV", "I, IV, V"], a: 2, fb: "A região da subdominante inclui II e IV. Esses acordes preparam harmonicamente a dominante — criam tensão intermediária entre o repouso (T) e a tensão máxima (D)." },
  { q: "Quais graus pertencem à região da dominante (D) em Dó maior?", opts: ["I, III, VI", "II, IV", "V, VII", "III, V"], a: 2, fb: "A região da dominante agrupa V e VII. Eles carregam a tensão máxima e exigem resolução para a tônica. V7 é o acorde de dominante por excelência; VII é sua versão incompleta." },
  { q: "Na progressão I–VI–II–V–I, a qual região pertence VI?", opts: ["Região da dominante", "Região da subdominante", "Região tônica", "Nenhuma região"], a: 2, fb: "VI (Lá menor em Dó maior) pertence à região tônica porque compartilha duas notas com I (Dó e Mi). Nessa progressão, VI prolonga a tônica antes do movimento para SD (II) e D (V)." },
  { q: "A progressão T–SD–D–T descreve:", opts: ["A regra das quintas paralelas", "A sequência funcional básica da harmonia tonal", "A estrutura do Urlinie", "O princípio da Bassbrechung"], a: 1, fb: "T–SD–D–T é o esquema funcional fundamental da música tonal: partida estável (T), preparação (SD), tensão máxima (D), retorno ao repouso (T). Toda progressão tonal pode ser lida como variante desse modelo." },
  { q: "O acorde II6 (2° grau no primeiro inversão) pertence a qual região funcional?", opts: ["Região tônica", "Região da dominante", "Região da subdominante", "Nenhuma — as inversões mudam a região"], a: 2, fb: "A inversão não muda a região funcional. II (Ré–Fá–Lá) pertence à região da subdominante em estado fundamental ou em primeira inversão. II6 é inclusive a forma preferida de II no estilo clássico antes de V." },
  { q: "Por que IV–V–IV é uma progressão desaconselhada?", opts: ["Porque IV e V não podem se seguir", "Porque esse retrocesso D→SD quebra a lógica direcional SD→D→T", "Porque IV não pertence à escala", "Porque V seguido de IV cria quintas paralelas sistemáticas"], a: 1, fb: "IV–V–IV representa um 'retrocesso' funcional: abandona-se a subdominante para a dominante, depois se volta à subdominante. Essa hesitação quebra a lógica T→SD→D→T e enfraquece a progressão." },
  { q: "Em Sol maior, o acorde de Mi menor (VIm) pertence a:", opts: ["Região da dominante", "Região da subdominante", "Região tônica", "Nenhuma dessas regiões"], a: 2, fb: "Em Sol maior, VI é Mi menor. Pertence à região tônica porque compartilha duas notas com I (Sol e Si de Sol–Si–Ré). Mi–Sol–Si compartilha Sol e Si com Sol maior — é a cor de repouso tônico." },
  { q: "O que é um prolongamento da região tônica?", opts: ["Um acorde estranho à tonalidade", "Uma sequência de acordes que mantém a cor funcional de T sem mudar de região", "A passagem obrigatória por V antes de I", "A repetição literal de I na oitava"], a: 1, fb: "Um prolongamento tônico é um conjunto de acordes (ex. I–VI–I6–I) que permanecem na região T. Ornam e sustentam a cor de repouso da tônica sem movimento funcional real para SD ou D." },
  { q: "Em uma frase de 8 compassos em forma sentence clássica, os compassos 1–4 costumam ser:", opts: ["D–T–D–T", "T prolongada, depois movimento para D", "Apenas SD", "Alternância rápida T/D/T/D"], a: 1, fb: "A sentence clássica começa com uma apresentação (cc. 1–4) que prolonga a tônica, depois uma continuação (cc. 5–8) que desenvolve o movimento SD–D–T até a cadência final. É a estrutura arquetípica de Haydn e Mozart." },

  // ── 2. Prolongamento harmônico ────────────────────────────────────────────
  { q: "O que é prolongamento harmônico?", opts: ["Um acorde tocado muito alto para ser ouvido", "A manutenção de uma função harmônica por vários compassos através de harmonias de superfície mutáveis", "O aumento da duração de todas as notas", "Um acorde sustentado sem mudança por vários compassos"], a: 1, fb: "O prolongamento harmônico é o princípio pelo qual uma função (T, SD ou D) é mantida por vários compassos, mesmo que os acordes de superfície mudem. Ex.: I–I6–I6/4 prolongam todos a função tônica." },
  { q: "A progressão I–VI–I6–I é um exemplo de:", opts: ["Movimento T→SD→D→T", "Prolongamento da região tônica", "Cadência autêntica", "Bassbrechung"], a: 1, fb: "I–VI–I6–I prolonga a região tônica: VI pertence a T (compartilha duas notas com I), I6 é I em inversão. Todos esses acordes mantêm a cor funcional de repouso da tônica." },
  { q: "Em um prolongamento de dominante, qual acorde pode 'ornamentar' V sem o abandonar funcionalmente?", opts: ["IV", "I6/4 (antes de V, o 6/4 cadencial)", "II", "VI"], a: 1, fb: "O 6/4 cadencial (I6/4) em tempo forte prolonga a região da dominante: seu baixo é Sol (quinta de I mas também fundamental de V), e resolve imediatamente em V. Diz-se que I6/4–V forma uma unidade de prolongamento da dominante." },
  { q: "Como se reconhece um prolongamento em uma análise?", opts: ["Todos os acordes têm a mesma duração", "Vários acordes sucessivos compartilham a mesma função regional e servem para ornar ou desenvolver um acorde estrutural", "Todos os acordes estão na mesma oitava", "O baixo não se move"], a: 1, fb: "Um prolongamento se reconhece pela coerência funcional: vários acordes de superfície diferentes que mantêm a mesma região (T, SD ou D). O acorde estrutural é o pilar; os demais são seus ornamentos." },
  { q: "Uma nota pedal no baixo em Sol prolonga:", opts: ["A região tônica somente", "A região da dominante, mantendo a fundamental de V sob harmonias mutáveis", "A região da subdominante", "Nenhuma região precisa"], a: 1, fb: "Um pedal em Sol (dominante) mantém a tensão de V sob harmonias mutáveis. Os acordes que passam acima são ornamentos de superfície — a função estrutural permanece D durante todo o pedal." },
  { q: "Qual é a diferença entre um acorde de passagem e um acorde estrutural?", opts: ["O acorde de passagem é mais longo", "O acorde estrutural é um pilar funcional; o acorde de passagem é um ornamento entre dois pilares", "O acorde estrutural está sempre em estado fundamental", "Não há diferença — todos os acordes são iguais"], a: 1, fb: "O acorde estrutural (pilar) é um ponto de ancoragem funcional na análise em camadas. O acorde de passagem é um ornamento de superfície que conecta dois pilares — não tem peso estrutural independente." },
  { q: "Na sequência I–IV–I6–V–I, quais acordes prolongam a tônica no início?", opts: ["I e IV", "I, IV e I6", "Apenas I", "I e I6"], a: 3, fb: "I e I6 prolongam a tônica (mesmo acorde, inversão diferente). IV pertence a SD — é um movimento para a subdominante, não um prolongamento tônico. Portanto apenas I e I6 prolongam T aqui." },
  { q: "Uma escala ascendente no baixo (Dó–Ré–Mi–Fá) sob um acorde de I prolonga:", opts: ["A dominante", "A tônica por movimento ornamental do baixo", "A subdominante", "Nenhuma região — a escala quebra o prolongamento"], a: 1, fb: "Uma linha de baixo conjunta ascendente (Dó–Ré–Mi–Fá) pode prolongar a tônica: o baixo orna o acorde de I passando por posições intermediárias (I–I6–I6/4 ou com harmonias de passagem). É prolongamento por baixo arpejado ou conjunto." },
  { q: "O conceito de prolongamento é central na análise de:", opts: ["Schoenberg", "Schenker", "Rameau", "Riemann"], a: 1, fb: "Heinrich Schenker (1868–1935) é o teórico que desenvolveu o prolongamento como ferramenta analítica fundamental. Segundo ele, toda a música tonal é um prolongamento do Ursatz (estrutura fundamental)." },
  { q: "Um prolongamento típico de dominante antes de uma cadência final é:", opts: ["V–IV–V", "I6/4–V–V7", "V–VI–V", "I–V–I"], a: 1, fb: "I6/4–V–V7 é um prolongamento clássico da dominante antes da cadência: o 6/4 cadencial prepara V que é amplificado por V7. Toda essa sequência prolonga a região D antes da resolução em I." },

  // ── 3. Harmonia de superfície vs estrutural ────────────────────────────
  { q: "O que é harmonia de superfície?", opts: ["Os acordes tocados na parte superior do piano", "O conjunto de todos os acordes tal como aparecem na partitura", "Os acordes principais da estrutura profunda", "Os acordes sem inversões"], a: 1, fb: "A harmonia de superfície designa todos os acordes tal como aparecem na partitura — cada acorde de passagem, ornamento, nota auxiliar. É a 'superfície' visível da harmonia, antes de qualquer redução analítica." },
  { q: "O que é um acorde estrutural (pilar harmônico)?", opts: ["Um acorde tocado fortíssimo", "Um acorde que ocupa uma posição funcional chave na estrutura profunda da peça", "Um acorde sem inversões", "O acorde mais repetido na peça"], a: 1, fb: "Um acorde estrutural (ou pilar) é um acorde que carrega uma função chave na lógica tonal: ancora uma região (T, SD, D) e faz parte da estrutura profunda que a redução procura revelar." },
  { q: "Como se distingue um acorde de superfície de um acorde estrutural?", opts: ["Apenas pela duração", "Pela sua posição funcional e sua importância para a lógica cadencial da frase", "Pela sua posição no compasso (tempo forte = estrutural)", "Pelo número de notas que contém"], a: 1, fb: "A duração e a posição métrica são indícios mas não critérios absolutos. O acorde estrutural é aquele cuja remoção mudaria a lógica tonal fundamental — é indispensável à progressão cadencial." },
  { q: "Na progressão I–IV–V–I, o acorde IV é estrutural ou de superfície?", opts: ["Sempre de superfície", "Estrutural — articula o movimento SD antes de D", "De superfície — pode ser substituído por II6 sem mudar a estrutura", "Nenhum dos dois — IV não tem nenhum papel harmônico"], a: 1, fb: "IV é um acorde estrutural da região SD: articula o movimento funcional T→SD→D→T. Nesse contexto, sua presença tem significado estrutural. Um IV de passagem entre dois I seria de superfície." },
  { q: "Em I–I6–I6/4–V–I, qual é o verdadeiro acorde estrutural de dominante?", opts: ["I6/4 porque está no tempo forte", "V — I6/4 é um prolongamento ornamental de V (6/4 cadencial)", "I6/4 e V juntos", "Nenhum — todos são de superfície"], a: 1, fb: "V é o acorde estrutural de dominante. I6/4 (6/4 cadencial) é um prolongamento ornamental que 'prepara' V — pertence funcionalmente à região da dominante mas não é o pilar estrutural." },
  { q: "Um acorde de bordadura (nota de bordadura harmonizada) é:", opts: ["Um acorde estrutural por definição", "Um acorde de superfície que orna um acorde estrutural sem mudar sua função", "Um acorde pivô entre duas tonalidades", "Um acorde de passagem modulante"], a: 1, fb: "Um acorde de bordadura é um acorde de superfície: orna um acorde estrutural afastando-se e retornando a ele. Não cria movimento funcional independente — prolonga o acorde estrutural que o envolve." },
  { q: "Como se identificam os pilares estruturais de uma frase de 4 compassos?", opts: ["Tomar todos os acordes nos tempos fortes", "Identificar o acorde de abertura, a cadência mediana e a cadência final — os demais são prolongamentos", "Conservar apenas os acordes de I e V", "Identificar os acordes mais longos"], a: 1, fb: "A estratégia schenkeriana consiste em localizar os pontos de ancoragem cadenciais: início (tônica), cadência mediana (muitas vezes semicadência V), cadência final (V–I). Esses três polos formam o esqueleto estrutural." },
  { q: "Em uma redução, o que se faz com os acordes de passagem?", opts: ["Transpõem-se para a oitava", "Eliminam-se — não fazem parte da estrutura profunda", "Movem-se para o tempo forte", "Substituem-se por acordes de sétima"], a: 1, fb: "Na redução, os acordes de passagem são eliminados porque não pertencem à estrutura profunda. Conservam-se apenas os pilares estruturais (início, cadências) e seus prolongamentos diretos." },
  { q: "Qual é a limitação da análise puramente de superfície (acorde por acorde)?", opts: ["É simples demais para músicos avançados", "Não revela a lógica tonal profunda e pode mascarar a estrutura direcional da peça", "Não existe — a análise de superfície é o único método válido", "Produz sempre erros de harmonia"], a: 1, fb: "A análise acorde por acorde permanece na superfície: pode perder os prolongamentos e os grandes arcos funcionais. A estrutura profunda (T→D→T ao longo de toda uma obra) é invisível se paramos na superfície." },
  { q: "Por que a distinção superfície/estrutura é pedagogicamente importante?", opts: ["Para simplificar o aprendizado", "Para compreender que nem todos os acordes têm a mesma importância e desenvolver uma leitura hierárquica", "Para evitar analisar certos acordes difíceis", "Para memorizar mais facilmente as progressões"], a: 1, fb: "A distinção superfície/estrutura desenvolve o pensamento hierárquico: o aluno compreende que a riqueza da harmonia de superfície serve a uma estrutura mais simples e profunda. É uma ferramenta de compreensão, não de simplificação." },

  // ── 4. O Urlinie ─────────────────────────────────────────────────────
  { q: "O que é o Urlinie segundo Schenker?", opts: ["A linha fundamental do baixo", "A linha melódica fundamental descendente do soprano, de 3̂/5̂/8̂ até 1̂", "A linha do tenor em um coral", "A melodia principal da obra"], a: 1, fb: "O Urlinie ('linha fundamental') é a descida melódica fundamental do soprano, partindo de 3̂, 5̂ ou 8̂ e descendo diatonicamente até 1̂ (tônica). É a estrutura melódica profunda que toda melodia tonal realiza, segundo Schenker." },
  { q: "Quais são as três formas possíveis do Urlinie?", opts: ["1̂–2̂–3̂, 3̂–4̂–5̂, 5̂–6̂–7̂", "3̂–2̂–1̂, 5̂–4̂–3̂–2̂–1̂, 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "Dó–Ré–Mi, Sol–Lá–Si, Mi–Fá–Sol", "I–V–I, I–IV–I, I–II–I"], a: 1, fb: "Schenker reconhece três Urlinien: 3̂–2̂–1̂ (descida de terça), 5̂–4̂–3̂–2̂–1̂ (descida de quinta) e 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (descida de oitava). Toda grande melodia tonal realiza uma dessas três formas." },
  { q: "No Urlinie 3̂–2̂–1̂ em Dó maior, qual nota corresponde a 3̂?", opts: ["Dó", "Ré", "Mi", "Sol"], a: 2, fb: "Em Dó maior, 3̂ é Mi (3° grau da escala). O Urlinie 3̂–2̂–1̂ desce Mi–Ré–Dó. Mi é o Kopfton (nota de cabeça) que inicia a linha fundamental." },
  { q: "No Urlinie 5̂–4̂–3̂–2̂–1̂ em Sol maior, qual é a nota de início?", opts: ["Sol", "Ré", "Si", "Lá"], a: 1, fb: "Em Sol maior, 5̂ é Ré (quinta de Sol). O Urlinie 5̂–4̂–3̂–2̂–1̂ desce Ré–Dó–Si–Lá–Sol. Ré é o Kopfton (nota de cabeça) que inicia a descida fundamental." },
  { q: "Por que o Urlinie desce sempre para 1̂?", opts: ["Por convenção arbitrária de Schenker", "Porque 1̂ (tônica) é o ponto de resolução e repouso de toda tensão melódica tonal", "Porque as vozes de soprano sempre descem", "Para evitar quintas paralelas"], a: 1, fb: "1̂ é a tônica — o ponto de resolução final de toda tensão. Na lógica tonal, toda tensão melódica deve resolver na tônica. O Urlinie materializa essa resolução obrigatória na escala de toda a obra." },
  { q: "Como se localiza o Kopfton (nota de cabeça, início do Urlinie) em uma melodia?", opts: ["É a nota mais aguda da melodia", "É a nota estruturalmente predominante no início, harmonizada por I, a partir da qual a descida fundamental começa", "É a primeira nota da melodia", "É a nota mais longa"], a: 1, fb: "O Kopfton é a nota estrutural de abertura (3̂, 5̂ ou 8̂) que pertence ao acorde de tônica inicial e a partir da qual começa a descida do Urlinie. Não é necessariamente a primeira nota nem a mais alta." },
  { q: "Na melodia Mi–Fá–Mi–Ré–Dó (Dó maior), qual é o Urlinie provável?", opts: ["5̂–4̂–3̂–2̂–1̂", "3̂–2̂–1̂ com Mi como Kopfton", "8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂", "Nenhum Urlinie — a melodia é ornamental demais"], a: 1, fb: "Mi é 3̂ em Dó maior. A melodia Mi–Fá–Mi–Ré–Dó realiza o Urlinie 3̂–2̂–1̂ (Mi–Ré–Dó) com Fá como nota de bordadura ornamental. O Kopfton é Mi, e a descida estrutural é 3̂(Mi)–2̂(Ré)–1̂(Dó)." },
  { q: "O Urlinie é sempre diretamente audível na melodia de superfície?", opts: ["Sim — sempre corresponde à melodia exata", "Não — é frequentemente ornamentado, deslocado para a oitava ou interrompido por notas estranhas de superfície", "Não — pertence sempre ao baixo", "Sim — mas apenas na música de Bach"], a: 1, fb: "O Urlinie é uma abstração da melodia de superfície — é ornamentado, prolongado, interrompido. A melodia real é uma realização de superfície dessa estrutura profunda. É preciso 'ouvir através' da superfície para extraí-lo." },
  { q: "O que significa '2̂ harmonizado por V' no Urlinie?", opts: ["O 2° grau é tocado pela voz do tenor", "A nota 2̂ coincide com o acorde de dominante na estrutura profunda", "O 2° grau é tocado duas vezes", "O acorde V está no segundo inversão"], a: 1, fb: "No Urlinie, cada nota fundamental é harmonizada por um acorde estrutural: 2̂ coincide com V (dominante) e 1̂ com I (tônica). É a conjunção do Urlinie e da Bassbrechung que forma o Ursatz." },
  { q: "Por que Schenker diz que toda grande melodia tonal realiza o Urlinie?", opts: ["Porque todas as melodias são idênticas", "Porque a lógica tonal exige a resolução de toda tensão para a tônica — o Urlinie é a expressão melódica universal dessa lei", "Porque ele analisou todas as melodias existentes", "Porque os compositores copiam todos o mesmo modelo"], a: 1, fb: "Para Schenker, a lógica tonal é universal: toda tensão deve resolver para 1̂. O Urlinie não é um esquema imposto de fora, mas a consequência inevitável da própria tonalidade." },

  // ── 5. A Bassbrechung ────────────────────────────────────────────────
  { q: "O que é a Bassbrechung?", opts: ["A linha melódica descendente do soprano", "O arco de baixo I–V–I que estrutura a tonalidade na escala de toda a obra", "Uma técnica de baixo contínuo barroca", "A cifragem do baixo em um coral"], a: 1, fb: "A Bassbrechung ('arpejo de baixo') é o arco fundamental I–V–I no baixo, que descreve o movimento de quinta fundamental da harmonia tonal: da tônica para a dominante, e volta para a tônica." },
  { q: "Qual é o baixo fundamental da Bassbrechung em Dó maior?", opts: ["Dó–Fá–Dó", "Dó–Sol–Dó", "Dó–Ré–Dó", "Dó–Lá–Dó"], a: 1, fb: "A Bassbrechung em Dó maior é Dó–Sol–Dó (I–V–I). Sol é a dominante — a quinta da escala. O arco Dó→Sol→Dó representa o movimento de quinta fundamental da tonalidade." },
  { q: "A Bassbrechung abrange uma frase, uma seção ou uma obra inteira?", opts: ["Apenas uma frase de 4 compassos", "Pode se estender a qualquer escala — da frase à obra inteira", "Apenas formas curtas (canção)", "Aplica-se apenas aos corais de Bach"], a: 1, fb: "A Bassbrechung é escalável: pode estruturar uma frase (cc. 1–4), uma seção (cc. 1–16), um movimento inteiro ou uma sinfonia completa. Esse caráter fractal torna a análise schenkeriana universal." },
  { q: "Como a Bassbrechung se relaciona com o Urlinie no Ursatz?", opts: ["São independentes", "A Bassbrechung (baixo I–V–I) sustenta o Urlinie (soprano 3̂–2̂–1̂) — juntos formam o Ursatz", "O Urlinie é a versão melódica da Bassbrechung", "A Bassbrechung substitui o Urlinie no modo menor"], a: 1, fb: "No Ursatz, o Urlinie (soprano) e a Bassbrechung (baixo) estão sobrepostos: 3̂ sobre I, 2̂ sobre V, 1̂ sobre I. Esse contraponto a duas vozes é a estrutura fundamental universal da música tonal segundo Schenker." },
  { q: "O que representa o V intermediário na Bassbrechung I–V–I?", opts: ["Uma tonicização momentânea", "O ponto de tensão máxima — a dominante que estrutura a progressão para a resolução final em I", "Um acorde de passagem sem importância", "A subdominante em inversão"], a: 1, fb: "V em I–V–I é o ápice de tensão da Bassbrechung — representa o movimento de quinta descendente fundamental da tonalidade (quinta I→V ou quarta ascendente). Sua resolução em I conclui o arco tonal." },
  { q: "Em uma fuga de Bach de 100 compassos, onde geralmente se situa o V da Bassbrechung?", opts: ["Apenas no compasso 2", "No ponto estrutural central da obra, frequentemente na grande cadência intermediária", "No final de cada frase", "Não há Bassbrechung nas fugas"], a: 1, fb: "Em uma grande forma, o V estrutural da Bassbrechung coincide com o ponto de tensão máxima da obra — muitas vezes a grande cadência em V a meio caminho. Tudo antes prolonga I (ida); tudo depois prolonga o retorno a I." },
  { q: "A Bassbrechung é análoga a qual princípio formal na forma sonata?", opts: ["A exposição e a recapitulação", "A apresentação → tensão (desenvolvimento) → resolução (recapitulação), ou seja I→V→I em grande escala", "O tema principal somente", "A coda final"], a: 1, fb: "A forma sonata realiza a Bassbrechung em grande escala: exposição em I (muitas vezes com 2° tema em V), desenvolvimento (tensão harmônica), recapitulação em I. Essa estrutura tonal I–V–I é a Bassbrechung de toda a obra." },
  { q: "Em menor, a Bassbrechung é Im–Vm–Im ou Im–V–Im?", opts: ["Im–Vm–Im (menor na dominante)", "Im–V–Im (dominante maior, com sensível elevada)", "Im–bVII–Im", "Im–IV–Im"], a: 1, fb: "Em menor, a dominante é sempre V maior (com sensível elevada). A Bassbrechung é portanto Im–V–Im: usa-se o menor harmônico na dominante para conservar a máxima tensão da sensível para a tônica." },
  { q: "Qual intervalo de baixo caracteriza o movimento I→V na Bassbrechung?", opts: ["Terça ascendente", "Quinta descendente (ou quarta ascendente) — o movimento fundamental da harmonia tonal", "Segunda ascendente", "Sexta descendente"], a: 1, fb: "I→V corresponde a uma quinta descendente (Dó→Sol em Dó maior) ou quarta ascendente. É o movimento mais poderoso da harmonia tonal — cria a tensão máxima que exige a resolução V→I." },
  { q: "Schenker considera a Bassbrechung como:", opts: ["Um esquema opcional para analisar o baixo", "O movimento de baixo universal de toda a música tonal — o arco fundamental do contraponto a duas vozes", "Uma regra aplicável apenas a Bach", "Uma simplificação pedagógica sem valor analítico"], a: 1, fb: "Para Schenker, a Bassbrechung é uma lei universal: toda a música tonal realiza o movimento I–V–I no baixo, em qualquer escala. É a fundação harmônica do Ursatz." },

  // ── 6. O Ursatz ─────────────────────────────────────────────────────
  { q: "O que é o Ursatz segundo Schenker?", opts: ["A estrutura rítmica fundamental", "A estrutura contrapontística fundamental = Urlinie (soprano) + Bassbrechung (baixo)", "A escala fundamental de toda tonalidade", "O motivo temático principal de uma obra"], a: 1, fb: "O Ursatz ('estrutura fundamental') é a sobreposição do Urlinie (descida do soprano 3̂–2̂–1̂) e da Bassbrechung (arco de baixo I–V–I). É um contraponto a duas vozes que subjaz a toda a música tonal." },
  { q: "De quantas camadas é composto o Ursatz?", opts: ["Uma só — a melodia principal", "Duas — soprano (Urlinie) e baixo (Bassbrechung)", "Três — soprano, contralto, baixo", "Quatro — as quatro vozes SATB"], a: 1, fb: "O Ursatz é um contraponto a duas vozes: o Urlinie no soprano e a Bassbrechung no baixo. Essas duas vozes fundamentais são suficientes para definir a estrutura tonal profunda de qualquer obra." },
  { q: "No Ursatz, como estão alinhados o Urlinie e a Bassbrechung?", opts: ["São independentes e nunca se cruzam", "3̂ coincide com I (baixo), 2̂ com V (baixo), 1̂ com I (baixo)", "5̂ coincide com V (baixo), 3̂ com IV, 1̂ com I", "Alternam-se sem nunca se sincronizar"], a: 1, fb: "O alinhamento canônico do Ursatz: Kopfton (3̂/5̂/8̂) sobre I, depois o movimento intermediário (2̂ sobre V), depois a resolução (1̂ sobre I). Essa sobreposição cria o contraponto fundamental da música tonal." },
  { q: "Por que Schenker diz que toda a música tonal é um 'prolongamento do Ursatz'?", opts: ["Porque todos os compositores copiam o mesmo esquema", "Porque toda composição tonal é uma elaboração dessa estrutura fundamental simples — os ornamentos de superfície desenvolvem o Ursatz", "Porque o Ursatz é imposto pelo conservatório", "Porque o Ursatz é a única estrutura audível"], a: 1, fb: "O Ursatz é a estrutura mais profunda e simples — toda composição tonal a elabora através de camadas sucessivas de prolongamento. Os ornamentos de superfície são realizações cada vez mais complexas desse arco fundamental." },
  { q: "O Ursatz se aplica à música atonal do século XX?", opts: ["Sim — Schenker o aplica a toda música", "Não — o Ursatz pressupõe a tonalidade; a música atonal não segue seus princípios", "Sim, mas com modificações", "Não — aplica-se apenas a Bach"], a: 1, fb: "O Ursatz pressupõe a tonalidade: Urlinie descendo para 1̂ e Bassbrechung I–V–I. A música atonal, que rejeita a hierarquia dos graus, não pode ser analisada nesse quadro. É um limite explícito do sistema schenkeriano." },
  { q: "Qual é a versão completa do Ursatz com o Urlinie 5̂–4̂–3̂–2̂–1̂?", opts: ["5̂ sobre I, 4̂ sobre IV, 3̂ sobre I, 2̂ sobre V, 1̂ sobre I", "5̂ sobre I, descida 4̂–3̂ prolongada, 2̂ sobre V, 1̂ sobre I", "5̂ sobre V, 4̂ sobre IV, 3̂ sobre III, 2̂ sobre II, 1̂ sobre I", "5̂ sobre I, 4̂–3̂–2̂ ornamentais, 1̂ sobre V"], a: 1, fb: "No Urlinie de quinta descendente, os graus 4̂ e 3̂ são frequentemente prolongados por movimentos harmônicos intermediários, mas os pontos de ancoragem estruturais são 5̂ sobre I, 2̂ sobre V e 1̂ sobre I — formando o Ursatz completo." },
  { q: "O Ursatz tem um único modelo ou várias variantes?", opts: ["Um único modelo para toda a música", "Três variantes segundo o Kopfton (3̂, 5̂ ou 8̂)", "Um número infinito de variantes segundo o compositor", "Duas variantes (maior e menor)"], a: 1, fb: "Schenker reconhece três formas de Ursatz segundo o Kopfton: 3̂–2̂–1̂ (mais simples), 5̂–4̂–3̂–2̂–1̂ (muito frequente), 8̂–7̂–6̂–5̂–4̂–3̂–2̂–1̂ (mais rara). A Bassbrechung permanece I–V–I nos três casos." },
  { q: "Como o Ursatz se manifesta em grande escala em uma sinfonia?", opts: ["Apenas no 1° movimento", "A tonalidade principal em I se prolonga até o V estrutural (frequentemente no desenvolvimento), depois volta a I no final", "É visível apenas no nível das frases", "Manifesta-se apenas no baixo contínuo"], a: 1, fb: "Em uma sinfonia, o Ursatz se estende por toda a obra: o início se ancora em I, o ponto de tensão máxima (muitas vezes desenvolvimento ou cadência central) realiza V, e a conclusão retorna a I. A Bassbrechung I–V–I estrutura toda a obra." },
  { q: "O que são o 'Vordergrund', o 'Mittelgrund' e o Hintergrund na análise schenkeriana?", opts: ["Três instrumentos diferentes", "As três camadas de análise: superfície (Vordergrund), camada intermediária (Mittelgrund), estrutura profunda (Hintergrund = Ursatz)", "Três partes de uma fuga", "Três tipos de cadências"], a: 1, fb: "Schenker usa esses três níveis: Vordergrund (primeiro plano = música de superfície como escrita), Mittelgrund (plano intermediário = prolongamentos agrupados), Hintergrund (plano de fundo = apenas o Ursatz). A redução progride do Vordergrund para o Hintergrund." },
  { q: "Qual é a contribuição principal da teoria do Ursatz para a análise musical?", opts: ["Permite memorizar as partituras mais facilmente", "Revela a estrutura tonal profunda comum a todas as grandes obras e explica sua coerência em grande escala", "Simplifica a notação musical", "Substitui a análise harmônica tradicional acorde por acorde"], a: 1, fb: "O Ursatz permite compreender a coerência tonal em grande escala: por que uma obra de 300 compassos 'se sustenta'. Revela que a complexidade de superfície mascara uma estrutura fundamental simples e universal." },

  // ── 7. Redução em camadas ───────────────────────────────────────────
  { q: "Quantas etapas comporta uma redução schenkeriana completa?", opts: ["1 etapa — passar diretamente ao Ursatz", "Pelo menos 3 camadas: superfície (Vordergrund) → intermediária (Mittelgrund) → profunda (Hintergrund)", "5 etapas fixas idênticas para cada análise", "2 etapas — acordes pares e acordes ímpares"], a: 1, fb: "A redução schenkeriana procede em camadas sucessivas: Vordergrund (superfície) → Mittelgrund(s) (camadas intermediárias, às vezes várias) → Hintergrund (Ursatz). O número de camadas intermediárias depende da complexidade da obra." },
  { q: "O que se faz primeiro em uma redução em camadas?", opts: ["Identificar o Urlinie imediatamente", "Escrever todos os acordes da partitura (harmonia de superfície)", "Reduzir ao Ursatz", "Analisar as modulações"], a: 1, fb: "O primeiro passo é escrever a harmonia de superfície completa — todos os acordes como aparecem. Este é o Vordergrund: o ponto de partida antes de qualquer redução. Não se pulam etapas." },
  { q: "O que é uma redução de camada intermediária (Mittelgrund)?", opts: ["Uma análise que conserva todos os acordes de superfície", "Uma análise que agrupa os acordes de superfície por funções e elimina os ornamentos, revelando os prolongamentos principais", "Uma análise apenas melódica", "Uma redução que conserva apenas I e V"], a: 1, fb: "O Mittelgrund é uma camada intermediária em que se eliminam os acordes de passagem e de bordadura, agrupando os acordes de superfície por função. Obtém-se uma visão dos prolongamentos principais sem chegar ao Ursatz completo." },
  { q: "Como se decide que um acorde é 'eliminável' na redução?", opts: ["Eliminando os acordes menores", "Eliminando os acordes que não têm papel funcional próprio — acordes de passagem, bordaduras, ornamentos", "Eliminando todos os acordes em tempos fracos", "Eliminando as inversões"], a: 1, fb: "Um acorde é eliminável se não tem papel funcional independente: acorde de passagem entre dois pilares, acorde de bordadura, acorde ornamental. Sua remoção não muda a lógica tonal fundamental." },
  { q: "Na redução de I–IV–I6–V7–I, qual seria a versão reduzida à camada intermediária?", opts: ["I–I6–V7–I", "I–IV–V–I", "I–V–I", "I–V7–I"], a: 3, fb: "I–IV–V7–I é uma redução intermediária razoável: conservam-se I, IV (SD), V7 (D) e I. I6 é eliminado porque é um prolongamento de I (mesmo acorde em inversão). A redução profunda seria I–V–I (Bassbrechung)." },
  { q: "A redução em camadas revela que tipo de estrutura?", opts: ["Apenas a estrutura rítmica", "A estrutura hierárquica: da complexidade de superfície à simplicidade fundamental", "A estrutura contrapontística de cada voz", "A estrutura modal da obra"], a: 1, fb: "A redução em camadas revela a hierarquia harmônica: a cada camada a estrutura se torna mais simples e mais fundamental. A complexidade de superfície (Vordergrund) se resolve em prolongamentos (Mittelgrund) e depois no Ursatz (Hintergrund)." },
  { q: "O que revela a diferença entre Vordergrund e Hintergrund?", opts: ["Os erros harmônicos do compositor", "A riqueza dos ornamentos e prolongamentos que desenvolvem a estrutura fundamental — é o 'conteúdo' da obra", "As passagens copiadas de outros compositores", "As dificuldades técnicas da peça"], a: 1, fb: "A diferença entre superfície e estrutura profunda mostra como o compositor 'veste' o Ursatz: os prolongamentos, ornamentos e desenvolvimentos que dão a cada obra sua personalidade única enquanto repousam sobre a mesma estrutura fundamental." },
  { q: "É possível reduzir uma peça em camadas sem conhecer a tonalidade?", opts: ["Sim — a redução é independente da tonalidade", "Não — a tonalidade é o quadro indispensável para identificar as funções e os pilares", "Sim, se conservarmos apenas o baixo", "Sim, mas apenas para o Vordergrund"], a: 1, fb: "A redução schenkeriana pressupõe a tonalidade: identificar T, SD, D e seus prolongamentos exige conhecer a tonalidade. Sem esse quadro, não se pode distinguir acorde estrutural de acorde ornamental." },
  { q: "Como se aplica a noção de camadas a uma frase de 8 compassos?", opts: ["Cada compasso é uma camada distinta", "Superfície: todos os acordes dos 8 compassos. Intermediária: I–IV–V–I (pilares). Profunda: I–V–I (Ursatz)", "A frase de 8 compassos não tem estrutura em camadas", "As camadas se aplicam apenas a movimentos inteiros"], a: 1, fb: "Mesmo uma frase curta de 8 compassos pode ser analisada em camadas: superfície (todos os acordes), intermediária (pilares funcionais T–SD–D–T), profunda (Ursatz I–V–I). É o princípio fractal da análise schenkeriana." },
  { q: "Qual é a utilidade prática da redução em camadas para um compositor?", opts: ["Nenhuma — é apenas para análise teórica", "Compreender a estrutura profunda para escrever obras longas coerentes e planejar a trajetória harmônica em grande escala", "Simplificar a escrita usando apenas I e V", "Evitar acordes complexos"], a: 1, fb: "A redução em camadas ajuda o compositor a planejar a grande forma: qual é a Bassbrechung da obra? Quando chega o V estrutural? Como os prolongamentos intermediários desenvolvem o Ursatz? É uma ferramenta de composição tanto quanto de análise." },

  // ── 8. Exemplos Bach/Mozart ────────────────────────────────────────────
  { q: "No Prelúdio em Dó maior BWV 846 de Bach (arpejos), a estrutura harmônica de superfície é:", opts: ["Apenas I durante toda a peça", "Uma sucessão de acordes arpejados mutáveis sobre um plano harmônico funcional T→SD→D→T", "Uma improvisação sem estrutura", "Uma série de modulações para tonalidades vizinhas"], a: 1, fb: "O Prelúdio BWV 846 realiza uma progressão harmônica funcional completa através de arpejos: a estrutura de superfície é rica mas a estrutura profunda é uma simples progressão T→SD→D→T que realiza o Ursatz." },
  { q: "Em um coral de Bach, as cadências internas servem principalmente para:", opts: ["Mudar de tonalidade definitivamente", "Articular a estrutura em frases e seções, criando pilares harmônicos intermediários na redução", "Evitar quintas paralelas", "Introduzir novas vozes"], a: 1, fb: "As cadências internas (semicadências, cadências imperfeitas) de um coral de Bach articulam a estrutura: criam pontos de ancoragem intermediários na redução, revelando a hierarquia das cadências (intermediárias vs. final)." },
  { q: "Na Sonata K.331 de Mozart (tema com variações), a estrutura harmônica do tema é:", opts: ["Complexa e modulante desde a 1ª frase", "Simples — I prolongada (cc. 1–4), depois V (cc. 5–8), resolução em I (cc. 9–16): Bassbrechung clara", "Apenas em IV e V alternados", "Sem estrutura funcional clara"], a: 1, fb: "O tema de K.331 realiza a Bassbrechung em 16 compassos: apresentação em I (cc. 1–8), tensão em V (cc. 9–14), resolução I (cc. 15–16). A estrutura é um modelo de economia tonal." },
  { q: "Em uma fuga de Bach em Dó maior, quando o sujeito entra em Sol maior (V), isso representa:", opts: ["Uma modulação definitiva em Sol maior", "A resposta tonal — uma tonicização de V que se inscreve na Bassbrechung I→V", "Um erro de escrita contrapontística", "A exposição do contrassujeito"], a: 1, fb: "A resposta em V em uma fuga realiza o primeiro movimento da Bassbrechung: I→V. A fuga 'modula' para V mas é uma tonicização que se inscreve no arco fundamental I–V–I de toda a fuga." },
  { q: "No 1° movimento da Sinfonia n.° 40 KV550 de Mozart, o 2° tema em Sib maior representa:", opts: ["Uma modulação definitiva e independente", "A tonicização do III (relativo maior do menor) — movimento harmônico da exposição para a 'dominante' estrutural", "Um erro de tonalidade de Mozart", "O início da recapitulação"], a: 1, fb: "Em Sol menor, o 2° tema em Sib (bIII = relativo maior) representa o movimento estrutural da exposição para a zona da dominante. Na Bassbrechung em menor, bIII frequentemente desempenha o papel de dominante estrutural da exposição." },
  { q: "Em um minueto de Haydn de 16 compassos, a cadência em V no compasso 8 representa:", opts: ["O final da obra", "O V estrutural da Bassbrechung — ponto de tensão mediano antes do retorno a I no final", "Uma modulação definitiva em Sol", "Um acidente harmônico não planejado"], a: 1, fb: "A cadência em V a meio caminho é típica da forma período: o V do compasso 8 é o V estrutural da Bassbrechung. Tudo o que segue (cc. 9–16) prolonga o retorno ao I final — é a segunda metade do arco I–V–I." },
  { q: "Na Chacona BWV 1004 de Bach (baixo obstinado), a Bassbrechung se estende sobre:", opts: ["Cada repetição do baixo somente", "A obra inteira — as 64 variações prolongam um único Ursatz do início ao fim", "Apenas as 4 primeiras variações", "O baixo obstinado não tem Bassbrechung"], a: 1, fb: "A Chacona de Bach realiza um Ursatz na escala de toda a obra: as 64 variações são um prolongamento monumental de I–V–I. O baixo obstinado é ele mesmo um prolongamento da Bassbrechung fundamental." },
  { q: "Como se analisa um coral de Bach de 4 compassos com o método de redução?", opts: ["Conservar todos os acordes e numerá-los", "1) anotar todos os acordes, 2) localizar abertura (T), cadência mediana (V ou II6–V), cadência final (V–I), 3) reduzir à Bassbrechung I–V–I", "Simplificar a I–IV–V–I somente", "Identificar apenas as inversões"], a: 1, fb: "O método em 3 etapas: 1) superfície completa, 2) pilares funcionais (abertura T, cadências intermediárias e final), 3) Bassbrechung I–V–I. Essa abordagem evita a análise puramente acorde por acorde e revela a estrutura profunda." },
  { q: "Em Mozart K.545 (Sonata em Dó maior, início), os 4 primeiros compassos prolongam:", opts: ["Apenas V", "I (tônica) através de harmonias de superfície variadas (I–V6–I–IV6–I6/4–V–I)", "Apenas IV", "A subdominante"], a: 1, fb: "Os cc. 1–4 de K.545 prolongam I (tônica): as harmonias de superfície (V6, IV6, I6/4–V–I) ornam e cadenciam a tônica. A estrutura profunda desses 4 compassos é um I prolongado — um Kopfton suspenso antes do movimento real para V." },
  { q: "Por que Bach e Mozart são os compositores de referência para a análise schenkeriana?", opts: ["Porque usavam exatamente as mesmas fórmulas", "Porque sua escrita tonal é exemplar: estrutura profunda simples, prolongamentos elaborados, lógica harmônica irrepreensível", "Porque Schenker os conhecia pessoalmente", "Porque sua música é a mais difícil de analisar"], a: 1, fb: "Bach e Mozart são modelos porque sua escrita tonal realiza perfeitamente o Ursatz: por trás de uma superfície de grande riqueza, a estrutura profunda é de exemplar clareza e lógica. Eles ilustram idealmente os princípios schenkerianos." },

  // ── 9. Aplicação prática ────────────────────────────────────────────────
  { q: "Na progressão Dó–Sol–Lá–Fá–Sol–Dó (baixo, Dó maior), qual é o acorde estrutural de dominante?", opts: ["Lá (VI)", "Fá (IV)", "Sol (V) — as duas ocorrências", "Dó (I)"], a: 2, fb: "Sol (V) é o acorde estrutural de dominante. As duas ocorrências de Sol podem prolongar V antes da resolução final em I. Dó = T, Lá = T prolongada (VI), Fá = SD, Sol = D, Dó = T: progressão T–T–SD–D–T." },
  { q: "Você analisa 8 compassos. A estrutura é I–IV–I6–V6–I–II6–V7–I. Quais são os pilares estruturais?", opts: ["Todos os 8 acordes são pilares", "I (início), V (cadência mediana ou dominante), I (conclusão) — os demais são prolongamentos", "Apenas I, IV, V7, I", "I6, V6, II6, I"], a: 1, fb: "Os pilares estruturais são I (abertura), V/V7 (dominante) e I (conclusão). IV, I6, V6 e II6 são prolongamentos ou ornamentos funcionais. A Bassbrechung subjacente é I–V–I." },
  { q: "Dá-se a melodia Mi–Ré–Dó em 3 compassos (Dó maior, harmonizada por I–V–I). É um exemplo de:", opts: ["Apenas Bassbrechung", "Urlinie 3̂–2̂–1̂ harmonizado pelo Ursatz I–V–I — um exemplo perfeito de estrutura fundamental", "Prolongamento de V", "Cadência imperfeita"], a: 1, fb: "Mi–Ré–Dó (3̂–2̂–1̂) sobre I–V–I é o exemplo mais puro do Ursatz: o Urlinie de terça desce de 3̂ a 1̂ sustentado pela Bassbrechung I–V–I. É o modelo básico que Schenker ilustra em Der freie Satz." },
  { q: "Como determinar se uma modulação é estrutural ou ornamental em uma peça?", opts: ["Todas as modulações são estruturais", "Se a nova tonalidade é confirmada por uma cadência V–I e mantida durante uma seção significativa, ela é estrutural; caso contrário é uma tonicização ornamental", "Uma modulação é sempre ornamental", "Se a modulação dura mais de 2 compassos, ela é estrutural"], a: 1, fb: "A distinção chave: tonicização (momentânea, alguns acordes) vs. modulação estrutural (confirmada por V–I, mantida em uma seção). Na análise em camadas, as tonicizações desaparecem no Mittelgrund; apenas as modulações estruturais permanecem." },
  { q: "Em uma análise prática, por onde se começa?", opts: ["Pelo último compasso", "Identificando a tonalidade, depois localizando a cadência final (V–I), depois subindo em direção ao início", "Pelas notas mais agudas", "Analisando cada acorde da esquerda para a direita sem ordem particular"], a: 1, fb: "Começar pela tonalidade e cadência final é a estratégia schenkeriana: a cadência final (V–I) é o V e o I da Bassbrechung. Depois se remonta para descobrir como a estrutura profunda se desdobra desde a abertura." },
  { q: "Qual dessas análises de I–VI–II–V–I é correta?", opts: ["I=D, VI=T, II=SD, V=D, I=T", "I=T, VI=T (prolongamento), II=SD, V=D, I=T", "I=T, VI=SD, II=D, V=T, I=D", "I=SD, VI=D, II=T, V=SD, I=T"], a: 1, fb: "I=T, VI=T (VI pertence à região tônica), II=SD, V=D, I=T. A progressão realiza T(prolongada por VI)–SD–D–T. A análise correta identifica VI como pertencente à região tônica, não a outra função." },
  { q: "Deve-se reduzir I–I6–IV–II6–I6/4–V7–I à camada intermediária. Qual é o resultado?", opts: ["I–IV–II6–V7–I", "I–IV–V7–I (ou I–II6–V7–I)", "I–I6/4–V7–I", "Apenas I–V–I"], a: 1, fb: "Na camada intermediária, I6 (prolongamento de I) é eliminado, IV ou II6 (SD) são conservados, I6/4 (prolongamento de V) às vezes eliminado. O resultado típico é I–IV–V7–I ou I–II6–V7–I — a estrutura funcional T–SD–D–T sem ornamentos." },
  { q: "Qual é a melhor análise de superfície para Dó–Sol–Mi–Dó (baixo ascendente, Dó maior)?", opts: ["I–V–I6–I (arpejo de I)", "I–V–III–I (4 acordes diferentes)", "I prolongado por arpejo (I–I6–I6/4–I) — uma única função tônica", "II–V–I–I"], a: 2, fb: "Dó–Sol–Mi–Dó no baixo arpeja o acorde de Dó maior: Dó = estado fundamental, Sol = I6/4 (quinta no baixo), Mi = I6 (terça no baixo), Dó = estado fundamental. É um prolongamento tônico por arpejo — uma única função T." },
  { q: "Por que a cadência V–I é o pilar final de todo Ursatz?", opts: ["Por convenção arbitrária", "Porque V–I realiza a resolução da tensão máxima (dominante) para o repouso (tônica) — a conclusão obrigatória de toda lógica tonal", "Porque V–I é a cadência mais longa", "Porque I soa mais forte que V"], a: 1, fb: "V–I é a resolução fundamental da lógica tonal: a dominante cria tensão máxima (trítono em V7, sensível para tônica) que só a tônica pode resolver. É a conclusão inevitável da Bassbrechung e do Urlinie." },
];

